// 分类→标签映射规则（关键词匹配）
const categoryTagRules = {
  // 休闲类
  休闲: ["生活", "日常", "分享", "闲聊", "聊天", "随便", "休息"],
  // 音乐类
  音乐: ["音乐", "歌曲", "唱歌", "演奏", "乐器", "演唱会"],
  // 游戏类
  游戏: ["游戏", "电竞", "竞技", "对战", "开黑", "吃鸡", "LOL"],
  // 学习类
  学习: ["学习", "教学", "课程", "知识", "分享", "讲解", "教程"],
  // 运动类
  运动: ["运动", "健身", "锻炼", "跑步", "瑜伽", "舞蹈"],
  // 美食类
  美食: ["美食", "做饭", "烹饪", "吃播", "料理", "烘焙"],
  // 情感类
  情感: ["情感", "恋爱", "心情", "倾诉", "陪伴", "治愈"],
  // 悲伤类
  悲伤: ["悲伤", "难过", "忧郁", "伤感", "失落", "孤独"],
  // 浪漫类
  浪漫: ["浪漫", "甜蜜", "温馨", "约会", "告白", "情侣"],
  // 工作类
  工作: ["工作", "办公", "编程", "设计", "写作", "专注"],
};

// 推断分类的标签（支持多标签）
function inferCategoryTags(category) {
  const tags = [];
  const categoryLower = category.toLowerCase();

  for (const [tag, keywords] of Object.entries(categoryTagRules)) {
    for (const keyword of keywords) {
      if (categoryLower.includes(keyword.toLowerCase())) {
        tags.push(tag);
        break; // 找到一个关键词就够了
      }
    }
  }

  return tags;
}

// 全局音频实例（单例模式）
let liveAudioPlayer = null;
let isAudioInitialized = false;

// 获取音乐配置（基于标签匹配，随机选择）
function getMusicForCategory(category) {
  const categoryTags = inferCategoryTags(category);

  if (categoryTags.length === 0) {
    return liveBackgroundMusic.default;
  }

  for (const tag of categoryTags) {
    const songs = customMusicLibrary[tag];
    if (songs && songs.length > 0) {
      const randomSong = songs[Math.floor(Math.random() * songs.length)];
      return randomSong.url;
    }
  }

  for (const tag of categoryTags) {
    if (liveBackgroundMusic[tag]) {
      return liveBackgroundMusic[tag];
    }
  }

  if (liveBackgroundMusic[category]) {
    return liveBackgroundMusic[category];
  }

  return liveBackgroundMusic.default;
}

// 验证音乐URL格式
function validateMusicURL(url) {
  if (!url || typeof url !== "string") {
    return { valid: false, error: "URL不能为空" };
  }

  // 基础URL格式验证
  try {
    const urlObj = new URL(url);

    // 必须是http/https协议
    if (!["http:", "https:"].includes(urlObj.protocol)) {
      return { valid: false, error: "仅支持 HTTP/HTTPS 协议" };
    }

    // 检查文件扩展名（可选）
    const validExtensions = [".mp3", ".m4a", ".ogg", ".wav", ".aac", ".flac"];
    const pathname = urlObj.pathname.toLowerCase();
    const hasValidExt = validExtensions.some((ext) => pathname.endsWith(ext));

    // 如果URL包含音乐平台特征，也认为有效
    const musicPlatforms = [
      "music.163.com",
      "y.qq.com",
      "music.apple.com",
      "spotify.com",
    ];
    const isMusicPlatform = musicPlatforms.some((platform) =>
      urlObj.hostname.includes(platform)
    );

    if (!hasValidExt && !isMusicPlatform) {
      console.warn("⚠️ URL可能不是有效的音频文件");
    }

    return { valid: true };
  } catch (error) {
    return { valid: false, error: "无效的URL格式" };
  }
}

// 加载自定义音乐库
async function loadCustomMusicList() {
  try {
    const db = getXDB();
    const accountId = currentAccountId || "main";
    const musicListId = `live_custom_music_${accountId}`;

    const saved = await db.xAccountProfiles.get(musicListId);
    if (saved && saved.data) {
      if (typeof saved.data === "object" && !Array.isArray(saved.data)) {
        customMusicLibrary = saved.data;
      } else if (Array.isArray(saved.data)) {
        customMusicLibrary = {};
        saved.data.forEach((item, index) => {
          const tag = item.category;
          if (!customMusicLibrary[tag]) {
            customMusicLibrary[tag] = [];
          }
          customMusicLibrary[tag].push({
            id: item.id || `music_${Date.now()}_${index}`,
            name: item.name || `歌曲${index + 1}`,
            url: item.url,
            addedTime: item.addedTime || Date.now(),
          });
        });
        await saveCustomMusicList();
      } else {
        customMusicLibrary = {};
      }
    } else {
      customMusicLibrary = {};
    }
  } catch (error) {
    console.error("❌ [直播设置] 加载自定义音乐失败:", error);
    customMusicLibrary = {};
  }
}

// 保存自定义音乐库
async function saveCustomMusicList() {
  try {
    const db = getXDB();
    const accountId = currentAccountId || "main";
    const musicListId = `live_custom_music_${accountId}`;

    await db.xAccountProfiles.put({
      handle: musicListId,
      data: customMusicLibrary,
      updatedAt: new Date().toISOString(),
    });

    return true;
  } catch (error) {
    console.error("❌ [直播设置] 保存自定义音乐失败:", error);
    return false;
  }
}

// 添加自定义音乐（新：支持歌曲名和多标签）
async function addCustomMusic(name, url, tags) {
  const validation = validateMusicURL(url);
  if (!validation.valid) {
    showXToast(validation.error, "error");
    return false;
  }

  if (!name || name.trim() === "") {
    showXToast("歌曲名称不能为空", "error");
    return false;
  }

  if (!tags || tags.length === 0) {
    showXToast("至少选择一个标签", "error");
    return false;
  }

  const musicData = {
    id: `music_${Date.now()}`,
    name: name.trim(),
    url: url.trim(),
    addedTime: Date.now(),
  };

  let addedCount = 0;
  for (const tag of tags) {
    if (!customMusicLibrary[tag]) {
      customMusicLibrary[tag] = [];
    }
    customMusicLibrary[tag].push({ ...musicData });
    addedCount++;
  }

  const saved = await saveCustomMusicList();
  if (saved) {
    showXToast(`成功添加到 ${addedCount} 个标签`, "success");
    return true;
  }
  return false;
}

// 删除自定义音乐
async function deleteCustomMusic(tag, musicId) {
  if (!customMusicLibrary[tag]) {
    showXToast("标签不存在", "error");
    return false;
  }

  const index = customMusicLibrary[tag].findIndex((m) => m.id === musicId);
  if (index < 0) {
    showXToast("音乐不存在", "error");
    return false;
  }

  const music = customMusicLibrary[tag][index];
  customMusicLibrary[tag].splice(index, 1);

  if (customMusicLibrary[tag].length === 0) {
    delete customMusicLibrary[tag];
  }

  const saved = await saveCustomMusicList();
  if (saved) {
    showXToast(`已删除 "${music.name}"`, "success");
    return true;
  }
  return false;
}

// ============================================
// 🎵 音乐库导入导出功能
// ============================================

// 导出音乐库到JSON文件
function handleExportMusicLibrary() {
  try {
    // 检查是否有歌曲
    const totalSongs = Object.values(customMusicLibrary).reduce(
      (sum, songs) => sum + songs.length,
      0
    );

    if (totalSongs === 0) {
      showXToast("音乐库为空，无内容可导出", "info");
      return;
    }

    // 创建导出数据结构
    const exportData = {
      version: "1.0",
      exportedAt: new Date().toISOString(),
      exportedBy: currentAccountId || "main",
      totalTags: Object.keys(customMusicLibrary).length,
      totalSongs: totalSongs,
      data: customMusicLibrary,
    };

    // 转换为JSON字符串（格式化，便于阅读）
    const jsonString = JSON.stringify(exportData, null, 2);

    // 创建Blob对象
    const blob = new Blob([jsonString], { type: "application/json" });

    // 创建下载链接
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;

    // 生成文件名：music_library_YYYYMMDD_HHMMSS.json
    const now = new Date();
    const dateStr = now
      .toISOString()
      .replace(/[-:]/g, "")
      .replace(/\..+/, "")
      .replace("T", "_");
    a.download = `music_library_${dateStr}.json`;

    // 触发下载
    document.body.appendChild(a);
    a.click();

    // 清理
    setTimeout(() => {
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    }, 100);

    showXToast(
      `已导出 ${totalSongs} 首歌曲（${Object.keys(customMusicLibrary).length} 个标签）`,
      "success"
    );

    console.log("📤 [音乐库] 导出成功:", {
      totalTags: Object.keys(customMusicLibrary).length,
      totalSongs: totalSongs,
      fileName: a.download,
    });
  } catch (error) {
    console.error("❌ [音乐库] 导出失败:", error);
    showXToast("导出失败: " + error.message, "error");
  }
}

// 触发文件选择（导入）
function handleImportMusicLibrary() {
  const fileInput = document.getElementById("musicLibraryFileInput");
  if (fileInput) {
    fileInput.value = ""; // 清空，允许重复导入同一文件
    fileInput.click();
  }
}

// 处理导入的文件
async function processImportFile(event) {
  const file = event.target.files[0];
  if (!file) return;

  // 检查文件类型
  if (!file.name.endsWith(".json")) {
    showXToast("请选择JSON文件", "error");
    return;
  }

  // 检查文件大小（限制10MB）
  const maxSize = 10 * 1024 * 1024; // 10MB
  if (file.size > maxSize) {
    showXToast("文件过大（超过10MB）", "error");
    return;
  }

  showXToast("正在导入...", "info");

  try {
    // 读取文件内容
    const text = await file.text();
    let importData;

    // 解析JSON
    try {
      importData = JSON.parse(text);
    } catch (parseError) {
      throw new Error("JSON格式错误，请检查文件内容");
    }

    // 验证数据结构
    if (!importData || typeof importData !== "object") {
      throw new Error("文件格式错误：根对象无效");
    }

    // 兼容性处理：支持直接导出的customMusicLibrary格式
    let musicData;
    if (importData.version && importData.data) {
      // 新格式：包含版本和元数据
      musicData = importData.data;
    } else if (typeof importData === "object") {
      // 旧格式：直接是customMusicLibrary对象
      musicData = importData;
    } else {
      throw new Error("无法识别的文件格式");
    }

    // 验证musicData是否有效
    if (!musicData || typeof musicData !== "object") {
      throw new Error("文件格式错误：音乐数据无效");
    }

    // 统计数据
    let addedCount = 0;
    let skippedCount = 0;
    let newTagsCount = 0;

    // 遍历每个标签
    for (const [tag, songs] of Object.entries(musicData)) {
      if (!Array.isArray(songs)) {
        console.warn(`⚠️ [导入] 跳过无效标签: ${tag}`);
        continue;
      }

      // 检查是否是新标签
      const isNewTag = !customMusicLibrary[tag];
      if (isNewTag) {
        customMusicLibrary[tag] = [];
        newTagsCount++;
      }

      // 遍历歌曲
      for (const song of songs) {
        // 验证歌曲数据
        if (!song || !song.url || !song.name) {
          console.warn("⚠️ [导入] 跳过无效歌曲:", song);
          skippedCount++;
          continue;
        }

        // 去重检查：同一标签下，URL相同则跳过
        const isDuplicate = customMusicLibrary[tag].some(
          (existingSong) => existingSong.url === song.url
        );

        if (isDuplicate) {
          console.log(`⏭️ [导入] 跳过重复歌曲: ${song.name} (${tag})`);
          skippedCount++;
          continue;
        }

        // 添加歌曲（生成新ID，保留原有数据）
        customMusicLibrary[tag].push({
          id: `music_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          name: song.name,
          url: song.url,
          addedTime: Date.now(),
        });

        addedCount++;
      }
    }

    // 保存到数据库
    const saved = await saveCustomMusicList();
    if (!saved) {
      throw new Error("保存到数据库失败");
    }

    // 刷新UI
    refreshCassetteWall();

    // 显示结果
    let message = `导入完成！\n新增 ${addedCount} 首歌曲`;
    if (newTagsCount > 0) {
      message += `\n新增 ${newTagsCount} 个标签`;
    }
    if (skippedCount > 0) {
      message += `\n跳过 ${skippedCount} 首重复/无效歌曲`;
    }

    showXToast(message, "success");

    console.log("📥 [音乐库] 导入成功:", {
      added: addedCount,
      skipped: skippedCount,
      newTags: newTagsCount,
      totalTags: Object.keys(customMusicLibrary).length,
      totalSongs: Object.values(customMusicLibrary).reduce(
        (sum, songs) => sum + songs.length,
        0
      ),
    });
  } catch (error) {
    console.error("❌ [音乐库] 导入失败:", error);
    showXToast("导入失败: " + error.message, "error");
  }
}

