// 彩蛋配置
const easterEggConfig = {
  // 触发条件
  bigAmountThreshold: 50, // 大额充值阈值（美元）
  frequentCountThreshold: 3, // 反复充值阈值（次数）
  frequentTimeWindow: 300000, // 反复充值时间窗口（5分钟）

  // 触发概率
  triggerChance: 0.15, // 15%概率触发彩蛋
  badEggChance: 0.4, // 40%概率是负面彩蛋（在触发时）

  // 冷却时间
  cooldownTime: 600000, // 10分钟冷却（避免频繁触发）

  // 负面彩蛋配置（扣除比例）
  badEggDeductionRange: [0.3, 0.7], // 扣除30%-70%

  // 正面彩蛋配置（额外赠送比例）
  goodEggBonusRange: [0.2, 0.5], // 额外赠送20%-50%
};

