// 获取充值历史（从localStorage）
function getRechargeHistory() {
  const saved = localStorage.getItem("liveRechargeHistory");
  if (!saved) return { records: [], lastEasterEgg: 0 };

  try {
    return JSON.parse(saved);
  } catch (error) {
    console.error("❌ [彩蛋] 充值历史解析失败:", error);
    return { records: [], lastEasterEgg: 0 };
  }
}

// 保存充值历史
function saveRechargeHistory(history) {
  try {
    localStorage.setItem("liveRechargeHistory", JSON.stringify(history));
  } catch (error) {
    console.error("❌ [彩蛋] 充值历史保存失败:", error);
  }
}

// 记录充值
function recordRecharge(amount, points) {
  const history = getRechargeHistory();
  const now = Date.now();

  // 添加新记录
  history.records.push({
    amount,
    points,
    timestamp: now,
  });

  // 清理5分钟前的旧记录（节省空间）
  const windowStart = now - easterEggConfig.frequentTimeWindow;
  history.records = history.records.filter((r) => r.timestamp > windowStart);

  saveRechargeHistory(history);
}

// 检查是否应该触发彩蛋
function shouldTriggerEasterEgg(amount, points) {
  const history = getRechargeHistory();
  const now = Date.now();

  // 检查冷却时间
  if (now - history.lastEasterEgg < easterEggConfig.cooldownTime) {
    console.log(
      `🎭 [彩蛋] 冷却中，距离下次触发还需 ${Math.ceil(
        (easterEggConfig.cooldownTime - (now - history.lastEasterEgg)) / 60000
      )} 分钟`
    );
    return false;
  }

  // 检查触发条件
  const isBigAmount = amount >= easterEggConfig.bigAmountThreshold;
  const recentCount = history.records.length;
  const isFrequent = recentCount >= easterEggConfig.frequentCountThreshold;

  if (!isBigAmount && !isFrequent) {
    console.log(
      `🎭 [彩蛋] 未满足触发条件 (金额:${amount} 次数:${recentCount})`
    );
    return false;
  }

  // 随机触发
  const roll = Math.random();
  const triggered = roll < easterEggConfig.triggerChance;

  console.log(
    `🎭 [彩蛋] 触发检测: ${triggered ? "✅ 触发" : "❌ 未触发"} (掷骰:${(
      roll * 100
    ).toFixed(1)}% 阈值:${easterEggConfig.triggerChance * 100}%)`
  );

  return triggered;
}

// 触发彩蛋并返回修正后的积分
function triggerEasterEgg(originalAmount, originalPoints) {
  const history = getRechargeHistory();
  const now = Date.now();

  // 更新冷却时间
  history.lastEasterEgg = now;
  saveRechargeHistory(history);

  // 随机决定好/坏彩蛋
  const isBadEgg = Math.random() < easterEggConfig.badEggChance;

  let finalPoints = originalPoints;
  let message;

  if (isBadEgg) {
    // 负面彩蛋：扣除积分
    const [minDeduction, maxDeduction] = easterEggConfig.badEggDeductionRange;
    const deductionRate =
      minDeduction + Math.random() * (maxDeduction - minDeduction);
    const deductedAmount = Math.floor(originalPoints * deductionRate);
    finalPoints = originalPoints - deductedAmount;

    // 随机选择文案
    const template =
      easterEggMessages.bad[
        Math.floor(Math.random() * easterEggMessages.bad.length)
      ];
    message = {
      type: "bad",
      title: template.title,
      reason: template.reason,
      detail: template.detail,
      suffix: template.suffix,
      originalPoints,
      finalPoints,
      difference: -deductedAmount,
    };

    console.log(
      `😈 [彩蛋-负面] 扣除 ${deductedAmount} 积分 (${(
        deductionRate * 100
      ).toFixed(0)}%)`
    );
  } else {
    // 正面彩蛋：额外赠送
    const [minBonus, maxBonus] = easterEggConfig.goodEggBonusRange;
    const bonusRate = minBonus + Math.random() * (maxBonus - minBonus);
    const bonusAmount = Math.floor(originalPoints * bonusRate);
    finalPoints = originalPoints + bonusAmount;

    // 随机选择文案并替换变量
    const template =
      easterEggMessages.good[
        Math.floor(Math.random() * easterEggMessages.good.length)
      ];
    const rank = Math.floor(Math.random() * 9999) + 1; // 随机排名
    const events = ["成立3", "成立5", "成立7", "上市2", "破产重组1"];
    const event = events[Math.floor(Math.random() * events.length)];

    message = {
      type: "good",
      title: template.title,
      reason: template.reason.replace("{rank}", rank).replace("{event}", event),
      detail: template.detail,
      suffix: template.suffix,
      originalPoints,
      finalPoints,
      difference: bonusAmount,
    };

    console.log(
      `🎁 [彩蛋-正面] 赠送 ${bonusAmount} 积分 (${(bonusRate * 100).toFixed(
        0
      )}%)`
    );
  }

  return { finalPoints, message };
}

