// 🎭 测试函数：手动触发彩蛋弹窗（控制台调用）
// 用法：
// testEasterEgg('bad', 100, 10) - 触发负面彩蛋
// testEasterEgg('good', 100, 10) - 触发正面彩蛋
// testEasterEgg() - 随机触发
window.testEasterEgg = function (type = "random", amount = 100, points = 10) {
  let isBadEgg;

  if (type === "random") {
    isBadEgg = Math.random() < 0.5;
  } else if (type === "bad" || type === 0) {
    isBadEgg = true;
  } else if (type === "good" || type === 1) {
    isBadEgg = false;
  } else {
    isBadEgg = Math.random() < 0.5;
  }

  console.log(
    `🎭 [测试] 手动触发${
      isBadEgg ? "负面" : "正面"
    }彩蛋 (原始积分: ${points}, 金额: $${amount})`
  );

  // 手动构建彩蛋结果（模拟triggerEasterEgg逻辑）
  let finalPoints = points;
  let message;

  if (isBadEgg) {
    // 负面彩蛋：扣除积分
    const [minDeduction, maxDeduction] = easterEggConfig.badEggDeductionRange;
    const deductionRate =
      minDeduction + Math.random() * (maxDeduction - minDeduction);
    const deductedAmount = Math.floor(points * deductionRate);
    finalPoints = points - deductedAmount;

    // 随机选择文案
    const template =
      easterEggMessages.bad[
        Math.floor(Math.random() * easterEggMessages.bad.length)
      ];
    message = {
      type: "bad",
      title: template.title,
      reason: template.reason,
      detail: template.detail,
      suffix: template.suffix,
      originalPoints: points,
      finalPoints: finalPoints,
      difference: -deductedAmount,
    };

    console.log(
      `😈 [彩蛋-负面] 扣除 ${deductedAmount} 积分 (${(
        deductionRate * 100
      ).toFixed(0)}%)`
    );
  } else {
    // 正面彩蛋：额外赠送
    const [minBonus, maxBonus] = easterEggConfig.goodEggBonusRange;
    const bonusRate = minBonus + Math.random() * (maxBonus - minBonus);
    const bonusAmount = Math.floor(points * bonusRate);
    finalPoints = points + bonusAmount;

    // 随机选择文案并替换变量
    const template =
      easterEggMessages.good[
        Math.floor(Math.random() * easterEggMessages.good.length)
      ];
    const rank = Math.floor(Math.random() * 9999) + 1;
    const events = ["成立3", "成立5", "成立7", "上市2", "破产重组1"];
    const event = events[Math.floor(Math.random() * events.length)];

    message = {
      type: "good",
      title: template.title,
      reason: template.reason.replace("{rank}", rank).replace("{event}", event),
      detail: template.detail,
      suffix: template.suffix,
      originalPoints: points,
      finalPoints: finalPoints,
      difference: bonusAmount,
    };

    console.log(
      `🎁 [彩蛋-正面] 赠送 ${bonusAmount} 积分 (${(bonusRate * 100).toFixed(
        0
      )}%)`
    );
  }

  showEasterEggModal(message);

  return { finalPoints, message };
};

