// 获取用户音量偏好
function getMusicVolume() {
  const saved = localStorage.getItem("liveMusicVolume");
  return saved !== null ? parseFloat(saved) : 0.3; // 默认30%
}

// 保存音量偏好
function saveMusicVolume(volume) {
  localStorage.setItem("liveMusicVolume", volume.toString());
}

// 获取静音状态
function getMusicMuted() {
  const saved = localStorage.getItem("liveMusicMuted");
  return saved === "true";
}

// 保存静音状态
function saveMusicMuted(muted) {
  localStorage.setItem("liveMusicMuted", muted.toString());
}

// 初始化音频播放器
function initAudioPlayer(musicUrl) {
  // 如果已存在，先停止并销毁
  if (liveAudioPlayer) {
    stopAudioPlayer();
  }

  try {
    liveAudioPlayer = new Audio(musicUrl);
    liveAudioPlayer.loop = true;
    liveAudioPlayer.volume = getMusicVolume();
    liveAudioPlayer.muted = getMusicMuted();
    liveAudioPlayer.preload = "auto";

    // 错误处理
    liveAudioPlayer.addEventListener("error", (e) => {
      console.warn("⚠️ [直播间音乐] 加载失败:", e);
      // 不显示错误提示，避免干扰用户
    });

    liveAudioPlayer.addEventListener("play", () => {
      isAudioInitialized = true;
    });
  } catch (error) {
    console.error("❌ [直播间音乐] 初始化失败:", error);
    liveAudioPlayer = null;
  }
}

// 播放音乐
function playAudioPlayer() {
  if (!liveAudioPlayer) return;

  // 尝试播放（可能被浏览器阻止）
  const playPromise = liveAudioPlayer.play();

  if (playPromise !== undefined) {
    playPromise
      .then(() => {})
      .catch((error) => {
        console.warn("⚠️ [直播间音乐] 自动播放被阻止:", error.message);
        isAudioInitialized = false;
      });
  }
}

// 暂停音乐
function pauseAudioPlayer() {
  if (liveAudioPlayer && !liveAudioPlayer.paused) {
    liveAudioPlayer.pause();
  }
}

// 停止并销毁音频播放器
function stopAudioPlayer() {
  if (liveAudioPlayer) {
    liveAudioPlayer.pause();
    liveAudioPlayer.currentTime = 0;
    liveAudioPlayer.src = "";
    liveAudioPlayer = null;
    isAudioInitialized = false;
  }
}

// 切换静音
function toggleMusicMute() {
  if (!liveAudioPlayer) return;

  liveAudioPlayer.muted = !liveAudioPlayer.muted;
  saveMusicMuted(liveAudioPlayer.muted);

  // 更新 UI
  updateMusicControlUI();

  return liveAudioPlayer.muted;
}

// 设置音量
function setMusicVolume(volume) {
  if (!liveAudioPlayer) return;

  // 限制在 0-1 范围
  volume = Math.max(0, Math.min(1, volume));
  liveAudioPlayer.volume = volume;
  saveMusicVolume(volume);

  // 如果设置音量，自动取消静音
  if (volume > 0 && liveAudioPlayer.muted) {
    liveAudioPlayer.muted = false;
    saveMusicMuted(false);
  }

  // 更新 UI
  updateMusicControlUI();
}

// 更新音乐控制UI
function updateMusicControlUI() {
  if (!liveAudioPlayer) return;

  const muteBtn = document.getElementById("musicMuteBtn");
  const volumeSlider = document.getElementById("musicVolumeSlider");
  const playBtn = document.getElementById("musicPlayBtn");

  if (muteBtn) {
    const isMuted = liveAudioPlayer.muted;
    const volume = liveAudioPlayer.volume;

    // 更新图标
    if (isMuted || volume === 0) {
      muteBtn.innerHTML = `
          <svg viewBox="0 0 24 24" style="width: 18px; height: 18px; fill: #fff;">
            <path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v2.21l2.45 2.45c.03-.2.05-.41.05-.63zm2.5 0c0 .94-.2 1.82-.54 2.64l1.51 1.51C20.63 14.91 21 13.5 21 12c0-4.28-2.99-7.86-7-8.77v2.06c2.89.86 5 3.54 5 6.71zM4.27 3L3 4.27 7.73 9H3v6h4l5 5v-6.73l4.25 4.25c-.67.52-1.42.93-2.25 1.18v2.06c1.38-.31 2.63-.95 3.69-1.81L19.73 21 21 19.73l-9-9L4.27 3zM12 4L9.91 6.09 12 8.18V4z"/>
          </svg>
        `;
    } else if (volume < 0.3) {
      muteBtn.innerHTML = `
          <svg viewBox="0 0 24 24" style="width: 18px; height: 18px; fill: #fff;">
            <path d="M7 9v6h4l5 5V4l-5 5H7z"/>
          </svg>
        `;
    } else if (volume < 0.7) {
      muteBtn.innerHTML = `
          <svg viewBox="0 0 24 24" style="width: 18px; height: 18px; fill: #fff;">
            <path d="M7 9v6h4l5 5V4l-5 5H7zm11.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02z"/>
          </svg>
        `;
    } else {
      muteBtn.innerHTML = `
          <svg viewBox="0 0 24 24" style="width: 18px; height: 18px; fill: #fff;">
            <path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/>
          </svg>
        `;
    }
  }

  if (volumeSlider) {
    volumeSlider.value = liveAudioPlayer.volume * 100;
  }

  if (playBtn) {
    const isPlaying = !liveAudioPlayer.paused;
    playBtn.style.display = isPlaying ? "none" : "flex";
  }
}

// 手动播放（用于浏览器阻止自动播放后）
function manualPlayMusic() {
  if (!liveAudioPlayer) return;

  playAudioPlayer();

  // 隐藏播放按钮
  const playBtn = document.getElementById("musicPlayBtn");
  if (playBtn) {
    playBtn.style.display = "none";
  }
}
window.manualPlayMusic = manualPlayMusic;

// 加入直播间
function joinLiveStream(streamId) {
  let streamData = null;

  for (const category in liveStreamData) {
    const found = liveStreamData[category].find((s) => s.id === streamId);
    if (found) {
      streamData = found;
      break;
    }
  }

  if (!streamData) {
    console.error("❌ [直播间] 未找到直播数据:", streamId);
    showXToast("直播间不存在", "error");
    return;
  }

  // 保存当前直播间数据
  currentLiveRoomData = {
    ...streamData,
    type:
      streamData.category.includes("语音") || streamId.startsWith("audio")
        ? "audio"
        : "video",
  };

  loadLiveRoomDetails(streamId)
    .then((cachedData) => {
      if (cachedData) {
        currentLiveRoomData.details = cachedData;

        // 🚨 【核心检查】如果直播间已结束，显示弹窗并阻止进入
        if (cachedData.isEnded === true) {
          console.log(`🚫 [直播间] 直播间 ${streamId} 已结束，阻止进入`);
          const streamerName = streamData.streamerName || "主播";
          showLiveEndedModal(streamerName, false); // autoClose = false，不自动关闭，点击弹窗关闭
          currentLiveRoomData = null; // 清除当前直播间数据
          return; // 阻止进入
        }

        // 💾 【数据恢复验证】显示用户历史数据
        if (
          cachedData.giftLeaderboard &&
          cachedData.giftLeaderboard.userTotalPoints > 0
        ) {
          const totalPoints = cachedData.giftLeaderboard.userTotalPoints;
          const rank = cachedData.giftLeaderboard.userRank;
          const giftCount = cachedData.userGifts
            ? cachedData.userGifts.length
            : 0;
          console.log(
            `💝 [直播间] 已恢复您的礼物记录: ${giftCount}个礼物, 总积分${totalPoints}, 排名#${
              rank || "未上榜"
            }`
          );
        }

        openLiveRoomPage();
      } else {
        showXToast("正在准备直播间...", "info");

        generateLiveRoomDetails(streamData)
          .then((liveRoomData) => {
            currentLiveRoomData.details = liveRoomData;
            // 保存到数据库
            return saveLiveRoomDetails(streamId, liveRoomData);
          })
          .then(() => {
            openLiveRoomPage();
          })
          .catch((error) => {
            console.error("❌ [直播间] 生成失败:", error);
            showXToast("进入直播间失败: " + error.message, "error");
          });
      }
    })
    .catch((error) => {
      console.error("❌ [直播间] 加载失败:", error);
      showXToast("进入直播间失败", "error");
    });
}

// 初始化直播页面
async function initLivePage() {
  try {
    // 🚨 重置退出标志,允许新的直播操作
    isLiveRoomExiting = false;

    // 🔧 重置直播列表页面样式(清除从直播间退出时的污染样式)
    // ⚠️ 只重置污染的样式，保留必要的布局样式(flex-direction, overflow等)
    const livePageElement = document.getElementById("x-live-page");
    if (livePageElement) {
      livePageElement.style.visibility = "visible";
      livePageElement.style.opacity = "1";
      livePageElement.style.pointerEvents = "auto";
    }

    currentLiveTab = "audio";

    // 加载已保存的直播数据
    await loadSavedLiveData();

    // 加载已保存的直播状态
    const liveCharacters = await loadLiveCharacterStatus();

    // 渲染直播内容
    renderLiveStreams("audio");
    renderLiveStreams("video");

    // 同步用户头像
    syncLivePageAvatar();

    // 加载自定义直播分类
    await loadLiveCustomCategories();

    // 加载自定义音乐列表
    await loadCustomMusicList();

    // 同步角色头像（使用已保存的直播状态）
    await syncLiveCharacterAvatars(liveCharacters);

    window.liveBtnExpanded = false;
    resetLiveActionButtons();
  } catch (error) {
    console.error("❌ [直播页面] 初始化失败:", error);
  }
}

