// 打开直播间页面
function openLiveRoomPage() {
  if (!currentLiveRoomData) {
    console.error("❌ [直播间] 无直播间数据");
    return;
  }

  if (currentLiveRoomData.type === "audio") {
    createAudioLiveRoom();
  } else {
    createVideoLiveRoom();
  }
}

