// 关闭直播间
function closeLiveRoom() {
  isLiveRoomExiting = true;

  if (danmakuInterval) {
    clearInterval(danmakuInterval);
    danmakuInterval = null;
  }
  if (streamerMessageInterval) {
    clearTimeout(streamerMessageInterval);
    streamerMessageInterval = null;
  }
  if (progressInterval) {
    clearInterval(progressInterval);
    progressInterval = null;
  }

  currentSpeechIndex = 0;
  if (speechRotationInterval) {
    clearInterval(speechRotationInterval);
    speechRotationInterval = null;
  }
  if (speechCheckInterval) {
    clearInterval(speechCheckInterval);
    speechCheckInterval = null;
  }

  if (currentSuperChatElement) {
    currentSuperChatElement.remove();
    currentSuperChatElement = null;
  }
  superChatQueue = [];

  // 🎙️ 清理连线系统状态
  if (connectionState.durationTimer) {
    clearInterval(connectionState.durationTimer);
    connectionState.durationTimer = null;
  }
  if (connectionState.queueInterval) {
    clearInterval(connectionState.queueInterval);
    connectionState.queueInterval = null;
  }
  connectionState.isConnected = false;
  connectionState.connectedAt = null;
  connectionState.hasRequested = false;
  connectionState.isOpen = false;
  connectionState.managementOpen = false;
  connectionState.pendingInteraction = null;
  connectionState.queuePosition = -1;
  pendingSuperChats = [];
  shownSuperChatIds.clear();
  isSuperChatDisplaying = false;

  // ⚔️ 清理PK系统状态
  if (pkState.countdownTimer) {
    clearInterval(pkState.countdownTimer);
    pkState.countdownTimer = null;
  }
  if (pkState.scoreAnimationTimer) {
    clearInterval(pkState.scoreAnimationTimer);
    pkState.scoreAnimationTimer = null;
  }
  if (pkState.preparingInterval) {
    clearInterval(pkState.preparingInterval);
    pkState.preparingInterval = null;
  }
  pkState.isActive = false;
  pkState.isPreparing = false;
  pkState.config = null;
  pkState.scenario14Data = null;

  stopAudioPlayer();

  if (sidebarState.isOpen) {
    const sidebar = document.getElementById("controlSidebar");
    const overlay = document.getElementById("controlSidebarOverlay");
    if (sidebar) sidebar.classList.remove("active");
    if (overlay) overlay.classList.remove("active");
    sidebarState.isOpen = false;
    sidebarState.isAnimating = false;
  }

  if (leaderboardState.isOpen) {
    const panel = document.getElementById("leaderboardPanel");
    if (panel) {
      panel.remove();
    }
    leaderboardState.isOpen = false;
    leaderboardState.currentIndex = 0;
    leaderboardState.currentType = "gifts";
    leaderboardState.isAnimating = false;
  }

  const container = document.getElementById("live-room-container");
  if (container) {
    container.remove();
  }

  removeLiveRoomStyles();

  currentLiveRoomData = null;
  currentProgress = 0;
}

