// 结束直播并显示消息
async function closeLiveRoomWithEndMessage() {
  const streamerName = currentLiveRoomData?.streamerName || "主播";
  const streamId = currentLiveRoomData?.id;

  console.log(`📴 [直播结束] 主播 ${streamerName} 结束了直播，正在标记状态...`);

  // 🚨 【核心】标记直播间为已结束状态
  if (currentLiveRoomData && currentLiveRoomData.details && streamId) {
    try {
      // 设置结束标志
      currentLiveRoomData.details.isEnded = true;
      currentLiveRoomData.details.endedAt = new Date().toISOString();

      // 💾 立即保存到数据库（在关闭UI之前）
      await saveLiveRoomDetails(streamId, currentLiveRoomData.details);
      console.log(
        `✅ [直播结束] 已标记直播间 ${streamId} 为结束状态并保存到数据库`
      );
    } catch (error) {
      console.error("❌ [直播结束] 保存结束状态失败:", error);
      // 即使保存失败，也要继续显示弹窗和关闭UI
    }
  } else {
    console.warn("⚠️ [直播结束] 无法标记状态：缺少必要数据");
  }

  // 显示结束弹窗（autoClose = true，会自动关闭UI）
  showLiveEndedModal(streamerName, true);
}

