// ============================================
// 侧边栏控制功能
// ============================================

// 打开侧边栏
function openLiveSidebar() {
  if (sidebarState.isAnimating || sidebarState.isOpen) return;

  sidebarState.isAnimating = true;
  sidebarState.isOpen = true;

  const sidebar = document.getElementById("controlSidebar");
  const overlay = document.getElementById("controlSidebarOverlay");

  if (sidebar) sidebar.classList.add("active");
  if (overlay) overlay.classList.add("active");

  setTimeout(() => {
    sidebarState.isAnimating = false;
  }, 400);
}

// 关闭侧边栏
function closeLiveSidebar() {
  if (sidebarState.isAnimating || !sidebarState.isOpen) return;

  sidebarState.isAnimating = true;
  sidebarState.isOpen = false;

  const sidebar = document.getElementById("controlSidebar");
  const overlay = document.getElementById("controlSidebarOverlay");

  if (sidebar) sidebar.classList.remove("active");
  if (overlay) overlay.classList.remove("active");

  setTimeout(() => {
    sidebarState.isAnimating = false;
  }, 400);
}

// 切换侧边栏
function toggleLiveSidebar() {
  if (sidebarState.isOpen) {
    closeLiveSidebar();
  } else {
    openLiveSidebar();
  }
}

// ============================================
// 🎙️ 语音连线系统
// ============================================

// 🔧 开发者模式：自动连线开关
// true: 刷新后自动建立连线，跳过申请和排队流程（方便测试）
// false: 正常流程，需要手动申请连线
let DEV_AUTO_CONNECT = false;

// 连线系统状态
let connectionState = {
  isOpen: false,
  isAnimating: false,
  settings: null, // AI生成的连线设置
  hasRequested: false, // 用户是否已申请
  isConnected: false, // 用户是否已成功连线
  pendingInteraction: null, // 保存的AI生成反应（等待连线成功后播放）
  queuePosition: -1, // 用户在队列中的位置（-1表示未在队列中）
  queueInterval: null, // 排队计时器
  connectedAt: null, // 连线开始时间戳
  durationTimer: null, // 时长更新定时器
  managementOpen: false, // 管理弹窗是否打开
};

// ⚔️ PK系统状态（打PK是语音连线状态下的新互动形式）
let pkState = {
  isActive: false, // PK是否进行中
  isPreparing: false, // 是否在准备阶段（弹窗显示中）
  config: null, // PK配置（timeLimit, penalties, challengeMessage等）
  startTime: null, // PK开始时间戳
  endTime: null, // PK结束时间戳（startTime + timeLimit * 60000）
  streamerScore: 0, // 主播当前积分
  userScore: 0, // 用户当前积分
  lastScoreUpdate: null, // 上次积分更新的数据（用于动画from值）
  scoreAnimationTimer: null, // 积分动画定时器
  countdownTimer: null, // 倒计时定时器
  progressBarVisible: false, // 进度条是否显示
  scenario14Data: null, // 第14情景生成的数据（初始积分等）
  preparingProgress: 0, // 准备弹窗的进度（0-100）
  preparingInterval: null, // 准备进度的定时器
  preGeneratedEndContent: null, // 提前生成的结束内容（30秒时）
  preGeneratedResult: null, // 提前预判的结果类型（victory/defeat/draw/closeMatch）
  prepareTriggered: false, // 是否已触发30秒预生成（避免重复）
  endContentGenerating: false, // 结束内容是否正在生成中
  endContentPromise: null, // 正在进行的生成Promise（用于等待）
  endContentError: false, // 生成是否失败（用于重试判断）
  pendingEndContent: null, // 待播放的结束内容（弹窗关闭后播放）
};

// 🔄 用户连线发言缓存（与弹幕一样，回车加入队列，点击发送才触发AI）
let userConnectionSpeechCache = [];

// 🎙️ 主播开启连线功能（互动中决定开启）
async function enableConnectionSystem() {
  if (!currentLiveRoomData || !currentLiveRoomData.details) {
    console.warn("⚠️ [连线系统] 无法开启：缺少直播间数据");
    return;
  }

  // 如果没有连线设置，创建默认设置
  if (!currentLiveRoomData.details.connectionSettings) {
    currentLiveRoomData.details.connectionSettings = {
      enabled: true,
      threshold: {
        type: "none",
        value: 0,
        description: "无门槛，欢迎所有人连线"
      },
      waitingList: [],
      maxWaiting: 8,
      averageWaitTime: "约3-5分钟"
    };
  } else if (currentLiveRoomData.details.connectionSettings.enabled) {
    return;
  } else {
    currentLiveRoomData.details.connectionSettings.enabled = true;
  }

  // 保存到数据库
  try {
    await saveLiveRoomDetails(currentLiveRoomData.id, currentLiveRoomData.details);
  } catch (error) {
    console.error("❌ [连线系统] 保存连线状态失败:", error);
  }

  // 重新初始化连线系统UI
  initConnectionSystem();

  // 显示提示
  showXToast("主播已开启连线功能", "success");
  console.log("✅ [连线系统] 连线功能已成功开启");
}

// 初始化连线系统
function initConnectionSystem() {
  // 从AI生成的数据中获取连线设置
  if (
    currentLiveRoomData &&
    currentLiveRoomData.details &&
    currentLiveRoomData.details.connectionSettings
  ) {
    connectionState.settings = currentLiveRoomData.details.connectionSettings;
    console.log("🎙️ [连线系统] 检测到连线设置");

    // 将右侧轮盘转换为连线入口
    const rightReel = document.getElementById("rightReel");
    const rightReelInner = document.getElementById("rightReelInner");

    if (rightReel && rightReelInner && connectionState.settings.enabled) {
      // 添加连线功能（使用字符串属性方式，和左侧轮盘一致）
      rightReel.classList.add("connection-reel");
      rightReel.style.cursor = "pointer";
      rightReel.title = "点击申请连线";
      rightReel.setAttribute("onclick", "openConnectionDialog()");

      // 修改内部样式为连线图标
      rightReelInner.classList.add("connection-icon-container");
      rightReelInner.style.background = "";
      rightReelInner.innerHTML = `
        <!-- 连线图标 -->
        <svg viewBox="0 0 24 24" style="width: 40px; height: 40px; fill: #666;">
          <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 18c-4.41 0-8-3.59-8-8s3.59-8 8-8 8 3.59 8 8-3.59 8-8 8zm-1-13h2v6h-2zm0 8h2v2h-2z"/>
          <circle cx="12" cy="12" r="2" fill="#999"/>
        </svg>
      `;
      console.log("✅ [连线系统] 连线入口已启用");
    }

    populateConnectionData();

    // 🔧 开发者模式：自动连线
    devAutoConnect();
  }
}

// 🔧 开发者模式：静默自动连线（跳过弹窗和排队流程）
function devAutoConnect() {
  if (!DEV_AUTO_CONNECT) return;

  // 检查连线功能是否开启
  if (!connectionState.settings || !connectionState.settings.enabled) {
    console.log("🔧 [开发者模式] 连线功能未开启，跳过自动连线");
    return;
  }

  // 已经连线了，不重复连线
  if (connectionState.isConnected) {
    console.log("🔧 [开发者模式] 已处于连线状态");
    return;
  }

  console.log("🔧 [开发者模式] 启用自动连线...");

  // 设置连线状态（静默，不显示弹窗）
  connectionState.isConnected = true;
  connectionState.hasRequested = true;
  connectionState.connectedAt = Date.now();

  // 更新UI：右侧轮盘显示用户头像
  setTimeout(() => {
    updateRightReelToUserAvatar();
    switchToConnectionMode();
    console.log("✅ [开发者模式] 自动连线成功 - 已跳过申请和排队流程");
    showXToast("🔧 开发者模式：已自动建立连线", "success");
  }, 500); // 延迟确保DOM已加载
}

// 填充连线数据到UI
function populateConnectionData() {
  const settings = connectionState.settings;
  if (!settings) return;

  // 填充等待队列数量
  const waitingCount = document.getElementById("connectionWaitingCount");
  if (waitingCount) {
    const current = settings.waitingList ? settings.waitingList.length : 0;
    const max = settings.maxWaiting || 10;
    waitingCount.textContent = `${current} / ${max}`;
  }

  // 填充平均等待时间
  const avgWait = document.getElementById("connectionAvgWait");
  if (avgWait) {
    avgWait.textContent = settings.averageWaitTime || "约3-5分钟";
  }

  // 填充门槛描述
  const thresholdText = document.querySelector(".threshold-text");
  if (thresholdText && settings.threshold) {
    if (settings.enabled) {
      thresholdText.textContent = settings.threshold.description || "无门槛";
    } else {
      thresholdText.textContent = "主播暂未开启连线功能";
    }
  }

  // 更新按钮状态
  updateConnectionButton();
}

// 更新连线按钮状态
function updateConnectionButton() {
  const settings = connectionState.settings;
  const confirmBtn = document.getElementById("connectionConfirmBtn");
  const statusTag = document.getElementById("connectionStatusTag");

  if (!confirmBtn || !statusTag || !settings) return;

  const tagText = statusTag.querySelector(".tag-text");
  if (!tagText) return;

  if (!settings.enabled) {
    // 主播未开启连线
    confirmBtn.disabled = true;
    confirmBtn.style.opacity = "0.5";
    confirmBtn.style.cursor = "not-allowed";
    tagText.textContent = "主播当前未开启连线功能";
  } else if (connectionState.hasRequested) {
    // 已申请
    confirmBtn.innerHTML = `
      <div class="btn-led" style="background: rgba(100, 200, 100, 0.8); box-shadow: 0 0 6px rgba(100, 255, 100, 0.5);"></div>
      <span class="btn-text">ALREADY REQUESTED</span>
      <div class="btn-shadow"></div>
    `;
    confirmBtn.disabled = true;
    confirmBtn.style.opacity = "0.7";
    confirmBtn.style.cursor = "not-allowed";
    tagText.textContent = "申请已提交，请耐心等待主播回应";
  } else {
    // 可以申请
    const waitingList = settings.waitingList || [];
    const maxWaiting = settings.maxWaiting || 10;

    if (waitingList.length >= maxWaiting) {
      confirmBtn.disabled = true;
      confirmBtn.style.opacity = "0.5";
      confirmBtn.style.cursor = "not-allowed";
      tagText.textContent = "当前等待队列已满，请稍后再试";
    } else {
      confirmBtn.disabled = false;
      confirmBtn.style.opacity = "1";
      confirmBtn.style.cursor = "pointer";
      tagText.textContent = "点击申请与主播连线";
    }
  }
}

// 打开连线对话框
function openConnectionDialog() {
  if (connectionState.isAnimating || connectionState.isOpen) return;

  // 检查连线设置是否存在
  if (!connectionState.settings) {
    showXToast("主播未开启连线功能", "info");
    return;
  }

  connectionState.isAnimating = true;
  connectionState.isOpen = true;

  const dialog = document.getElementById("connectionDialog");
  const overlay = document.getElementById("connectionDialogOverlay");

  if (dialog) {
    dialog.classList.add("active");
    // 触发动画
    requestAnimationFrame(() => {
      dialog.style.right = "20px";
      dialog.style.opacity = "1";
    });
  }

  if (overlay) {
    overlay.classList.add("active");
  }

  // 关闭侧边栏（如果打开）
  if (sidebarState.isOpen) {
    closeLiveSidebar();
  }

  setTimeout(() => {
    connectionState.isAnimating = false;
  }, 500);
}

// 关闭连线对话框
function closeConnectionDialog() {
  if (connectionState.isAnimating || !connectionState.isOpen) return;

  connectionState.isAnimating = true;
  connectionState.isOpen = false;

  const dialog = document.getElementById("connectionDialog");
  const overlay = document.getElementById("connectionDialogOverlay");

  if (dialog) {
    dialog.classList.remove("active");
    dialog.style.right = "-400px";
    dialog.style.opacity = "0";
  }

  if (overlay) {
    overlay.classList.remove("active");
  }

  setTimeout(() => {
    connectionState.isAnimating = false;
  }, 500);
}

// 确认申请连线（异步，需要验证门槛）
async function confirmConnection() {
  const settings = connectionState.settings;

  if (!settings || !settings.enabled) {
    showXToast("主播未开启连线功能", "error");
    return;
  }

  const waitingList = settings.waitingList || [];
  const maxWaiting = settings.maxWaiting || 10;

  if (waitingList.length >= maxWaiting) {
    showXToast("等待队列已满，请稍后再试", "error");
    return;
  }

  if (connectionState.hasRequested) {
    showXToast("您已提交申请，请勿重复申请", "info");
    return;
  }

  // 🚪 门槛验证
  const thresholdCheck = await checkConnectionThreshold(settings.threshold);
  if (!thresholdCheck.passed) {
    showXToast(thresholdCheck.reason, "error");
    return;
  }

  // ✅ 通过门槛，立即更新UI反馈
  connectionState.hasRequested = true;
  updateConnectionButton();
  showXToast("连线申请已提交！", "success");

  // 2秒后关闭对话框
  setTimeout(() => {
    if (connectionState.isOpen) {
      closeConnectionDialog();
    }
  }, 2000);

  // 后台生成AI反应（不阻塞UI）
  (async () => {
    try {
      showXToast("正在为您排队...", "info");

      // 触发AI生成连线互动（类型：connection）
      const interactionData = await generateLiveInteraction(
        [],
        [],
        "connection"
      );

      // 保存生成的反应
      connectionState.pendingInteraction = interactionData;

      console.log("✅ [连线系统] AI反应已生成，开始排队");

      // AI生成完毕后，开始排队过程
      startConnectionQueue();
    } catch (error) {
      console.error("❌ [连线系统] AI生成失败:", error);
      showXToast("连线系统繁忙，请稍后再试", "error");

      // 重置状态
      connectionState.hasRequested = false;
      updateConnectionButton();
    }
  })();
}

// 🚪 检查用户是否通过连线门槛
async function checkConnectionThreshold(threshold) {
  if (!threshold || threshold.type === "none") {
    return { passed: true };
  }

  try {
    const xDb = getXDB();
    const streamerHandle = HandleUtils.clean(
      currentLiveRoomData.streamerHandle
    );

    switch (threshold.type) {
      case "points": // 礼物积分门槛
        const userGiftPoints =
          currentLiveRoomData?.details?.giftLeaderboard?.userTotalPoints || 0;
        if (userGiftPoints < threshold.value) {
          return {
            passed: false,
            reason: `需要送礼满${threshold.value}积分，您当前${userGiftPoints}积分`,
          };
        }
        return { passed: true };

      case "fanLevel": // 粉丝团等级门槛
        const membership = await xDb.xFanClubMemberships.get(streamerHandle);
        const userLevel = membership?.level || 0;
        if (!membership || !membership.joined) {
          return {
            passed: false,
            reason: `需要加入粉丝团且等级达到${threshold.value}级`,
          };
        }
        if (userLevel < threshold.value) {
          return {
            passed: false,
            reason: `需要粉丝等级${threshold.value}级，您当前${userLevel}级`,
          };
        }
        return { passed: true };

      case "giftRank": // 礼物榜排名门槛
        const userRank =
          currentLiveRoomData?.details?.giftLeaderboard?.userRank || 999;
        if (userRank > threshold.value) {
          return {
            passed: false,
            reason: `需要礼物榜前${threshold.value}名，您当前第${userRank}名`,
          };
        }
        return { passed: true };

      case "followDays": // 关注天数门槛
        const followMembership = await xDb.xFanClubMemberships.get(
          streamerHandle
        );
        if (!followMembership || !followMembership.joined) {
          return {
            passed: false,
            reason: `需要关注主播超过${threshold.value}天`,
          };
        }
        const joinDate = followMembership.joinDate
          ? new Date(followMembership.joinDate)
          : new Date();
        const daysSinceJoin = Math.floor(
          (Date.now() - joinDate.getTime()) / (1000 * 60 * 60 * 24)
        );
        if (daysSinceJoin < threshold.value) {
          return {
            passed: false,
            reason: `需要关注主播超过${threshold.value}天，您当前${daysSinceJoin}天`,
          };
        }
        return { passed: true };

      default:
        console.warn(`⚠️ [连线门槛] 未知门槛类型: ${threshold.type}`);
        return { passed: true }; // 未知类型默认通过
    }
  } catch (error) {
    console.error("❌ [连线门槛] 验证失败:", error);
    return {
      passed: false,
      reason: "门槛验证失败，请稍后再试",
    };
  }
}

// 🚦 开始排队等待连线
function startConnectionQueue() {
  // 模拟排队人数（实际应该从服务器获取）
  const settings = connectionState.settings;
  const initialWaitingCount = settings.waitingList
    ? settings.waitingList.length
    : 0;

  connectionState.queuePosition = initialWaitingCount; // 用户在队尾
  console.log(
    `🚦 [连线排队] 开始排队，当前队列位置: ${connectionState.queuePosition}`
  );

  // 显示提示
  showXToast(
    `连线申请已提交，前面还有${connectionState.queuePosition}人等待`,
    "success"
  );

  // 更新连线对话框显示
  updateConnectionWaitingDisplay();

  // 2秒后关闭对话框，但保持状态追踪
  setTimeout(() => {
    if (connectionState.isOpen) {
      closeConnectionDialog();
    }
  }, 2000);

  // 启动排队计时器（每3-5秒减少一个队列位置，模拟前面的人连线完毕）
  const queueSpeed = 3000 + Math.random() * 2000; // 3-5秒
  connectionState.queueInterval = setInterval(() => {
    if (connectionState.queuePosition > 0) {
      connectionState.queuePosition--;
      console.log(
        `🚦 [连线排队] 队列前进，当前位置: ${connectionState.queuePosition}`
      );

      // 更新连线对话框显示（如果还开着）
      if (connectionState.isOpen) {
        updateConnectionWaitingDisplay();
      }

      // 提示用户队列前进
      if (connectionState.queuePosition === 0) {
        showXToast("排队轮到您了，即将接通连线！", "success");
      } else if (connectionState.queuePosition <= 2) {
        showXToast(`前面还有${connectionState.queuePosition}人`, "info");
      }
    } else {
      // 轮到用户了，建立连线
      clearInterval(connectionState.queueInterval);
      connectionState.queueInterval = null;
      establishConnection();
    }
  }, queueSpeed);
}

// 🔗 建立连线（排队完成）
async function establishConnection() {
  console.log("✅ [连线系统] 开始建立连线...");

  // 标记已连线并记录时间
  connectionState.isConnected = true;
  connectionState.connectedAt = Date.now();

  // 弹窗提示用户成功连线
  showConnectionSuccessModal();

  // 播放保存的AI反应
  if (connectionState.pendingInteraction) {
    console.log("🎬 [连线系统] 播放保存的AI反应");
    playConnectionInteraction(connectionState.pendingInteraction);
  }

  // 将右侧轮盘的+号替换为用户头像
  updateRightReelToUserAvatar();

  // 修改输入框功能为连线发言
  switchToConnectionMode();
}

// 🎥 播放连线互动内容（复用现有的处理逻辑，不重复造轮子）
function playConnectionInteraction(interactionData) {
  if (!interactionData) return;

  // 直接调用通用的互动数据处理函数（复用现有逻辑）
  processAndPlayInteractionData(interactionData);
}

// 👥 分析内容质量并计算人数变化
function analyzeContentQuality(streamerMessages, danmaku) {
  if (!streamerMessages || !danmaku) return 0;

  let qualityScore = 0;
  let changeAmount = 0;

  // 合并所有内容文本用于分析
  const allStreamerText = streamerMessages
    .map((m) => m.content || "")
    .join(" ")
    .toLowerCase();
  const allDanmakuText = danmaku
    .map((m) => m.content || "")
    .join(" ")
    .toLowerCase();

  // ========================================
  // 第一层：抓马和离谱事件检测（强烈吸引人）
  // ========================================
  const dramaKeywords = [
    "卧槽",
    "天哪",
    "什么鬼",
    "震惊",
    "不会吧",
    "真的假的",
    "吓我一跳",
    "我的天",
    "疯了",
    "炸了",
    "爆了",
    "牛逼",
    "绝了",
    "太离谱",
    "笑死",
    "哈哈哈哈",
    "666",
    "awesome",
    "amazing",
    "incredible",
  ];

  const accidentKeywords = [
    "水洒了",
    "手机掉了",
    "猫",
    "狗",
    "宠物",
    "打雷",
    "停电",
    "网络",
    "卡了",
    "bug",
    "出错",
    "坏了",
  ];

  let dramaCount = 0;
  dramaKeywords.forEach((keyword) => {
    if (allStreamerText.includes(keyword)) dramaCount++;
    if (allDanmakuText.includes(keyword)) dramaCount += 0.5;
  });

  let accidentCount = 0;
  accidentKeywords.forEach((keyword) => {
    if (allStreamerText.includes(keyword)) accidentCount++;
  });

  if (dramaCount >= 3 || accidentCount >= 2) {
    qualityScore += 40; // 强烈抓马事件
    console.log("🎭 检测到抓马事件！人数将大幅增加");
  } else if (dramaCount >= 1) {
    qualityScore += 15; // 一般有趣内容
  }

  // ========================================
  // 第二层：主播情绪和状态检测
  // ========================================
  const positiveKeywords = [
    "开心",
    "高兴",
    "兴奋",
    "激动",
    "喜欢",
    "爱",
    "感谢",
    "谢谢",
    "支持",
    "加油",
  ];
  const negativeKeywords = [
    "无聊",
    "累",
    "困",
    "算了",
    "不想",
    "烦",
    "差不多",
    "下播",
    "拜拜",
  ];
  const awkwardKeywords = [
    "尴尬",
    "emmm",
    "这个嘛",
    "怎么说",
    "不知道",
    "可能",
    "应该",
    "吧",
  ];

  let positiveCount = 0;
  positiveKeywords.forEach((keyword) => {
    if (allStreamerText.includes(keyword)) positiveCount++;
  });

  let negativeCount = 0;
  negativeKeywords.forEach((keyword) => {
    if (allStreamerText.includes(keyword)) negativeCount++;
  });

  let awkwardCount = 0;
  awkwardKeywords.forEach((keyword) => {
    if (allStreamerText.includes(keyword)) awkwardCount++;
  });

  if (positiveCount >= 2) {
    qualityScore += 10; // 主播心情好
  }
  if (negativeCount >= 2) {
    qualityScore -= 15; // 主播心情不好/想下播
    console.log("😴 主播状态不佳，人数将下降");
  }
  if (awkwardCount >= 3) {
    qualityScore -= 8; // 主播尴尬/冷场
  }

  // ========================================
  // 第三层：观众反应检测
  // ========================================
  const audiencePositive = [
    "666",
    "牛",
    "厉害",
    "赞",
    "支持",
    "好看",
    "好听",
    "有意思",
    "学到了",
  ];
  const audienceNegative = [
    "无聊",
    "一般",
    "就这",
    "不行",
    "溜了",
    "走了",
    "再见",
  ];

  let audienceGoodCount = 0;
  audiencePositive.forEach((keyword) => {
    if (allDanmakuText.includes(keyword)) audienceGoodCount++;
  });

  let audienceBadCount = 0;
  audienceNegative.forEach((keyword) => {
    if (allDanmakuText.includes(keyword)) audienceBadCount++;
  });

  if (audienceGoodCount >= 5) {
    qualityScore += 8; // 观众很满意
  }
  if (audienceBadCount >= 3) {
    qualityScore -= 12; // 观众不满意/要走
    console.log("👋 观众反应消极，人数将下降");
  }

  // ========================================
  // 第四层：互动频率检测（内容丰富度）
  // ========================================
  const messageCount = streamerMessages.length + danmaku.length;

  if (messageCount >= 80) {
    qualityScore += 12; // 内容非常丰富
    console.log("🔥 直播间非常活跃！");
  } else if (messageCount >= 50) {
    qualityScore += 5; // 内容较丰富
  } else if (messageCount < 30) {
    qualityScore -= 5; // 内容较少
  }

  // ========================================
  // 第五层：礼物和Super Chat检测
  // ========================================
  const hasGiftMention =
    allStreamerText.includes("礼物") || allStreamerText.includes("谢谢");
  const hasSCMention = allDanmakuText.includes("sc") || allDanmakuText.includes("super chat");

  if (hasGiftMention || hasSCMention) {
    qualityScore += 6; // 有氪金行为，吸引人
  }

  // ========================================
  // 计算最终人数变化
  // ========================================
  if (qualityScore >= 35) {
    // 非常精彩：+20 到 +50
    changeAmount = 20 + Math.floor(Math.random() * 31);
    console.log(`📈 [人数变化] 内容精彩！人数增加 +${changeAmount}`);
  } else if (qualityScore >= 15) {
    // 比较有趣：+5 到 +20
    changeAmount = 5 + Math.floor(Math.random() * 16);
    console.log(`📊 [人数变化] 内容不错，人数增加 +${changeAmount}`);
  } else if (qualityScore >= 0) {
    // 一般内容：-3 到 +10
    changeAmount = -3 + Math.floor(Math.random() * 14);
    if (changeAmount > 0) {
      console.log(`📊 [人数变化] 内容正常，人数微增 +${changeAmount}`);
    } else {
      console.log(`📉 [人数变化] 内容平淡，人数微降 ${changeAmount}`);
    }
  } else if (qualityScore >= -15) {
    // 较差内容：-10 到 -3
    changeAmount = -10 - Math.floor(Math.random() * 8);
    console.log(`📉 [人数变化] 内容较差，人数下降 ${changeAmount}`);
  } else {
    // 很差内容：-30 到 -10
    changeAmount = -30 + Math.floor(Math.random() * 21);
    console.log(`📉 [人数变化] 内容很差，人数大幅下降 ${changeAmount}`);
  }

  return changeAmount;
}

// 👥 更新在线人数并刷新UI
function updateOnlineCount(change) {
  if (!currentLiveRoomData) return;

  const oldCount = currentLiveRoomData.onlineCount || 100;
  let newCount = oldCount + change;

  // 限制范围：最少10人，最多5000人
  if (newCount < 10) {
    newCount = 10 + Math.floor(Math.random() * 5); // 10-14人
    console.log(`⚠️ [人数限制] 人数不能低于10，调整为 ${newCount}`);
  }
  if (newCount > 5000) {
    newCount = 4950 + Math.floor(Math.random() * 51); // 4950-5000人
    console.log(`⚠️ [人数限制] 人数不能超过5000，调整为 ${newCount}`);
  }

  // 更新数据
  currentLiveRoomData.onlineCount = newCount;

  // 更新UI
  const onlineText = document.getElementById("onlineText");
  if (onlineText) {
    // 添加动画效果
    onlineText.style.transition = "all 0.3s ease";
    if (change > 0) {
      onlineText.style.color = "#4ade80"; // 绿色（增长）
    } else if (change < 0) {
      onlineText.style.color = "#f87171"; // 红色（下降）
    }

    onlineText.textContent = newCount;

    // 0.5秒后恢复原色
    setTimeout(() => {
      onlineText.style.color = "";
    }, 500);
  }

  console.log(
    `👥 [在线人数] ${oldCount} → ${newCount} (${change >= 0 ? "+" : ""}${change})`
  );

  // 保存到数据库
  if (currentLiveRoomData.id) {
    saveLiveRoomBasicInfo(currentLiveRoomData.id, currentLiveRoomData).catch(
      (err) => {
        console.warn("⚠️ [人数更新] 保存失败:", err);
      }
    );
  }
}

// 🎁 播放PK观众礼物动画（根据数量调整速度）
function playPKGiftAnimations(pkGifts) {
  if (!pkGifts || pkGifts.length === 0) return;

  console.log(`🎁 [PK礼物] 开始播放${pkGifts.length}个礼物动画`);

  // 🎯 根据礼物总数调整播放速度
  // 礼物越多，每个礼物显示时间越短，整体播放越快
  const totalGifts = pkGifts.length;
  let baseDelay = 1800; // 基础间隔（毫秒）
  let animationDuration = 2500; // 基础动画时长

  if (totalGifts >= 6) {
    // 大量礼物：快速播放
    baseDelay = 800;
    animationDuration = 1500;
    console.log("🎁 [PK礼物] 大量礼物，使用快速模式");
  } else if (totalGifts >= 3) {
    // 中等礼物：中速播放
    baseDelay = 1200;
    animationDuration = 2000;
    console.log("🎁 [PK礼物] 中等数量礼物，使用中速模式");
  } else {
    // 少量礼物：正常播放
    console.log("🎁 [PK礼物] 少量礼物，使用正常模式");
  }

  // 依次播放每个礼物动画
  pkGifts.forEach((gift, index) => {
    setTimeout(() => {
      const quantity = gift.quantity || 1;

      // 🔍 根据giftName从liveGifts数组中查找对应的礼物数据
      let matchedGift = null;
      if (window.liveGifts) {
        matchedGift = window.liveGifts.find(
          (g) => g.name === gift.giftName || g.id === gift.giftName
        );
      }

      // 构造礼物数据（匹配showGiftAnimation期望的格式）
      const giftData = {
        userName: gift.sender || "观众",
        userAvatar:
          "https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg", // 默认观众头像
        giftName: matchedGift ? matchedGift.subtitle : gift.giftName,
        giftPrice: gift.giftPrice,
        giftIcon: matchedGift ? matchedGift.icon : "🎁", // 使用真实SVG图标
        giftCode: matchedGift ? matchedGift.code : "PK",
        animationType: gift.animationType || "default",
        target: gift.target, // 目标：streamer 或 user
        quantity: quantity,
      };

      console.log(
        `🎁 [PK礼物] 播放第${index + 1}/${totalGifts}个礼物: ${
          gift.sender
        } → ${gift.target === "streamer" ? "主播" : "用户"} [${
          gift.giftName
        } x${quantity}]`
      );

      // 显示礼物动画
      showGiftAnimation(giftData);

      // 🎯 更新PK积分（如果PK正在进行）
      if (window.pkState && window.pkState.active) {
        const points = gift.giftPrice * quantity;
        if (gift.target === "streamer") {
          window.pkState.streamerScore += points;
          console.log(
            `📊 [PK积分] 主播 +${points}，当前: ${window.pkState.streamerScore}`
          );
        } else if (gift.target === "user") {
          window.pkState.userScore += points;
          console.log(
            `📊 [PK积分] 用户 +${points}，当前: ${window.pkState.userScore}`
          );
        }

        // 更新PK积分显示
        updatePKScoreDisplay();
      }
    }, index * baseDelay);
  });
}

// 📦 通用的互动数据处理函数（统一处理所有类型的AI互动）
async function processAndPlayInteractionData(interactionData) {
  if (!interactionData) return;

  if (!currentLiveRoomData || !currentLiveRoomData.details) {
    console.error("❌ [互动处理] 当前没有直播间数据");
    return;
  }

  const newGenerationId = Date.now();
  console.log(`🎯 [互动处理] 新批次ID: ${newGenerationId}`);

  // 更新主播发言
  if (interactionData.streamerMessages) {
    interactionData.streamerMessages.forEach((msg) => {
      msg.generationId = newGenerationId;
    });

    currentLiveRoomData.details.streamerMessages = [
      ...interactionData.streamerMessages,
      ...currentLiveRoomData.details.streamerMessages,
    ];
  }

  // 更新弹幕
  if (interactionData.danmaku) {
    interactionData.danmaku.forEach((msg) => {
      msg.generationId = newGenerationId;
    });

    currentLiveRoomData.details.danmaku = [
      ...interactionData.danmaku,
      ...currentLiveRoomData.details.danmaku,
    ];
  }

  // 🎯 更新最新批次ID（确保SC检测能正常工作）
  currentLiveRoomData.details.latestGenerationId = newGenerationId;

  // 💰 处理SuperChat（使用统一的处理逻辑）
  if (interactionData.superChats && interactionData.superChats.length > 0) {
    interactionData.superChats.forEach((sc) => {
      sc.generationId = newGenerationId;
    });

    if (!currentLiveRoomData.details.superChats) {
      currentLiveRoomData.details.superChats = [];
    }
    currentLiveRoomData.details.superChats = [
      ...interactionData.superChats,
      ...currentLiveRoomData.details.superChats,
    ];

    console.log(
      `💰 [互动处理] AI生成了${interactionData.superChats.length}条SC，准备智能显示`
    );
  }

  // 🎁 处理PK观众礼物（PK专属）
  if (interactionData.pkGifts && interactionData.pkGifts.length > 0) {
    console.log(
      `🎁 [PK礼物] AI生成了${interactionData.pkGifts.length}个观众礼物，准备显示动画`
    );

    // 延迟显示礼物动画（让主播发言和弹幕先出现）
    setTimeout(() => {
      playPKGiftAnimations(interactionData.pkGifts);
    }, 1500);
  }

  // 保存到数据库
  try {
    await saveLiveRoomDetails(
      currentLiveRoomData.id,
      currentLiveRoomData.details
    );
  } catch (error) {
    console.error("⚠️ [互动处理] 保存数据失败:", error);
  }

  // 停止当前正在播放的内容
  if (streamerMessageInterval) {
    clearTimeout(streamerMessageInterval);
    streamerMessageInterval = null;
  }
  if (danmakuInterval) {
    clearInterval(danmakuInterval);
    danmakuInterval = null;
  }

  // 播放新生成的内容
  playNewStreamerMessages(interactionData.streamerMessages || []);
  playNewDanmaku(interactionData.danmaku || []);

  // 💰 延迟1秒后将SC添加到智能检测队列（让新弹幕先显示）
  if (interactionData.superChats && interactionData.superChats.length > 0) {
    setTimeout(() => {
      displaySuperChats(interactionData.superChats);
    }, 1000);
  }

  // 👥 分析内容质量并更新在线人数
  const onlineCountChange = analyzeContentQuality(
    interactionData.streamerMessages || [],
    interactionData.danmaku || []
  );
  updateOnlineCount(onlineCountChange);
}

// 🖼️ 将右侧轮盘替换为用户头像
function updateRightReelToUserAvatar() {
  const rightReel = document.getElementById("rightReel");
  const rightReelInner = document.getElementById("rightReelInner");

  if (!rightReel || !rightReelInner) {
    console.warn("⚠️ [连线系统] 未找到右侧轮盘元素");
    return;
  }

  const userAvatar =
    window.userProfileData?.avatar ||
    "https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg";

  // 替换为用户头像，并设置点击事件打开管理弹窗
  rightReelInner.innerHTML = `<img src="${userAvatar}" alt="用户" style="width: 100%; height: 100%; border-radius: 50%; object-fit: cover;" />`;
  rightReel.setAttribute("onclick", "openConnectionManagementDialog()");
  rightReel.style.cursor = "pointer";
  rightReel.title = "点击管理连线";

  console.log("✅ [连线系统] 右侧轮盘已更新为用户头像，可点击管理连线");
}

