// 打开PK配置弹窗
function openPKConfigDialog() {
  console.log("🎮 [PK系统] 打开PK配置弹窗");

  // 【第一验证】必须在语音连线状态下才能打开PK配置
  if (!connectionState.isConnected) {
    showXToast("请先开始语音连线，才能发起PK挑战", "error");
    console.error("❌ [PK系统] 未连线，无法打开PK配置弹窗");
    return;
  }

  // 【第二验证】防止重复触发PK
  if (pkState.isActive) {
    showXToast("PK正在进行中，请等待当前PK结束", "error");
    console.error("❌ [PK系统] PK正在进行中，无法再次发起");
    return;
  }

  if (pkState.isPreparing) {
    showXToast("PK正在准备中，请稍候...", "error");
    console.error("❌ [PK系统] PK正在准备中，无法重复发起");
    return;
  }

  // 关闭连线管理弹窗
  if (connectionState.managementOpen) {
    closeConnectionManagementDialog();
  }

  // 计算PK费用（根据用户当前积分随机决定）
  const userPoints = getUserLivePoints();
  let pkCost;

  if (userPoints < 50) {
    // 积分少：费用10-30
    pkCost = Math.floor(Math.random() * 21) + 10;
  } else if (userPoints < 200) {
    // 积分中等：费用20-50
    pkCost = Math.floor(Math.random() * 31) + 20;
  } else if (userPoints < 500) {
    // 积分较多：费用30-80
    pkCost = Math.floor(Math.random() * 51) + 30;
  } else {
    // 积分很多：费用50-150
    pkCost = Math.floor(Math.random() * 101) + 50;
  }

  console.log(`💰 [PK系统] 用户当前积分: ${userPoints}P，PK费用: ${pkCost}P`);

  // 笑面狐随机文案库（商店标签手写风格）
  const vendorMessages = [
    "今日特价！机不可失哦^^",
    "限时优惠价格！下次可能涨价^^",
    "已为您申请最低价^^（真的吗）",
    "这价格我都亏本了^^（才怪）",
    "您的专属VIP价格^^",
    "感谢惠顾！多多光临^^",
    "此价格仅限今日有效^^",
    "老板说了算便宜点^^（老板是我）",
    "成本价出售！血亏^^（骗你的）",
    "买到就是赚到^^（可能吧）",
  ];

  // 随机选择文案
  const randomMessage = vendorMessages[Math.floor(Math.random() * vendorMessages.length)];

  // 更新费用和文案显示
  const costDisplay = document.getElementById("pkCostDisplay");
  const messageDisplay = document.getElementById("pkVendorMessage");

  if (costDisplay) {
    costDisplay.textContent = `${pkCost} 积分`;
  }

  if (messageDisplay) {
    messageDisplay.textContent = randomMessage;
  }

  // 存储费用到全局（供确认时扣除）
  window.currentPKCost = pkCost;

  // 显示弹窗
  const dialog = document.getElementById("pkConfigDialog");
  const overlay = document.getElementById("pkConfigDialogOverlay");

  if (dialog) {
    dialog.classList.add("active");
    requestAnimationFrame(() => {
      dialog.style.right = "20px";
      dialog.style.opacity = "1";
    });
  }

  if (overlay) {
    overlay.classList.add("active");
  }

  console.log(`✅ [PK系统] PK配置弹窗已打开，费用: ${pkCost} 积分`);
}

