// 确认PK挑战
function confirmPKChallenge() {
  console.log("🎮 [PK系统] 确认PK挑战");

  // 【第一验证】必须在语音连线状态下才能PK
  if (!connectionState.isConnected) {
    showXToast("请先开始语音连线，才能发起PK挑战", "error");
    console.error("❌ [PK系统] PK必须在语音连线状态下进行");
    return;
  }

  // 获取表单数据
  const timeLimit = parseInt(document.getElementById("pkTimeLimitInput")?.value || "5");
  const streamerPenalty = document.getElementById("pkStreamerPenaltyInput")?.value.trim() || "";
  const userPenalty = document.getElementById("pkUserPenaltyInput")?.value.trim() || "";
  const challengeMessage = document.getElementById("pkChallengeMessageInput")?.value.trim() || "";

  // 验证必填项
  if (!streamerPenalty) {
    showXToast("请填写主播惩罚", "error");
    return;
  }

  if (!userPenalty) {
    showXToast("请填写您的惩罚", "error");
    return;
  }

  // 获取PK费用和当前积分
  const pkCost = window.currentPKCost || 0;
  const userPoints = getUserLivePoints();

  console.log(`💰 [PK系统] 当前积分: ${userPoints}P，PK费用: ${pkCost}P`);

  // 检查积分是否足够
  if (userPoints < pkCost) {
    showXToast(`积分不足！需要 ${pkCost} 积分，当前仅有 ${userPoints} 积分`, "error");
    return;
  }

  // 扣除积分（使用统一的积分管理函数）
  if (!deductLivePoints(pkCost)) {
    showXToast("扣除积分失败", "error");
    return;
  }

  console.log(`✅ [PK系统] 成功扣除 ${pkCost} 积分，剩余 ${getUserLivePoints()} 积分`);

  // 存储PK配置
  window.currentPKConfig = {
    timeLimit,
    streamerPenalty,
    userPenalty,
    challengeMessage,
    cost: pkCost,
    startTime: null, // 将在准备完成后设置
  };

  console.log("✅ [PK系统] PK配置已保存:", window.currentPKConfig);
  showPhoneNotification({
    title: "积分扣除",
    message: `已扣除 ${pkCost} 积分`,
    leftIcon: "x",
    duration: 2500,
  });

  // 关闭配置弹窗
  closePKConfigDialog();

  // 显示准备中弹窗
  showPKPreparingModal();
}

