// 触发PK开始（调用第14情景生成器）
async function triggerPKStart() {
  console.log("⚔️ [PK系统] 触发PK开始，调用第14情景...");

  try {
    // 调用现有的第14情景生成器，传入空弹幕和礼物，使用"pkStart"类型
    const interactionData = await generateLiveInteraction(
      [], // 无弹幕
      [], // 无礼物
      "pkStart" // 特殊的PK开始类型
    );

    // 保存第14情景数据
    pkState.scenario14Data = interactionData;

    console.log("✅ [PK系统] 第14情景生成完成:", interactionData);

  } catch (error) {
    console.error("❌ [PK系统] 第14情景生成失败:", error);

    // 失败时使用默认数据
    pkState.scenario14Data = {
      streamerMessages: [{
        content: "来战！",
        time: "刚刚"
      }],
      danmaku: [{
        userName: "观众1",
        content: "PK开始了！",
        time: "刚刚"
      }],
      pkScores: {
        streamer: Math.floor(Math.random() * 500) + 300,
        user: Math.floor(Math.random() * 500) + 300,
      },
    };
  }
}

// 慢速进度（等待第14情景生成）
function startSlowPKProgress() {
  const progressText = document.getElementById("pkProgressText");
  const pixels = document.querySelectorAll(".pk-energy-pixel");
  let currentPixel = 0;

  console.log("🐌 [PK系统] 开始慢速进度（等待AI生成）");

  pkState.preparingInterval = setInterval(() => {
    // 检查第14情景是否生成完毕
    if (pkState.scenario14Data) {
      console.log("🚀 [PK系统] 第14情景生成完毕，切换到快速进度");
      clearInterval(pkState.preparingInterval);
      startFastPKProgress(pkState.preparingProgress, currentPixel);
      return;
    }

    // 慢速增长（只到30%）
    pkState.preparingProgress += Math.random() * 1.5 + 0.5; // 每次增加0.5-2%
    if (pkState.preparingProgress > 30) pkState.preparingProgress = 30;

    // 更新UI
    if (progressText) {
      progressText.textContent = `${Math.floor(pkState.preparingProgress)}%`;
    }

    const targetPixel = Math.floor((pkState.preparingProgress / 100) * pixels.length);
    while (currentPixel < targetPixel && currentPixel < pixels.length) {
      pixels[currentPixel].classList.add("filled");
      currentPixel++;
    }

  }, 300); // 较慢的更新频率
}

// 快速进度（第14情景生成完毕后）
function startFastPKProgress(startProgress, startPixel) {
  const progressText = document.getElementById("pkProgressText");
  const pixels = document.querySelectorAll(".pk-energy-pixel");
  const modal = document.getElementById("pkPreparingModal");
  let currentPixel = startPixel;

  console.log("⚡ [PK系统] 开始快速进度");

  pkState.preparingInterval = setInterval(() => {
    // 快速增长
    pkState.preparingProgress += Math.random() * 12 + 8; // 每次增加8-20%
    if (pkState.preparingProgress > 100) pkState.preparingProgress = 100;

    // 更新UI
    if (progressText) {
      progressText.textContent = `${Math.floor(pkState.preparingProgress)}%`;
    }

    const targetPixel = Math.floor((pkState.preparingProgress / 100) * pixels.length);
    while (currentPixel < targetPixel && currentPixel < pixels.length) {
      pixels[currentPixel].classList.add("filled");
      currentPixel++;
    }

    // 完成
    if (pkState.preparingProgress >= 100) {
      clearInterval(pkState.preparingInterval);

      // 加载完成，延迟关闭弹窗
      setTimeout(() => {
        if (modal) modal.classList.remove("active");

        // 重置像素块状态
        pixels.forEach(pixel => pixel.classList.remove("filled"));
        if (progressText) progressText.textContent = "0%";

        pkState.isPreparing = false;

        console.log("✅ [PK系统] PK准备完成，开始PK对战！");

        // 开始PK对战
        startPKBattle();
      }, 800);
    }
  }, 100); // 快速更新频率
}

// 开始PK对战（显示进度条、初始化积分、启动倒计时）
function startPKBattle() {
  console.log("⚔️ [PK系统] 开始PK对战！");

  // 设置PK活动状态
  pkState.isActive = true;
  pkState.startTime = Date.now();
  pkState.endTime = Date.now() + (pkState.config.timeLimit * 60 * 1000);

  // 从第14情景获取初始积分（pkScores字段）
  const initialScores = pkState.scenario14Data?.pkScores || {
    streamer: 500,
    user: 500,
  };

  pkState.streamerScore = 0; // 先设为0，动画会慢慢增加到初始值
  pkState.userScore = 0;

  // 显示PK进度条
  showPKProgressBar();

  // 播放主播的反应和观众弹幕（第14情景生成的）
  if (pkState.scenario14Data) {
    // 通过processAndPlayInteractionData播放第14情景生成的内容
    processAndPlayInteractionData(pkState.scenario14Data).catch(err => {
      console.error("❌ [PK系统] 播放第14情景内容失败:", err);
    });
  }

  // 等待DOM更新完成后再启动动画
  setTimeout(() => {
    // 启动积分动画（从0到初始值）
    animateScoreChange(0, initialScores.streamer, 0, initialScores.user, true);

    // 启动倒计时
    startPKCountdown();
  }, 100); // 100ms延迟确保DOM已更新
}

