// 初始化侧边栏手势识别（改用双击触发）
function initLiveSidebarGestures() {
  const liveRoom = document.querySelector(".live-room");
  if (!liveRoom) return;

  // 双击检测变量
  let lastTapTime = 0;
  let tapCount = 0;
  const doubleTapDelay = 300; // 双击时间窗口：300ms

  // 不应触发双击的元素选择器
  const excludeSelectors = [
    "button",
    "input",
    "textarea",
    "a",
    ".action-btn", // 点赞/发送按钮
    ".danmaku-input",
    ".send-btn",
    ".live-action-btn",
    ".music-control-btn",
    ".settings-btn",
    ".header-icon", // 顶部导航按钮
    ".sidebar-item", // 侧边栏项目
    ".sidebar-close-btn", // 侧边栏关闭按钮
    "#danmakuList",
    ".streamer-message-carousel",
    "#superchat-display",
    ".speech-history-overlay",
    ".danmaku-history-overlay",
    "#controlSidebar",
    "#leaderboardPanel",
    ".like-container", // 点赞动画容器
    ".cassette-player", // 磁带播放器
    ".cassette-window", // 弹幕窗口
    ".audio-bars", // 音波条
    ".live-info-card", // 信息卡片
    ".live-details", // 详情区域
    ".gift-menu-panel", // 礼物菜单
    ".gift-card", // 礼物卡片
    ".connection-dialog", // 连线对话框
    "#rightReel", // 右侧轮盘（可能是连线入口）
  ];

  // 检查点击目标是否在排除列表中
  const isExcludedElement = (target) => {
    for (const selector of excludeSelectors) {
      if (target.matches(selector) || target.closest(selector)) {
        return true;
      }
    }
    return false;
  };

  const handleDoubleTap = (e) => {
    if (isExcludedElement(e.target)) {
      return;
    }

    const currentTime = Date.now();
    const timeSinceLastTap = currentTime - lastTapTime;

    if (timeSinceLastTap < doubleTapDelay && timeSinceLastTap > 0) {
      tapCount++;

      if (!sidebarState.isOpen) {
        openLiveSidebar();
      }

      lastTapTime = 0;
      tapCount = 0;
    } else {
      lastTapTime = currentTime;
      tapCount = 1;
    }
  };

  const handleDoubleClick = (e) => {
    if (isExcludedElement(e.target)) {
      return;
    }

    if (!sidebarState.isOpen) {
      openLiveSidebar();
    }
  };

  liveRoom.addEventListener("touchend", handleDoubleTap, { passive: true });
  liveRoom.addEventListener("dblclick", handleDoubleClick);

  const overlay = document.getElementById("controlSidebarOverlay");
  if (overlay) {
    overlay.addEventListener("click", closeLiveSidebar);
  }
}

// ============================================
// 榜单渲染和交互逻辑
// ============================================

// 格式化数值
function formatLeaderboardValue(value, type) {
  const config = leaderboardConfig[type];
  if (!config) return value;

  const formatted = config.formatValue(value);
  return `${config.valuePrefix}${formatted}`;
}

// 渲染榜单列表
function renderLeaderboardList(type) {
  const details = currentLiveRoomData?.details;
  if (!details || !details.leaderboards || !details.leaderboards[type]) {
    console.warn(`⚠️ [榜单] 没有${type}榜单数据`);
    return "<div style='padding: 20px; text-align: center; color: #71767b;'>暂无数据</div>";
  }

  let data = [...details.leaderboards[type]];

  if (
    type === "gifts" &&
    details.giftLeaderboard &&
    details.giftLeaderboard.userRank &&
    details.giftLeaderboard.userRank <= 10
  ) {
    const userName = window.userProfileData?.name || "我";
    const userHandle = window.userProfileData?.handle || "@user";
    const userTotalPoints = details.giftLeaderboard.userTotalPoints;

    const userItem = {
      userName: userName,
      userHandle: userHandle,
      value: userTotalPoints,
      isUser: true,
      badge: "👤",
    };

    data.push(userItem);
    data.sort((a, b) => b.value - a.value);
    data = data.slice(0, 10);
  }

  return data
    .map((item, index) => {
      const isTop3 = index < 3;
      const medals = ["🥇", "🥈", "🥉"];
      const medal = isTop3 ? medals[index] : index + 1;
      const badge = item.badge
        ? `<span class="rank-badge">${item.badge}</span>`
        : "";

      // 🆕 动态生成头像（用户使用真实头像，NPC使用随机头像）
      const avatar = item.isUser
        ? window.userProfileData?.avatar ||
          `https://api.dicebear.com/7.x/avataaars/svg?seed=user`
        : `https://api.dicebear.com/7.x/avataaars/svg?seed=${type}_${
            index + 1
          }`;

      // 🎨 用户榜单项高亮显示
      const isUserClass = item.isUser ? "user-rank-item" : "";

      return `
        <div class="rank-item ${isTop3 ? "top-3" : ""} ${isUserClass}">
          <span class="rank-medal">${medal}</span>
          <img class="rank-avatar" src="${avatar}" alt="${item.userName}"/>
          <span class="rank-name">${item.userName}</span>
          <span class="rank-value">${formatLeaderboardValue(
            item.value,
            type
          )}${badge}</span>
        </div>
      `;
    })
    .join("");
}

