// 更新榜单标题和指示器
function updateLeaderboardUI() {
  const currentType = leaderboardState.types[leaderboardState.currentIndex];
  const title = document.getElementById("leaderboardTitle");
  const indicator = document.getElementById("leaderboardIndicator");
  const prevBtn = document.getElementById("leaderboardPrev");
  const nextBtn = document.getElementById("leaderboardNext");

  if (title) {
    title.textContent = leaderboardConfig[currentType].title;
  }

  if (indicator) {
    indicator.textContent = `${leaderboardState.currentIndex + 1}/3`;
  }

  // 更新箭头禁用状态
  if (prevBtn) {
    if (leaderboardState.currentIndex === 0) {
      prevBtn.classList.add("disabled");
    } else {
      prevBtn.classList.remove("disabled");
    }
  }

  if (nextBtn) {
    if (leaderboardState.currentIndex === 2) {
      nextBtn.classList.add("disabled");
    } else {
      nextBtn.classList.remove("disabled");
    }
  }

  // 🏆 刷新所有榜单内容（特别是礼物榜单，需要显示用户数据）
  leaderboardState.types.forEach((type, index) => {
    const tapeSide = document.getElementById(`tapeSide${index}`);
    if (tapeSide) {
      tapeSide.innerHTML = renderLeaderboardList(type);
    }
  });
}

// 切换榜单面板（磁带翻页效果）
function switchLeaderboard(newIndex, direction) {
  if (leaderboardState.isAnimating) return;
  if (newIndex < 0 || newIndex > 2) return;
  if (newIndex === leaderboardState.currentIndex) return;

  leaderboardState.isAnimating = true;

  const oldIndex = leaderboardState.currentIndex;
  const oldPanel = document.getElementById(`tapeSide${oldIndex}`);
  const newPanel = document.getElementById(`tapeSide${newIndex}`);

  if (!oldPanel || !newPanel) {
    leaderboardState.isAnimating = false;
    return;
  }

  // 移除所有动画类
  [oldPanel, newPanel].forEach((panel) => {
    panel.classList.remove(
      "flip-out-left",
      "flip-in-right",
      "flip-out-right",
      "flip-in-left"
    );
  });

  // 添加翻页动画
  if (direction === "next") {
    oldPanel.classList.add("flip-out-left");
    newPanel.classList.add("flip-in-right");
  } else {
    oldPanel.classList.add("flip-out-right");
    newPanel.classList.add("flip-in-left");
  }

  // 显示新面板
  newPanel.classList.add("active");

  // 动画结束后清理
  setTimeout(() => {
    oldPanel.classList.remove("active", "flip-out-left", "flip-out-right");
    newPanel.classList.remove("flip-in-right", "flip-in-left");

    leaderboardState.currentIndex = newIndex;
    leaderboardState.currentType = leaderboardState.types[newIndex];

    updateLeaderboardUI();
    leaderboardState.isAnimating = false;
  }, 500);
}

// 上一个榜单
function prevLeaderboard() {
  if (leaderboardState.currentIndex > 0) {
    switchLeaderboard(leaderboardState.currentIndex - 1, "prev");
  }
}

// 下一个榜单
function nextLeaderboard() {
  if (leaderboardState.currentIndex < 2) {
    switchLeaderboard(leaderboardState.currentIndex + 1, "next");
  }
}

// 关闭榜单
function closeLeaderboard() {
  if (!leaderboardState.isOpen) return;

  const panel = document.getElementById("leaderboardPanel");
  if (panel) {
    panel.classList.remove("active");

    setTimeout(() => {
      panel.remove();
      leaderboardState.isOpen = false;
      leaderboardState.currentIndex = 0;
      leaderboardState.currentType = "gifts";
    }, 500);
  }
}

// 初始化榜单手势识别
function initLeaderboardGestures() {
  const panel = document.getElementById("leaderboardPanel");
  if (!panel) return;

  let touchStartX = 0;
  let touchStartY = 0;
  let touchCurrentX = 0;

  const handleTouchStart = (e) => {
    const touch = e.touches[0];
    touchStartX = touch.clientX;
    touchStartY = touch.clientY;
    touchCurrentX = touch.clientX;
  };

  const handleTouchMove = (e) => {
    const touch = e.touches[0];
    touchCurrentX = touch.clientX;

    const deltaX = touchStartX - touch.clientX;
    const deltaY = Math.abs(touchStartY - touch.clientY);

    // 横向滑动优先（大于纵向滑动时阻止滚动）
    if (Math.abs(deltaX) > deltaY && Math.abs(deltaX) > 10) {
      e.preventDefault();
    }
  };

  const handleTouchEnd = () => {
    const deltaX = touchStartX - touchCurrentX;

    // 向左滑动超过50px，切换到下一个榜单
    if (deltaX > 50 && leaderboardState.currentIndex < 2) {
      nextLeaderboard();
    }
    // 向右滑动超过50px，切换到上一个榜单
    else if (deltaX < -50 && leaderboardState.currentIndex > 0) {
      prevLeaderboard();
    }

    // 重置
    touchStartX = 0;
    touchStartY = 0;
    touchCurrentX = 0;
  };

  panel.addEventListener("touchstart", handleTouchStart, { passive: true });
  panel.addEventListener("touchmove", handleTouchMove, { passive: false });
  panel.addEventListener("touchend", handleTouchEnd, { passive: true });
}

// 打开榜单
function openLeaderboard() {
  if (leaderboardState.isOpen) {
    return;
  }

  const liveRoom = document.querySelector(".live-room");
  if (!liveRoom) {
    showXToast("请先进入直播间", "info");
    return;
  }

  if (sidebarState.isOpen) {
    closeLiveSidebar();
  }

  const panelHTML = createLeaderboardHTML();
  liveRoom.insertAdjacentHTML("beforeend", panelHTML);

  updateLeaderboardUI();
  initLeaderboardGestures();

  setTimeout(() => {
    const panel = document.getElementById("leaderboardPanel");
    if (panel) {
      panel.classList.add("active");
      leaderboardState.isOpen = true;
    }
  }, 50);
}

// 暴露函数到全局
window.prevLeaderboard = prevLeaderboard;

// ============================================
// 🎤 从直播间打开主播主页
// ============================================

/**
 * 从直播间打开主播账户主页
 * 收集直播间上下文（主播发言、弹幕、直播主题等）并传递给账户主页生成器
 */
window.openStreamerProfileFromLive = async function () {
  try {
    isLiveRoomExiting = true;

    if (!currentLiveRoomData) {
      showXToast("直播间数据异常", "error");
      isLiveRoomExiting = false;
      return;
    }

    // 停止弹幕轮播
    if (danmakuInterval) {
      clearInterval(danmakuInterval);
      danmakuInterval = null;
    }

    // 停止主播发言轮播
    if (streamerMessageInterval) {
      clearTimeout(streamerMessageInterval);
      streamerMessageInterval = null;
    }

    // 停止进度条更新
    if (progressInterval) {
      clearInterval(progressInterval);
      progressInterval = null;
    }

    // 停止主播发言检测定时器
    if (speechCheckInterval) {
      clearInterval(speechCheckInterval);
      speechCheckInterval = null;
    }

    // 停止主播发言轮播定时器
    if (speechRotationInterval) {
      clearInterval(speechRotationInterval);
      speechRotationInterval = null;
    }

    // 强制隐藏主播发言UI
    const speechText = document.getElementById("streamerSpeech");
    const speechContent = document.getElementById("speechContent");
    const audioBars = document.getElementById("audioBars");
    const visualizer = speechText?.parentElement;

    if (speechText) {
      speechText.style.display = "none";
      speechText.classList.remove("active", "fading");
      speechText.style.opacity = "0";
    }
    if (speechContent) {
      speechContent.style.animation = "none";
    }
    if (audioBars) {
      audioBars.classList.remove("dimmed");
      audioBars.style.opacity = "1";
    }
    if (visualizer) {
      visualizer.classList.remove("speech-active");
    }

    // 清理 Super Chat 队列
    if (currentSuperChatElement) {
      currentSuperChatElement.remove();
      currentSuperChatElement = null;
    }
    superChatQueue = [];
    pendingSuperChats = [];
    shownSuperChatIds.clear();
    isSuperChatDisplaying = false;

    // 停止音频播放器
    if (typeof stopAudioPlayer === "function") {
      stopAudioPlayer();
    }

    currentSpeechIndex = 0;

    // 关闭所有弹出层
    if (sidebarState && sidebarState.isOpen) {
      const sidebar = document.getElementById("controlSidebar");
      const overlay = document.getElementById("controlSidebarOverlay");
      if (sidebar) sidebar.classList.remove("active");
      if (overlay) overlay.classList.remove("active");
      sidebarState.isOpen = false;
      sidebarState.isAnimating = false;
    }

    // 从currentLiveRoomData提取主播信息（必须在清理前保存）
    const streamer = {
      name: currentLiveRoomData.streamerName || "主播",
      handle: currentLiveRoomData.streamerHandle || "@streamer",
      avatar: currentLiveRoomData.streamerAvatar || "",
    };

    const danmakuListElement = document.getElementById("danmakuList");
    const danmakuElements = danmakuListElement
      ? Array.from(danmakuListElement.children)
      : [];
    const danmakuMessages = danmakuElements
      .map((el) => {
        const userEl = el.querySelector(".danmaku-user");
        const textEl = el.querySelector(".danmaku-text");
        return {
          userId: userEl ? userEl.textContent : "观众",
          content: textEl ? textEl.textContent : "",
          time: Date.now(),
        };
      })
      .filter((dm) => dm.content);

    // 获取主播发言历史（从details中）
    const streamerSpeeches = [];
    if (
      currentLiveRoomData.details &&
      currentLiveRoomData.details.streamerMessages
    ) {
      currentLiveRoomData.details.streamerMessages.slice(-10).forEach((msg) => {
        streamerSpeeches.push({
          content: msg.text || msg,
          time: Date.now(),
        });
      });
    }

    const liveContext = {
      // 直播主题
      liveTitle: currentLiveRoomData.title || "直播中",
      liveSubtitle:
        `${currentLiveRoomData.streamerName} ${currentLiveRoomData.streamerHandle}` ||
        "",

      // 直播时长
      liveDuration: currentLiveRoomData.duration || "00:00",

      // 主播发言记录
      streamerSpeeches: streamerSpeeches,

      // 弹幕记录
      danmakuMessages: danmakuMessages,

      // 在线观众数
      onlineViewers: currentLiveRoomData.onlineCount || 0,

      // 直播描述和公告
      liveDescription:
        (currentLiveRoomData.details &&
          (currentLiveRoomData.details.details ||
            currentLiveRoomData.details.description)) ||
        "",
      liveNotice:
        (currentLiveRoomData.details && currentLiveRoomData.details.notice) ||
        "",

      // 直播标签
      liveTags:
        (currentLiveRoomData.details && currentLiveRoomData.details.tags) || [],
    };

    // 获取主播句柄
    const streamerHandle = HandleUtils.clean(
      currentLiveRoomData.streamerHandle || streamer.handle
    );

    // 1. 收集用户粉丝团数据
    let fanClubData = null;
    try {
      const xDb = getXDB();
      const membership = await xDb.xFanClubMemberships.get(streamerHandle);
      if (membership && membership.joined) {
        fanClubData = {
          joined: true,
          level: membership.level || 0,
          points: membership.points || 0,
          checkinDays: membership.checkinDays || 0,
        };
      }
    } catch (error) {
      console.warn("⚠️ [直播→主页] 获取粉丝团数据失败:", error);
    }

    // 2. 收集用户礼物贡献数据
    let giftContribution = 0;
    let userGifts = []; // 🆕 用户送的所有礼物详细信息
    try {
      if (
        currentLiveRoomData.details &&
        currentLiveRoomData.details.giftLeaderboard
      ) {
        giftContribution =
          currentLiveRoomData.details.giftLeaderboard.userTotalPoints || 0;

        if (
          currentLiveRoomData.details.userGifts &&
          currentLiveRoomData.details.userGifts.length > 0
        ) {
          userGifts = currentLiveRoomData.details.userGifts.map((gift) => ({
            name: gift.giftName,
            code: gift.giftCode,
            price: gift.giftPrice,
            description: gift.description || "",
            isCustom: gift.isCustom || false,
            category: gift.category || "",
            imageUrl: gift.imageUrl || "",
            imageLocal: gift.imageLocal || "",
            useLocalImage: gift.useLocalImage || false,
            timestamp: gift.timestamp,
          }));
        }
      }
    } catch (error) {
      console.warn("⚠️ [直播→主页] 获取礼物贡献失败:", error);
    }

    let userDanmakuMessages = [];
    try {
      if (currentLiveRoomData.details && currentLiveRoomData.details.danmaku) {
        userDanmakuMessages = currentLiveRoomData.details.danmaku
          .filter((d) => d.isUser === true)
          .map((d) => d.content);
      }
    } catch (error) {
      console.warn("⚠️ [直播→主页] 获取用户弹幕失败:", error);
    }

    // 获取主播追随者数量
    let streamerFollowers = 0;
    try {
      const xDb = getXDB();
      const allProfiles = await xDb.xAccountProfiles.toArray();
      const accountProfile = allProfiles.find(
        (p) =>
          p.data &&
          p.data.accountInfo &&
          (p.data.accountInfo.handle === streamerHandle ||
            p.data.accountInfo.handle === `@${streamerHandle}`)
      );

      if (
        accountProfile &&
        accountProfile.data &&
        accountProfile.data.accountInfo
      ) {
        streamerFollowers = accountProfile.data.accountInfo.followers || 0;
      }
    } catch (error) {
      console.warn("⚠️ [直播→主页] 获取主播追随者数失败:", error);
    }

    const liveUserData = {
      fanClub: fanClubData,
      giftContribution: giftContribution,
      gifts: userGifts,
      userDanmaku: userDanmakuMessages,
      streamerFollowers: streamerFollowers,
    };

    const sourceContext = {
      source: "live",
      liveContext: liveContext,
      liveUserData: liveUserData,
      isLiveStreaming: true,
    };

    closeLiveRoom();

    const livePageElement = document.getElementById("x-live-page");
    if (livePageElement) {
      livePageElement.style.visibility = "hidden";
      livePageElement.style.opacity = "0";
      livePageElement.style.pointerEvents = "none";
    }

    const xSocialScreen = document.getElementById("x-social-screen");
    if (xSocialScreen) {
      xSocialScreen.style.display = "flex";
      xSocialScreen.style.visibility = "visible";
    }

    const homePageElement = document.getElementById("x-home-page");
    if (homePageElement) {
      homePageElement.style.display = "flex";
    }

    const topBar = document.querySelector(".x-top-bar");
    const bottomNav = document.querySelector(".x-bottom-nav");
    if (topBar) {
      topBar.style.display = "flex";
    }
    if (bottomNav) {
      bottomNav.style.display = "flex";
    }

    await new Promise((resolve) => setTimeout(resolve, 150));

    await window.openAccountProfile(
      streamer.name,
      streamer.handle,
      streamer.avatar,
      sourceContext
    );
  } catch (error) {
    console.error("❌ [直播→主页] 打开主播主页失败:", error);
    showXToast("打开主播主页失败: " + error.message, "error");
  }
};

