// 初始化默认礼物分类
async function initDefaultGiftCategory() {
  const xDb = getXDB();
  const accountId = currentAccountId || "default";

  try {
    // 检查是否已存在默认分类
    const existingDefault = await xDb.xCustomGiftCategories
      .where({ accountId: accountId, isDefault: 1 })
      .first();

    if (existingDefault) {
      return;
    }

    const defaultCategoryId = `gift_cat_${Date.now()}`;
    await xDb.xCustomGiftCategories.add({
      id: defaultCategoryId,
      accountId: accountId,
      name: "原始礼物",
      enabled: 1,
      isDefault: 1,
      createdAt: new Date().toISOString(),
    });

    // 添加默认礼物（基于liveGifts数组）
    const defaultGifts = liveGifts.map((gift) => ({
      id: `gift_${Date.now()}_${gift.id}`,
      categoryId: defaultCategoryId,
      accountId: accountId,
      name: gift.name,
      subtitle: gift.subtitle,
      code: gift.code,
      description: gift.subtitle,
      imageUrl: "", // SVG存储在icon字段
      icon: gift.icon,
      useLocalImage: false,
      points: gift.price,
      animationType: "default",
      createdAt: new Date().toISOString(),
    }));

    await xDb.xCustomGifts.bulkAdd(defaultGifts);
  } catch (error) {
    console.error("❌ [自定义礼物] 初始化失败:", error);
  }
}

// 获取所有礼物分类
async function getGiftCategories() {
  const xDb = getXDB();
  const accountId = currentAccountId || "default";

  try {
    const categories = await xDb.xCustomGiftCategories
      .where({ accountId: accountId })
      .toArray();
    return categories.sort((a, b) => {
      // 默认分类排在最前
      if (a.isDefault) return -1;
      if (b.isDefault) return 1;
      return new Date(b.createdAt) - new Date(a.createdAt);
    });
  } catch (error) {
    console.error("❌ [自定义礼物] 获取分类失败:", error);
    return [];
  }
}

// 获取分类下的所有礼物
async function getGiftsByCategory(categoryId) {
  const xDb = getXDB();

  try {
    const gifts = await xDb.xCustomGifts
      .where({ categoryId: categoryId })
      .toArray();
    return gifts.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
  } catch (error) {
    console.error("❌ [自定义礼物] 获取礼物列表失败:", error);
    return [];
  }
}

// 获取所有启用分类的礼物
async function getEnabledGifts() {
  const xDb = getXDB();
  const accountId = currentAccountId || "default";

  try {
    // 获取启用的分类
    const enabledCategories = await xDb.xCustomGiftCategories
      .where({ accountId: accountId, enabled: 1 })
      .toArray();

    if (enabledCategories.length === 0) {
      return [];
    }

    // 获取这些分类下的所有礼物
    const categoryIds = enabledCategories.map((cat) => cat.id);
    const allGifts = await xDb.xCustomGifts
      .where("categoryId")
      .anyOf(categoryIds)
      .toArray();

    // 🔧 Linus: 按积分从低到高排序
    return allGifts.sort((a, b) => (a.points || 0) - (b.points || 0));
  } catch (error) {
    console.error("❌ [自定义礼物] 获取启用礼物失败:", error);
    return [];
  }
}

// 创建新分类
async function createGiftCategory(name) {
  const xDb = getXDB();
  const accountId = currentAccountId || "default";

  try {
    const newCategory = {
      id: `gift_cat_${Date.now()}`,
      accountId: accountId,
      name: name,
      enabled: 0,
      isDefault: 0,
      createdAt: new Date().toISOString(),
    };

    await xDb.xCustomGiftCategories.add(newCategory);
    return newCategory;
  } catch (error) {
    console.error("❌ [自定义礼物] 创建分类失败:", error);
    return null;
  }
}

// 删除分类（及其下的所有礼物）
async function deleteGiftCategory(categoryId) {
  const xDb = getXDB();

  try {
    const category = await xDb.xCustomGiftCategories.get(categoryId);
    if (category && category.isDefault === 1) {
      showXToast("默认分类无法删除", "error");
      return false;
    }

    await xDb.xCustomGifts.where({ categoryId: categoryId }).delete();
    await xDb.xCustomGiftCategories.delete(categoryId);

    return true;
  } catch (error) {
    console.error("❌ [自定义礼物] 删除分类失败:", error);
    return false;
  }
}

// 切换分类启用状态
async function toggleCategoryEnabled(categoryId) {
  const xDb = getXDB();

  try {
    const category = await xDb.xCustomGiftCategories.get(categoryId);
    if (!category) return false;

    await xDb.xCustomGiftCategories.update(categoryId, {
      enabled: category.enabled === 1 ? 0 : 1,
    });

    return true;
  } catch (error) {
    console.error("❌ [自定义礼物] 切换分类状态失败:", error);
    return false;
  }
}

// 创建新礼物
async function createCustomGift(giftData) {
  const xDb = getXDB();
  const accountId = currentAccountId || "default";

  try {
    const newGift = {
      id: `gift_${Date.now()}`,
      categoryId: giftData.categoryId,
      accountId: accountId,
      name: giftData.name,
      subtitle: giftData.subtitle || "",
      code: giftData.code,
      description: giftData.description,
      imageUrl: giftData.imageUrl || "",
      imageLocal: giftData.imageLocal || "",
      icon: giftData.icon || "",
      useLocalImage: giftData.useLocalImage || false,
      points: giftData.points,
      animationType: giftData.animationType || "default",
      createdAt: new Date().toISOString(),
    };

    await xDb.xCustomGifts.add(newGift);
    return newGift;
  } catch (error) {
    console.error("❌ [自定义礼物] 创建礼物失败:", error);
    return null;
  }
}

// 删除礼物
async function deleteCustomGift(giftId) {
  const xDb = getXDB();

  try {
    await xDb.xCustomGifts.delete(giftId);
    return true;
  } catch (error) {
    console.error("❌ [自定义礼物] 删除礼物失败:", error);
    return false;
  }
}

// 获取用户直播积分
function getUserLivePoints() {
  const points = localStorage.getItem(
    `livePoints_${currentAccountId || "default"}`
  );
  const parsed = points ? parseInt(points) : 0;

  // 🔧 修复NaN问题：如果解析失败，重置为默认值
  if (isNaN(parsed)) {
    console.warn(`⚠️ [积分系统] 检测到无效积分值，已重置为5000P`);
    saveUserLivePoints(5000);
    return 5000;
  }

  return parsed;
}

// 保存用户直播积分
function saveUserLivePoints(points) {
  // 🔧 修复NaN问题：拒绝保存无效值
  if (isNaN(points) || points === undefined || points === null) {
    console.error(`❌ [积分系统] 拒绝保存无效积分: ${points}`);
    return;
  }

  localStorage.setItem(
    `livePoints_${currentAccountId || "default"}`,
    points.toString()
  );
}

// 扣除积分
function deductLivePoints(amount) {
  // 🔧 修复NaN问题：确保amount有效
  if (isNaN(amount) || amount <= 0) {
    console.error(`❌ [积分系统] 无效扣除金额: ${amount}`);
    return false;
  }

  const currentPoints = getUserLivePoints();
  if (currentPoints < amount) {
    console.warn(
      `⚠️ [积分系统] 积分不足: 需要${amount}P，当前${currentPoints}P`
    );
    return false;
  }
  saveUserLivePoints(currentPoints - amount);
  return true;
}
window.nextLeaderboard = nextLeaderboard;
window.closeLeaderboard = closeLeaderboard;

// 侧边栏按钮功能（占位函数）

