// 🔧 Linus: 刷新礼物菜单（实时更新礼物列表）
async function refreshGiftMenu() {
  if (!giftMenuState.isOpen) return;

  const selectionArea = document.querySelector(".jukebox-selection-area");
  const pointsDisplay = document.getElementById("giftPointsValue");

  if (!selectionArea) return;

  // 获取当前积分
  const currentPoints = getUserLivePoints();

  // 更新积分显示
  if (pointsDisplay) {
    pointsDisplay.textContent = currentPoints.toLocaleString();
  }

  // 获取启用的礼物列表
  const enabledGifts = await getEnabledGifts();

  // 如果没有启用的礼物，使用默认礼物并排序
  let giftsToShow = enabledGifts.length > 0 ? enabledGifts : liveGifts;

  // 🔧 Linus: 确保默认礼物也按积分排序
  if (enabledGifts.length === 0) {
    giftsToShow = [...liveGifts].sort(
      (a, b) => (a.price || 0) - (b.price || 0)
    );
  }

  // 保存当前选中的礼物ID
  const currentSelectedId = giftMenuState.selectedGift?.id;

  // 重新生成礼物列表HTML
  const giftsHTML = giftsToShow
    .map((gift) => {
      const canAfford = currentPoints >= gift.points;
      const priceDisplay =
        gift.points >= 1000
          ? (gift.points / 1000).toFixed(gift.points % 1000 === 0 ? 0 : 1) + "K"
          : gift.points;

      // 获取礼物图标
      let giftIconHTML = "";
      if (gift.useLocalImage && gift.imageLocal) {
        giftIconHTML = `<img src="${gift.imageLocal}" alt="${gift.name}" style="width:100%;height:100%;object-fit:contain;">`;
      } else if (gift.imageUrl) {
        giftIconHTML = `<img src="${gift.imageUrl}" alt="${gift.name}" style="width:100%;height:100%;object-fit:contain;">`;
      } else if (gift.icon) {
        giftIconHTML = gift.icon;
      } else {
        giftIconHTML =
          '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:24px;color:rgba(255,255,255,0.3);">?</div>';
      }

      return `
        <div class="jukebox-ticket ${canAfford ? "" : "insufficient"}" 
             data-gift-id="${gift.id}"
             data-gift-code="${gift.code}"
             onclick="selectGift('${gift.id}')">
          <!-- 左侧：编号+图标区 -->
          <div class="ticket-left-section">
            <div class="ticket-code">${gift.code}</div>
            <div class="ticket-icon-box">
              ${giftIconHTML}
            </div>
            <div class="ticket-perforations">
              <div class="perf"></div>
              <div class="perf"></div>
              <div class="perf"></div>
            </div>
          </div>
          
          <!-- 右侧：信息区 -->
          <div class="ticket-right-section">
            <div class="ticket-main-name">${gift.name}</div>
            <div class="ticket-subtitle">${
              gift.subtitle || gift.description || ""
            }</div>
            <div class="ticket-price-tag">
              <span class="price-amount">${priceDisplay}</span>
              <span class="price-currency">P</span>
            </div>
            ${
              !canAfford
                ? '<div class="insufficient-badge">INSUFFICIENT</div>'
                : ""
            }
          </div>
          
          <!-- 选中指针 -->
          <div class="selection-pointer">▶</div>
        </div>
      `;
    })
    .join("");

  // 更新DOM
  selectionArea.innerHTML = giftsHTML;

  // 恢复选中状态（如果之前有选中且该礼物仍然存在）
  if (currentSelectedId) {
    const stillExists = giftsToShow.find((g) => g.id === currentSelectedId);
    if (stillExists) {
      // 重新选中
      await selectGift(currentSelectedId);
    } else {
      // 礼物不存在了，清空选中状态
      giftMenuState.selectedGift = null;
      const codeDisplay = document.getElementById("selectedGiftCode");
      if (codeDisplay) codeDisplay.textContent = "- -";

      const footerInfo = document.getElementById("giftFooterInfo");
      const sendBtn = document.getElementById("giftSendBtn");
      if (footerInfo) {
        footerInfo.innerHTML =
          '<div class="play-bar-placeholder">SELECT A GIFT TO PLAY</div>';
      }
      if (sendBtn) {
        sendBtn.disabled = true;
        sendBtn.classList.remove("ready");
      }
    }
  }
}
window.refreshGiftMenu = refreshGiftMenu;

// 关闭礼物菜单
function closeGiftMenu() {
  if (!giftMenuState.isOpen) return;

  const panel = document.getElementById("giftMenuPanel");
  const overlay = document.getElementById("giftMenuOverlay");

  if (panel) panel.classList.remove("active");
  if (overlay) overlay.classList.remove("active");

  setTimeout(() => {
    if (panel && panel.parentNode) panel.parentNode.removeChild(panel);
    if (overlay && overlay.parentNode) overlay.parentNode.removeChild(overlay);
    giftMenuState.isOpen = false;
    giftMenuState.selectedGift = null;
  }, 300);
}

// 选择礼物（兼容自定义礼物）
async function selectGift(giftId) {
  // 先从启用的自定义礼物中查找
  const enabledGifts = await getEnabledGifts();
  let gift = enabledGifts.find((g) => g.id === giftId);

  // 如果没找到，从默认礼物中查找
  if (!gift) {
    gift = liveGifts.find((g) => g.id === giftId);
    if (gift) {
      // 转换为统一格式
      gift = {
        id: gift.id,
        name: gift.name,
        subtitle: gift.subtitle,
        code: gift.code,
        points: gift.price,
        icon: gift.icon,
        animationType: "default",
      };
    }
  }

  if (!gift) return;

  const currentPoints = getUserLivePoints();

  // 检查积分是否足够
  if (currentPoints < gift.points) {
    showXToast(`积分不足，需要 ${gift.points}P`, "error");
    return;
  }

  // 更新选中状态
  giftMenuState.selectedGift = gift;

  // 更新UI
  document.querySelectorAll(".jukebox-ticket").forEach((ticket) => {
    ticket.classList.remove("selected");
  });
  const selectedTicket = document.querySelector(`[data-gift-id="${giftId}"]`);
  if (selectedTicket) {
    selectedTicket.classList.add("selected");
  }

  // 更新顶部编号窗口
  const codeDisplay = document.getElementById("selectedGiftCode");
  if (codeDisplay) {
    codeDisplay.textContent = gift.code;
  }

  // 更新底部播放条信息
  const footerInfo = document.getElementById("giftFooterInfo");
  const sendBtn = document.getElementById("giftSendBtn");

  if (footerInfo) {
    const priceDisplay =
      gift.points >= 1000
        ? (gift.points / 1000).toFixed(gift.points % 1000 === 0 ? 0 : 1) + "K"
        : gift.points;

    // 获取礼物图标
    let giftIconHTML = "";
    if (gift.useLocalImage && gift.imageLocal) {
      giftIconHTML = `<img src="${gift.imageLocal}" alt="${gift.name}" style="width:100%;height:100%;object-fit:contain;">`;
    } else if (gift.imageUrl) {
      giftIconHTML = `<img src="${gift.imageUrl}" alt="${gift.name}" style="width:100%;height:100%;object-fit:contain;">`;
    } else if (gift.icon) {
      giftIconHTML = gift.icon;
    } else {
      giftIconHTML =
        '<div style="width:24px;height:24px;background:rgba(255,255,255,0.1);border-radius:4px;"></div>';
    }

    footerInfo.innerHTML = `
      <div class="play-bar-selected">
        <div class="selected-icon-mini">
          ${giftIconHTML}
        </div>
        <div class="selected-info">
          <div class="selected-name">${gift.name}</div>
          <div class="selected-price">${priceDisplay}P</div>
        </div>
      </div>
    `;
  }

  if (sendBtn) {
    sendBtn.disabled = false;
    sendBtn.classList.add("ready");
  }
}

