// 🎵 浮动动画（VU表能量条风格）
function showFloatAnimation(giftData, giftIconHTML) {
  const liveRoom = document.querySelector(".live-room");
  if (!liveRoom) return;

  // 生成唯一ID避免冲突
  const uniqueId = `giftFloat_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  // 创建VU表能量条
  const vuBars = Array.from({ length: 12 }, (_, i) => {
    const height = 50 + Math.random() * 100;
    const delay = i * 0.05;
    return `<div class="vu-bar" style="--height: ${height}%; --delay: ${delay}s;"></div>`;
  }).join("");

  // 创建音符粒子
  const notes = Array.from({ length: 6 }, (_, i) => {
    const angle = i * 60 + (Math.random() * 20 - 10);
    const distance = 120 + Math.random() * 60;
    const scale = 0.6 + Math.random() * 0.4;
    return `<div class="music-note" style="--angle: ${angle}deg; --distance: ${distance}px; --scale: ${scale};">
      <div class="note-icon">${giftIconHTML}</div>
    </div>`;
  }).join("");

  // 创建扫描线
  const scanlines = Array.from(
    { length: 3 },
    (_, i) => `<div class="scan-line" style="--delay: ${i * 0.3}s;"></div>`
  ).join("");

  // PK目标标签（LCD风格）
  const pkTargetLine = giftData.target ? `
    <div class="lcd-line lcd-pk-target">
      <span class="lcd-label">TARGET</span>
      <span class="lcd-dots">••••</span>
      <span class="lcd-target">${giftData.target === "streamer" ? "▶STREAMER" : "▶USER"}</span>
    </div>
  ` : "";

  const animationHTML = `
    <div class="gift-animation-float" id="${uniqueId}">
      <!-- 背景扫描线 -->
      <div class="float-scanlines">${scanlines}</div>

      <!-- VU表能量条 -->
      <div class="vu-meter">
        ${vuBars}
      </div>

      <!-- 中心礼物显示 -->
      <div class="float-center">
        <div class="float-vinyl-spin">
          <div class="vinyl-grooves"></div>
          <div class="float-gift-icon">
            ${giftIconHTML}
          </div>
        </div>

        <!-- 音符粒子 -->
        <div class="music-notes">${notes}</div>
      </div>

      <!-- 信息显示板 -->
      <div class="float-info-panel">
        <div class="float-lcd-display">
          <div class="lcd-line">
            <span class="lcd-label">GIFT</span>
            <span class="lcd-dots">••••</span>
            <span class="lcd-name">${giftData.giftName}</span>
          </div>
          <div class="lcd-line">
            <span class="lcd-label">VALUE</span>
            <span class="lcd-dots">••••</span>
            <span class="lcd-value">+${giftData.giftPrice}P</span>
          </div>
          ${pkTargetLine}
          <div class="lcd-line lcd-sender">
            <img src="${giftData.userAvatar}" class="lcd-avatar">
            <span class="lcd-user">${giftData.userName}</span>
          </div>
        </div>
      </div>
    </div>
  `;

  liveRoom.insertAdjacentHTML("beforeend", animationHTML);
  injectFloatAnimationStyles();

  const container = document.getElementById(uniqueId);
  if (!container) return;

  setTimeout(() => container.classList.add("active"), 50);
  setTimeout(() => container.remove(), 3000);
}

// 💥 爆炸动画（像素冲击波风格）
function showExplosionAnimation(giftData, giftIconHTML) {
  const liveRoom = document.querySelector(".live-room");
  if (!liveRoom) return;

  // 生成唯一ID避免冲突
  const uniqueId = `giftExplosion_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  // 创建方形像素块（复古游戏风格）
  const pixels = Array.from({ length: 40 }, (_, i) => {
    const angle = i * 9 + Math.random() * 5;
    const distance = 100 + Math.random() * 120;
    const size = 6 + Math.random() * 8;
    const delay = Math.random() * 0.2;
    const rotation = Math.random() * 360;
    return `<div class="pixel-block" style="
      --angle: ${angle}deg;
      --distance: ${distance}px;
      --size: ${size}px;
      --delay: ${delay}s;
      --rotation: ${rotation}deg;
    "></div>`;
  }).join("");

  // 创建冲击波环
  const shockwaves = Array.from(
    { length: 3 },
    (_, i) =>
      `<div class="shockwave-ring" style="--delay: ${i * 0.15}s;"></div>`
  ).join("");

  // 创建碎片光束
  const beams = Array.from({ length: 8 }, (_, i) => {
    const angle = i * 45;
    return `<div class="explosion-beam" style="--angle: ${angle}deg;"></div>`;
  }).join("");

  // PK目标标签（磁带风格）
  const pkTargetStrip = giftData.target ? `
    <div class="explosion-target-strip">
      <div class="target-strip-label">TARGET:</div>
      <div class="target-strip-value">▶ ${giftData.target === "streamer" ? "STREAMER" : "USER"}</div>
      <div class="target-strip-holes">
        <span></span><span></span>
      </div>
    </div>
  ` : "";

  const animationHTML = `
    <div class="gift-animation-explosion" id="${uniqueId}">
      <!-- 冲击波环 -->
      <div class="shockwave-container">${shockwaves}</div>

      <!-- 爆炸中心 -->
      <div class="explosion-center">
        <!-- 光束 -->
        <div class="beam-container">${beams}</div>

        <!-- 礼物图标（破碎前） -->
        <div class="explosion-icon-wrapper">
          <div class="explosion-icon">
            ${giftIconHTML}
          </div>
          <div class="icon-flash"></div>
        </div>

        <!-- 像素块爆炸 -->
        <div class="pixel-explosion">${pixels}</div>
      </div>

      <!-- 爆炸信息显示（磁带标签风格） -->
      <div class="explosion-info-tape">
        <div class="tape-border-top"></div>
        <div class="explosion-info-content">
          <div class="explosion-header">
            <div class="explosion-code">${giftData.giftCode || "GIFT"}</div>
            <div class="explosion-separator"></div>
            <div class="explosion-status">RECEIVED</div>
          </div>
          <div class="explosion-name">${giftData.giftName}</div>
          <div class="explosion-value-bar">
            <div class="value-bar-fill" style="--width: ${Math.min(
              giftData.giftPrice / 100,
              100
            )}%;"></div>
            <div class="value-text">${giftData.giftPrice}P</div>
          </div>
          ${pkTargetStrip}
          <div class="explosion-user-strip">
            <img src="${giftData.userAvatar}" class="explosion-avatar">
            <span class="explosion-username">${giftData.userName}</span>
            <div class="user-strip-holes">
              <span></span><span></span><span></span>
            </div>
          </div>
        </div>
        <div class="tape-border-bottom"></div>
      </div>
    </div>
  `;

  liveRoom.insertAdjacentHTML("beforeend", animationHTML);
  injectExplosionAnimationStyles();

  const container = document.getElementById(uniqueId);
  if (!container) return;

  setTimeout(() => container.classList.add("active"), 50);
  setTimeout(() => container.remove(), 3000);
}

function openMyLiveRoom() {
  showXToast("直播间管理功能开发中...", "info");
}

