// 切换直播信息展开/收起
function toggleLiveInfo() {
  const content = document.getElementById("live-info-content");
  const arrow = document.getElementById("live-info-arrow");

  if (!content || !arrow) return;

  const isExpanded =
    content.style.maxHeight && content.style.maxHeight !== "0px";

  if (isExpanded) {
    content.style.maxHeight = "0";
    arrow.style.transform = "rotate(0deg)";
  } else {
    content.style.maxHeight = content.scrollHeight + "px";
    arrow.style.transform = "rotate(180deg)";
  }
}

// 切换直播详情展开/收起
function toggleLiveDetails() {
  const content = document.getElementById("detailsContent");
  const icon = document.getElementById("detailsExpandIcon");
  const container = content?.closest(".live-details");

  if (!content || !icon) return;

  const isExpanded = content.classList.contains("expanded");

  if (isExpanded) {
    // 收起动画
    const currentHeight = content.scrollHeight;
    content.style.maxHeight = currentHeight + "px";

    // 强制重绘
    content.offsetHeight;

    // 执行收起
    requestAnimationFrame(() => {
      content.style.maxHeight = "0px";
      content.classList.remove("expanded");
      icon.classList.remove("expanded");
    });

    // 收起完成后才移除父容器的 overflow: visible
    const onTransitionEnd = (e) => {
      if (
        e.propertyName === "max-height" &&
        !content.classList.contains("expanded")
      ) {
        if (container) container.classList.remove("details-expanded");
        content.removeEventListener("transitionend", onTransitionEnd);
      }
    };
    content.addEventListener("transitionend", onTransitionEnd);
  } else {
    // 展开开始前就设置父容器为 visible，避免动画过程中被裁剪
    if (container) container.classList.add("details-expanded");

    // 先添加 expanded class（触发 margin-top）
    content.classList.add("expanded");
    icon.classList.add("expanded");

    // 临时移除 overflow 和 max-height 限制以获取准确高度
    content.style.maxHeight = "none";
    content.style.overflow = "visible";

    const targetHeight = content.scrollHeight;

    // 恢复初始状态
    content.style.maxHeight = "0px";
    content.style.overflow = "hidden";

    // 触发动画
    requestAnimationFrame(() => {
      content.style.maxHeight = targetHeight + 20 + "px"; // 加20px余量确保完整显示
    });

    // 动画结束后移除固定高度限制，允许内容自适应
    const onTransitionEnd = (e) => {
      if (
        e.propertyName === "max-height" &&
        content.classList.contains("expanded")
      ) {
        content.style.maxHeight = "none";
        content.style.overflow = "visible";
        content.removeEventListener("transitionend", onTransitionEnd);
      }
    };
    content.addEventListener("transitionend", onTransitionEnd);
  }
}
window.toggleLiveDetails = toggleLiveDetails;

// 启动弹幕模拟
function startDanmakuSimulation() {
  const danmakuList = document.getElementById("danmakuList");
  if (!danmakuList) return;

  // 🆕 使用AI生成的弹幕数据
  const details = currentLiveRoomData?.details;
  if (!details || !details.danmaku || details.danmaku.length === 0) {
    console.warn("⚠️ [弹幕] 没有弹幕数据");
    return;
  }

  // 🎯 只播放最新批次的内容（排除用户发言，因为已经显示过了）
  const latestGenerationId = details.latestGenerationId;
  const danmakuData = details.danmaku.filter(
    (msg) => msg.generationId === latestGenerationId && msg.isUser !== true
  );

  if (danmakuData.length === 0) {
    console.warn(`⚠️ [弹幕] 没有批次ID为 ${latestGenerationId} 的弹幕`);
    return;
  }

  let messageIndex = 0;

  danmakuInterval = setInterval(() => {
    if (messageIndex >= danmakuData.length) {
      clearInterval(danmakuInterval);
      danmakuInterval = null;
      return;
    }

    const message = danmakuData[messageIndex];

    checkAndShowRelatedSuperChat(message.content, messageIndex);

    // 默认头像（将被头像修正函数处理）
    const avatar = "https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg";

    const danmakuItem = document.createElement("div");
    danmakuItem.style.cssText = `
        display: flex; 
        gap: 12px; 
        align-items: flex-start; 
        padding: 8px 0; 
        animation: fadeInUp 0.4s ease-out;
        position: relative;
      `;

    danmakuItem.innerHTML = `
        <img src="${avatar}" style="width: 34px; height: 34px; border-radius: 50%; border: 2px solid rgba(255, 255, 255, 0.15); flex-shrink: 0; box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3), inset 0 1px 1px rgba(255, 255, 255, 0.2); filter: brightness(0.95) contrast(1.05); background: #000;" alt="${message.userName}">
        <div style="flex: 1; min-width: 0; padding-top: 2px;">
          <div style="font-size: 10px; color: rgba(255, 255, 255, 0.5); font-weight: 800; margin-bottom: 4px; letter-spacing: 0.8px; text-transform: uppercase; font-family: 'Courier New', monospace;">${message.userName}</div>
          <div style="font-size: 12px; color: rgba(255, 255, 255, 0.85); line-height: 1.6; word-break: break-word; letter-spacing: 0.3px; font-family: 'Courier New', monospace;">${message.content}</div>
        </div>
        <div style="position: absolute; bottom: 0; left: 48px; right: 0; height: 1px; background: linear-gradient(90deg, rgba(255, 255, 255, 0.08), transparent);"></div>
      `;

    danmakuList.appendChild(danmakuItem);

    // 限制弹幕数量
    if (danmakuList.children.length > 5) {
      const firstItem = danmakuList.firstChild;
      firstItem.style.transition = "all 0.3s ease-out";
      firstItem.style.opacity = "0";
      firstItem.style.transform = "translateX(-20px)";
      setTimeout(() => {
        danmakuList.removeChild(firstItem);
      }, 300);
    }

    // 自动滚动到底部
    const container = document.getElementById("danmaku-container");
    if (container) {
      container.scrollTop = container.scrollHeight;
    }

    messageIndex++;
  }, 3000); // 每1.5秒一条弹幕，更快节奏
}

// 启动主播发言模拟
function startStreamerMessageSimulation() {
  // 🆕 使用AI生成的主播发言数据
  const details = currentLiveRoomData?.details;

  if (
    !details ||
    !details.streamerMessages ||
    details.streamerMessages.length === 0
  ) {
    console.warn("⚠️ [主播发言] 没有主播发言数据");
    return;
  }

  // 🎯 只播放最新批次的内容
  const latestGenerationId = details.latestGenerationId;
  const streamerMessages = details.streamerMessages.filter(
    (msg) => msg.generationId === latestGenerationId
  );

  if (streamerMessages.length === 0) {
    console.warn(`⚠️ [主播发言] 没有批次ID为 ${latestGenerationId} 的发言`);
    return;
  }

  let messageIndex = 0;

  function playNextMessage() {
    if (messageIndex >= streamerMessages.length) {
      streamerMessageInterval = null;
      return;
    }

    const message = streamerMessages[messageIndex];
    const isLastMessage = messageIndex === streamerMessages.length - 1;

    checkAndShowRelatedSuperChat(message.content, messageIndex);

    if (message.musicAction) {
      executeMusicAction(message.musicAction);
    }

    // 🚨 检测主播踢出用户 - 立即执行，不等文字滚动完成
    if (message.shouldKickUser === true && connectionState.isConnected) {
      console.log("🚨 [连线系统] 主播决定踢出用户");
      messageIndex++;
      showStreamerMessage(message.content, () => {
        // 文字滚动完成后继续播放下一条
        streamerMessageInterval = setTimeout(() => {
          playNextMessage();
        }, 2000);
      });

      // 立即执行踢出（不等文字滚动）
      setTimeout(() => {
        endConnection("kicked");
      }, 1500);
      return; // 直接返回，避免继续执行
    }

    // 🎙️ 检测主播开启连线 - 立即执行
    if (message.shouldEnableConnection === true) {
      if (!currentLiveRoomData?.details?.connectionSettings ||
          currentLiveRoomData.details.connectionSettings.enabled === false) {
        console.log("🎙️ [连线系统] 主播决定开启连线功能");
        messageIndex++;
        showStreamerMessage(message.content, () => {
          // 文字滚动完成后继续播放下一条
          streamerMessageInterval = setTimeout(() => {
            playNextMessage();
          }, 2000);
        });

        // 立即执行开启连线（不等文字滚动）
        setTimeout(() => {
          enableConnectionSystem();
        }, 1500);
        return; // 直接返回，避免继续执行
      }
    }

    messageIndex++;

    showStreamerMessage(message.content, () => {
      if (isLastMessage && message.shouldEndLive === true) {
        streamerMessageInterval = setTimeout(() => {
          closeLiveRoomWithEndMessage();
        }, 3000);
      } else {
        streamerMessageInterval = setTimeout(() => {
          playNextMessage();
        }, 2000);
      }
    });
  }

  setTimeout(() => {
    playNextMessage();
  }, 1000);
}

// 主播发言轮播管理
let currentSpeechIndex = 0;
let speechRotationInterval = null;
let speechCheckInterval = null; // 用于检测文字位置的定时器

// 🚨 直播间退出标志（用于阻止所有异步操作）
let isLiveRoomExiting = false;

// 显示主播发言（横向滚动 + 实时检测）
function showStreamerMessage(message, onComplete) {
  if (isLiveRoomExiting) {
    if (onComplete) onComplete();
    return;
  }

  if (!message || !message.trim()) {
    if (onComplete) onComplete();
    return;
  }

  const audioBars = document.getElementById("audioBars");
  const speechText = document.getElementById("streamerSpeech");
  const speechContent = document.getElementById("speechContent");
  const visualizer = speechText?.parentElement; // .audio-visualizer

  if (!audioBars || !speechText || !speechContent || !visualizer) {
    if (onComplete) onComplete();
    return;
  }

  // 清除之前的检测定时器和状态
  if (speechCheckInterval) {
    clearInterval(speechCheckInterval);
    speechCheckInterval = null;
  }

  // 清理之前的状态
  speechText.classList.remove("fading");
  speechText.style.opacity = "";
  speechText.style.transition = "";
  audioBars.classList.remove("dimmed");
  visualizer.classList.remove("speech-active");

  console.log(
    `🎤 [主播发言] "${message.substring(0, 30)}..." (${
      message.length
    }字, 实时检测模式)`
  );

  // 设置文本内容
  speechContent.textContent = message;
  speechContent.style.animation = "none"; // 重置动画

  // 确保初始状态（透明）
  speechText.style.opacity = "0";

  // 使用requestAnimationFrame确保浏览器先渲染初始状态，然后触发渐入动画
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      // 显示边缘渐变遮罩
      visualizer.classList.add("speech-active");

      // 显示文字，降低音波透明度并添加模糊效果
      audioBars.style.transition =
        "opacity 0.8s cubic-bezier(0.4, 0, 0.2, 1), filter 0.8s cubic-bezier(0.4, 0, 0.2, 1)";
      audioBars.style.opacity = "0.15";
      audioBars.classList.add("dimmed");

      // 触发渐入动画
      speechText.style.opacity = "1";
      speechText.style.transition = "opacity 0.8s cubic-bezier(0.4, 0, 0.2, 1)";
      speechText.classList.add("active");
    });
  });

  // 计算快速滚动时长：固定速度每秒600px
  const textWidth = speechContent.offsetWidth;
  const containerWidth = speechText.offsetWidth;
  const totalDistance = textWidth + containerWidth; // 需要滚动的总距离
  const speed = 100; // 每秒600px，快速滚动
  const calculatedDuration = totalDistance / speed;
  const scrollDuration = Math.min(calculatedDuration, 30);

  requestAnimationFrame(() => {
    speechContent.style.animation = `scrollSpeech ${scrollDuration}s linear forwards`;
  });

  // 实时检测文字是否完全离开可视区域
  let checkCount = 0;
  speechCheckInterval = setInterval(() => {
    checkCount++;

    // 读取当前 transform 的 translateX 值
    const style = window.getComputedStyle(speechContent);
    const transform = style.transform;

    // 解析 transform 矩阵获取 translateX
    let translateX = 0;
    if (transform && transform !== "none") {
      const matrixValues = transform.match(/matrix\(([^)]+)\)/);
      if (matrixValues && matrixValues[1]) {
        const values = matrixValues[1]
          .split(",")
          .map((v) => parseFloat(v.trim()));
        translateX = values[4] || 0; // matrix的第5个值是translateX
      }
    }

    // 检测：文字接近左边界时，提前触发渐出（更平滑）
    // translateX是负值，当文字还有50px就要滚出时开始渐出
    const isNearingEnd = translateX + textWidth < 50;
    const isFullyGone = translateX + textWidth < -200;

    if (isNearingEnd && !speechText.classList.contains("fading")) {
      speechText.classList.add("fading");

      // 移除active类停止呼吸动画
      speechText.classList.remove("active");

      // 同时开始恢复音波（2秒渐变）+ 移除模糊
      audioBars.style.transition =
        "opacity 2s cubic-bezier(0.4, 0, 0.2, 1), filter 2s cubic-bezier(0.4, 0, 0.2, 1)";
      audioBars.style.opacity = "1";
      audioBars.classList.remove("dimmed");

      // 移除边缘遮罩
      visualizer.classList.remove("speech-active");
    }

    if (isFullyGone && speechText.classList.contains("fading")) {
      speechContent.style.animation = "none";

      // 清除检测定时器
      clearInterval(speechCheckInterval);
      speechCheckInterval = null;

      // 等待0.5秒确保视觉上完全消失
      setTimeout(() => {
        // 清理状态
        speechText.classList.remove("fading");
        speechText.style.opacity = "";
        speechText.style.transition = "";
        audioBars.style.transition = ""; // 恢复默认

        if (onComplete) {
          onComplete();
        }
      }, 500);
    }
  }, 50); // 每50ms检测一次
}

