// 进度条更新定时器
let progressInterval = null;
let currentProgress = 0;

// 启动进度条更新
function startProgressUpdate() {
  const totalDuration = 5000; // 1h 23m = 4980s, 使用5000秒演示
  currentProgress = 0;

  progressInterval = setInterval(() => {
    currentProgress++;
    if (currentProgress > totalDuration) {
      currentProgress = 0;
    }

    const percentage = (currentProgress / totalDuration) * 100;
    const progressFill = document.getElementById("progressFill");
    if (progressFill) {
      progressFill.style.width = percentage + "%";
    }

    // 更新时间显示
    const hours = Math.floor(currentProgress / 3600);
    const minutes = Math.floor((currentProgress % 3600) / 60);
    const seconds = currentProgress % 60;
    const timeStr =
      hours > 0
        ? `${hours}:${minutes.toString().padStart(2, "0")}:${seconds
            .toString()
            .padStart(2, "0")}`
        : `${minutes}:${seconds.toString().padStart(2, "0")}`;

    const currentTime = document.getElementById("currentTime");
    if (currentTime) {
      currentTime.textContent = timeStr;
    }
  }, 1000);
}

