// 获取钱包余额（直接从数据库读取）
async function getWalletBalance() {
  try {
    const db = getXDB();
    const accountId = window.currentAccountId || "main";
    const walletId = `wallet_${accountId}`;
    const savedWallet = await db.xAccountProfiles.get(walletId);

    if (savedWallet && savedWallet.data) {
      return {
        balance: savedWallet.data.balance || 0,
        isActivated: savedWallet.data.isActivated || false,
        data: savedWallet.data,
      };
    }

    return { balance: 0, isActivated: false, data: null };
  } catch (error) {
    console.error("💰 [获取钱包余额] 失败:", error);
    return { balance: 0, isActivated: false, data: null };
  }
}

// 保存钱包余额（直接写入数据库）
async function saveWalletBalance(walletData) {
  try {
    const db = getXDB();
    const accountId = window.currentAccountId || "main";
    const walletId = `wallet_${accountId}`;

    await db.xAccountProfiles.put({
      handle: walletId,
      name: "wallet",
      accountId: accountId,
      data: walletData,
      updatedAt: new Date().toISOString(),
    });

    return true;
  } catch (error) {
    console.error("💰 [保存钱包余额] 失败:", error);
    return false;
  }
}

