// 关闭充值页面
function closePointsRecharge() {
  const container = document.getElementById("rechargeContainer");
  if (container) {
    const overlay = document.getElementById("rechargeOverlay");
    const panel = document.getElementById("rechargePanel");

    if (overlay) overlay.classList.remove("active");
    if (panel) {
      panel.style.transform = "translateX(-50%) translateY(100%)";
      panel.style.opacity = "0";
    }

    setTimeout(() => {
      container.remove();
    }, 400);
  }
}

// 切换充值方式
function switchRechargeTab(tabName) {
  // 更新Tab状态
  document.querySelectorAll(".cassette-tab").forEach((tab) => {
    tab.classList.remove("active");
    if (tab.dataset.tab === tabName) {
      tab.classList.add("active");
    }
  });

  // 切换内容区域
  const directContent = document.getElementById("directRechargeContent");
  const packageContent = document.getElementById("packageRechargeContent");

  if (tabName === "direct") {
    directContent.style.display = "block";
    packageContent.style.display = "none";
  } else {
    directContent.style.display = "none";
    packageContent.style.display = "block";
  }
}

// 计算直充积分
function calculateDirectPoints(amount) {
  const pointsResult = document.getElementById("directPointsResult");
  if (pointsResult) {
    const numAmount = parseFloat(amount) || 0;
    const points = Math.floor(numAmount / 10); // 10美元 = 1积分
    pointsResult.textContent = points.toLocaleString();
  }
}

// 执行直充
async function executeDirectRecharge() {
  const amountInput = document.getElementById("directRechargeAmount");
  const amount = parseFloat(amountInput?.value) || 0;

  // 验证金额
  if (amount < 10) {
    showXToast("充值金额最低为10美元", "error");
    return;
  }

  if (amount % 10 !== 0) {
    showXToast("充值金额必须是10的倍数", "error");
    return;
  }

  const walletInfo = await getWalletBalance();

  if (!walletInfo.isActivated) {
    showXToast("请先激活钱包", "error");
    return;
  }

  if (walletInfo.balance < amount) {
    showXToast("钱包余额不足", "error");
    showInsufficientBalance();
    return;
  }

  // 计算积分
  const points = Math.floor(amount / 10);

  // 确认对话框
  if (!confirm(`确认充值 $${amount.toFixed(2)} 换取 ${points} 积分？`)) {
    return;
  }

  try {
    // 🎭 记录充值历史（用于彩蛋检测）
    recordRecharge(amount, points);

    // 🎭 检查是否触发彩蛋
    let finalPoints = points;
    let easterEggTriggered = false;
    let easterEggMessage = null;

    if (shouldTriggerEasterEgg(amount, points)) {
      const eggResult = triggerEasterEgg(amount, points);
      finalPoints = eggResult.finalPoints;
      easterEggMessage = eggResult.message;
      easterEggTriggered = true;
    }

    // 扣除钱包余额
    walletInfo.data.balance -= amount;

    // 添加钱包交易记录
    const transaction = {
      id: "points_recharge_" + Date.now(),
      description: `直播积分充值 - ${finalPoints}积分${
        easterEggTriggered
          ? finalPoints > points
            ? " (幸运加成)"
            : " (系统扣费)"
          : ""
      }`,
      amount: -amount,
      timestamp: new Date().toISOString(),
      type: "points_recharge",
    };

    if (!walletInfo.data.transactions) {
      walletInfo.data.transactions = [];
    }
    walletInfo.data.transactions.unshift(transaction);

    // 保存钱包数据到数据库
    await saveWalletBalance(walletInfo.data);

    // 增加积分（使用彩蛋修正后的积分）
    const currentPoints = getUserLivePoints();
    const newPoints = currentPoints + finalPoints;
    saveUserLivePoints(newPoints);

    // 🎭 如果触发彩蛋，显示彩蛋弹窗（延迟500ms以获得更好的体验）
    if (easterEggTriggered && easterEggMessage) {
      setTimeout(() => {
        showEasterEggModal(easterEggMessage);
      }, 500);
    }

    // 显示手机通知
    if (typeof showPhoneNotification === "function") {
      showPhoneNotification({
        title: "X Wallet",
        message: `充值成功！获得 ${finalPoints} 积分，当前余额 $${walletInfo.data.balance.toFixed(
          2
        )}`,
        avatar: window.userProfileData?.avatar,
        leftIcon: "x",
      });
    }

    // 更新UI
    updateRechargeUI(newPoints, walletInfo.data.balance);

    // 清空输入框
    if (amountInput) amountInput.value = "";
    const pointsResult = document.getElementById("directPointsResult");
    if (pointsResult) pointsResult.textContent = "0";

    console.log(
      `✅ [充值] 直充成功: $${amount} → ${finalPoints}积分${
        easterEggTriggered ? " 🎭彩蛋触发" : ""
      }`
    );
  } catch (error) {
    console.error("充值失败:", error);
    showXToast("充值失败，请重试", "error");
  }
}

// 执行套餐充值
async function executePackageRecharge(packageId) {
  const pkg = rechargePackages.find((p) => p.id === packageId);
  if (!pkg) return;

  // 检查钱包余额（直接从数据库读取）
  const walletInfo = await getWalletBalance();

  console.log(
    `💰 [套餐充值] 钱包余额: $${walletInfo.balance}, 需要: $${pkg.amount}`
  );

  if (!walletInfo.isActivated) {
    showXToast("请先激活钱包", "error");
    return;
  }

  if (walletInfo.balance < pkg.amount) {
    showXToast("钱包余额不足", "error");
    showInsufficientBalance();
    return;
  }

  // 确认对话框
  if (
    !confirm(
      `确认购买「${
        pkg.title
      }」套餐？\n支付 $${pkg.amount.toLocaleString()} 获得 ${pkg.points.toLocaleString()} 积分（含${
        pkg.bonus
      }赠送）`
    )
  ) {
    return;
  }

  try {
    // 🎭 记录充值历史（用于彩蛋检测）
    recordRecharge(pkg.amount, pkg.points);

    // 🎭 检查是否触发彩蛋
    let finalPoints = pkg.points;
    let easterEggTriggered = false;
    let easterEggMessage = null;

    if (shouldTriggerEasterEgg(pkg.amount, pkg.points)) {
      const eggResult = triggerEasterEgg(pkg.amount, pkg.points);
      finalPoints = eggResult.finalPoints;
      easterEggMessage = eggResult.message;
      easterEggTriggered = true;
    }

    // 扣除钱包余额
    walletInfo.data.balance -= pkg.amount;

    // 添加钱包交易记录
    const transaction = {
      id: "points_package_" + Date.now(),
      description: `直播积分套餐充值 - ${pkg.title}${
        easterEggTriggered
          ? finalPoints > pkg.points
            ? " (幸运加成)"
            : " (系统扣费)"
          : ""
      }`,
      amount: -pkg.amount,
      timestamp: new Date().toISOString(),
      type: "points_recharge",
    };

    if (!walletInfo.data.transactions) {
      walletInfo.data.transactions = [];
    }
    walletInfo.data.transactions.unshift(transaction);

    // 保存钱包数据到数据库
    await saveWalletBalance(walletInfo.data);

    // 增加积分（使用彩蛋修正后的积分）
    const currentPoints = getUserLivePoints();
    const newPoints = currentPoints + finalPoints;
    saveUserLivePoints(newPoints);

    // 🎭 如果触发彩蛋，显示彩蛋弹窗（延迟500ms以获得更好的体验）
    if (easterEggTriggered && easterEggMessage) {
      setTimeout(() => {
        showEasterEggModal(easterEggMessage);
      }, 500);
    }

    // 显示手机通知
    if (typeof showPhoneNotification === "function") {
      const bonusText =
        !easterEggTriggered && pkg.bonus ? `（含${pkg.bonus}赠送）` : "";
      showPhoneNotification({
        title: "X Wallet",
        message: `套餐购买成功！获得 ${finalPoints.toLocaleString()} 积分${bonusText}，余额 $${walletInfo.data.balance.toFixed(
          2
        )}`,
        avatar: window.userProfileData?.avatar,
        leftIcon: "x",
      });
    }

    updateRechargeUI(newPoints, walletInfo.data.balance);

    console.log(
      `✅ [充值] 套餐购买成功: $${pkg.amount} → ${finalPoints}积分${
        easterEggTriggered ? " 🎭彩蛋触发" : ""
      }`
    );
  } catch (error) {
    console.error("套餐充值失败:", error);
    showXToast("充值失败，请重试", "error");
  }
}

// 更新充值页面UI
function updateRechargeUI(newPoints, newBalance) {
  // 更新充值页面的积分和余额显示
  const pointsDisplay = document.getElementById("rechargeCurrentPoints");
  const balanceDisplay = document.getElementById("rechargeWalletBalance");

  if (pointsDisplay) {
    pointsDisplay.textContent = newPoints.toLocaleString();
  }

  if (balanceDisplay) {
    balanceDisplay.textContent = `$${newBalance.toFixed(2)}`;
  }

  // 更新礼物菜单的积分显示
  const giftPointsValue = document.getElementById("giftPointsValue");
  if (giftPointsValue) {
    giftPointsValue.textContent = newPoints.toLocaleString();
  }

  // 更新套餐卡片的可购买状态
  document.querySelectorAll(".package-card").forEach((card) => {
    const packageAmount =
      parseFloat(
        card.querySelector(".package-amount")?.textContent.replace(/[$,]/g, "")
      ) || 0;

    if (newBalance >= packageAmount) {
      card.classList.remove("insufficient");
      const mask = card.querySelector(".package-insufficient-mask");
      if (mask) mask.remove();
    } else {
      card.classList.add("insufficient");
      if (!card.querySelector(".package-insufficient-mask")) {
        const mask = document.createElement("div");
        mask.className = "package-insufficient-mask";
        mask.textContent = "余额不足";
        card.appendChild(mask);
      }
    }
  });
}

// 显示余额不足提示
function showInsufficientBalance() {
  showXToast("钱包余额不足，请先充值钱包", "error");
}

