// 粉丝团会员管理系统
// ============================================

// 获取北京时间的日期字符串（YYYY-MM-DD格式）
function getBeijingDateString() {
  const now = new Date();
  const beijingTime = new Date(
    now.getTime() + 8 * 60 * 60 * 1000 + now.getTimezoneOffset() * 60 * 1000
  );
  const year = beijingTime.getFullYear();
  const month = String(beijingTime.getMonth() + 1).padStart(2, "0");
  const day = String(beijingTime.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

// 加入粉丝团
async function joinFanClub(streamerHandle) {
  try {
    const xDb = getXDB();
    const today = getBeijingDateString();

    // 🔑 统一清理句柄格式
    const cleanHandle = HandleUtils.clean(streamerHandle);
    console.log(`🎊 [会员系统] 加入粉丝团: ${cleanHandle}`);

    // 创建会员记录（初始等级根据积分计算）
    const initialPoints = 0;
    const initialLevel = await calculateLevel(initialPoints, cleanHandle);

    const membership = {
      streamerHandle: cleanHandle, // 使用清理后的句柄作为主键
      joined: true,
      joinedAt: new Date().toISOString(),
      checkinDays: 0,
      lastCheckinDate: null,
      points: initialPoints,
      level: initialLevel,
      checkinHistory: [],
    };

    await xDb.xFanClubMemberships.put(membership);
    console.log(`✅ [会员系统] 会员数据已保存 (初始等级: LV${initialLevel})`);

    // 触发欢迎留言
    try {
      const fanClubRecord = await xDb.xFanClubs.get(cleanHandle);
      if (
        fanClubRecord &&
        fanClubRecord.data &&
        fanClubRecord.data.messages &&
        fanClubRecord.data.messages.welcome
      ) {
        showFanClubNotification(fanClubRecord.data.messages.welcome, "welcome");
      }
    } catch (err) {
      console.warn(`⚠️ [会员系统] 获取欢迎留言失败:`, err);
    }

    // 刷新UI
    await refreshMembershipUI(cleanHandle);
    showXToast("欢迎加入粉丝团！", "success");

    return membership;
  } catch (error) {
    console.error("❌ [会员系统] 加入失败:", error);
    showXToast(`加入失败: ${error.message}`, "error");
    throw error;
  }
}

// 签到
async function checkinFanClub(streamerHandle) {
  try {
    const xDb = getXDB();
    const today = getBeijingDateString();
    const cleanHandle = HandleUtils.clean(streamerHandle);

    // 获取会员数据
    const membership = await xDb.xFanClubMemberships.get(cleanHandle);
    if (!membership || !membership.joined) {
      throw new Error("您还未加入粉丝团");
    }

    // 检查今日是否已签到
    if (membership.lastCheckinDate === today) {
      showXToast("今日已签到过了", "info");
      return membership;
    }

    // 判断是否连续签到
    const yesterday = getYesterdayDateString(today);
    const isConsecutive = membership.lastCheckinDate === yesterday;

    // 更新签到数据
    const newCheckinDays = isConsecutive ? membership.checkinDays + 1 : 1;
    const newPoints = membership.points + 10;

    membership.checkinDays = newCheckinDays;
    membership.lastCheckinDate = today;
    membership.points = newPoints;
    membership.checkinHistory = [...(membership.checkinHistory || []), today];

    // 检查等级变化
    const oldLevel = membership.level;
    const newLevel = await calculateLevel(newPoints, cleanHandle);
    const levelChanged = newLevel > oldLevel;

    if (levelChanged) {
      membership.level = newLevel;
      console.log(`🎉 [会员系统] 等级提升: LV${oldLevel} -> LV${newLevel}`);
    }

    // 保存更新
    await xDb.xFanClubMemberships.put(membership);

    // 触发签到留言（随机选择）
    try {
      const fanClubRecord = await xDb.xFanClubs.get(cleanHandle);
      if (
        fanClubRecord &&
        fanClubRecord.data &&
        fanClubRecord.data.messages &&
        fanClubRecord.data.messages.checkin
      ) {
        const checkinMessages = fanClubRecord.data.messages.checkin;
        const randomMessage =
          checkinMessages[Math.floor(Math.random() * checkinMessages.length)];
        showFanClubNotification(randomMessage, "checkin");
      }
    } catch (err) {
      console.warn(`⚠️ [会员系统] 获取签到留言失败:`, err);
    }

    // 如果等级提升，触发升级留言
    if (levelChanged) {
      setTimeout(async () => {
        try {
          const xDb = getXDB();
          const fanClubRecord = await xDb.xFanClubs.get(cleanHandle);
          if (
            fanClubRecord &&
            fanClubRecord.data &&
            fanClubRecord.data.levelSystem &&
            fanClubRecord.data.messages
          ) {
            const levelData = fanClubRecord.data.levelSystem.find(
              (l) => l.level === newLevel
            );
            if (levelData && fanClubRecord.data.messages.levelUp) {
              // 🎯 根据等级选择合适的留言
              let messagePool = fanClubRecord.data.messages.levelUp;

              // 如果levelUp是数组（合并后的格式），根据等级选择对应部分
              if (Array.isArray(messagePool)) {
                if (newLevel <= 7 && messagePool.length >= 3) {
                  // 低等级：使用前3条
                  messagePool = messagePool.slice(0, 3);
                } else if (newLevel <= 14 && messagePool.length >= 6) {
                  // 中等级：使用中间3条
                  messagePool = messagePool.slice(3, 6);
                } else if (messagePool.length >= 9) {
                  // 高等级：使用后3条
                  messagePool = messagePool.slice(6, 9);
                }

                // 从池中随机选择一条
                const randomIndex = Math.floor(
                  Math.random() * messagePool.length
                );
                var selectedMessage = messagePool[randomIndex];
              } else {
                // 如果是字符串（旧格式），直接使用
                var selectedMessage = messagePool;
              }

              // 替换占位符
              const levelUpMessage = selectedMessage
                .replace("{level}", newLevel)
                .replace("{levelName}", levelData.levelName);

              showFanClubNotification(levelUpMessage, "levelup");
            }
          }
        } catch (err) {
          console.warn(`⚠️ [会员系统] 获取升级留言失败:`, err);
        }
      }, 2000); // 延迟2秒显示升级留言
    }

    // 刷新UI并触发动画
    await refreshMembershipUIWithAnimation(cleanHandle, {
      checkinSuccess: true,
      pointsAdded: 10,
      checkinDaysChanged: true,
      oldCheckinDays: membership.checkinDays - 1,
      newCheckinDays: membership.checkinDays,
    });
    showXToast(`签到成功！连续${newCheckinDays}天，获得10积分`, "success");

    return membership;
  } catch (error) {
    console.error("❌ [会员系统] 签到失败:", error);
    showXToast(`签到失败: ${error.message}`, "error");
    throw error;
  }
}

// 增加积分（刷礼物时调用）
async function addFanClubPoints(streamerHandle, points) {
  try {
    const xDb =
      typeof getXDB === "function"
        ? getXDB()
        : typeof window.getXDB === "function"
        ? window.getXDB()
        : null;
    if (!xDb) {
      console.error("❌ [会员系统] 无法获取数据库实例");
      return null;
    }
    const cleanHandle = HandleUtils.clean(streamerHandle);
    const membership = await xDb.xFanClubMemberships.get(cleanHandle);

    if (!membership || !membership.joined) {
      console.error("❌ [会员系统] 用户未加入粉丝团");
      return null;
    }

    const oldLevel = membership.level;
    const newPoints = membership.points + points;
    const newLevel = await calculateLevel(newPoints, cleanHandle);
    const levelChanged = newLevel > oldLevel;

    membership.points = newPoints;
    membership.level = newLevel;
    await xDb.xFanClubMemberships.put(membership);

    if (levelChanged) {
      console.log(`🎉 [会员系统] 等级提升: LV${oldLevel} -> LV${newLevel}`);
    }

    // 如果等级提升，触发升级留言
    if (levelChanged) {
      try {
        const fanClubRecord = await xDb.xFanClubs.get(cleanHandle);
        if (
          fanClubRecord &&
          fanClubRecord.data &&
          fanClubRecord.data.levelSystem &&
          fanClubRecord.data.messages
        ) {
          const levelData = fanClubRecord.data.levelSystem.find(
            (l) => l.level === newLevel
          );
          if (levelData && fanClubRecord.data.messages.levelUp) {
            // 🎯 根据等级选择合适的留言
            let messagePool = fanClubRecord.data.messages.levelUp;

            // 如果levelUp是数组（合并后的格式），根据等级选择对应部分
            if (Array.isArray(messagePool)) {
              if (newLevel <= 7 && messagePool.length >= 3) {
                // 低等级：使用前3条
                messagePool = messagePool.slice(0, 3);
              } else if (newLevel <= 14 && messagePool.length >= 6) {
                // 中等级：使用中间3条
                messagePool = messagePool.slice(3, 6);
              } else if (messagePool.length >= 9) {
                // 高等级：使用后3条
                messagePool = messagePool.slice(6, 9);
              }

              // 从池中随机选择一条
              const randomIndex = Math.floor(
                Math.random() * messagePool.length
              );
              var selectedMessage = messagePool[randomIndex];
            } else {
              // 如果是字符串（旧格式），直接使用
              var selectedMessage = messagePool;
            }

            // 替换占位符
            const levelUpMessage = selectedMessage
              .replace("{level}", newLevel)
              .replace("{levelName}", levelData.levelName);

            showFanClubNotification(levelUpMessage, "levelup");
          }
        }
      } catch (err) {
        console.warn(`⚠️ [会员系统] 获取升级留言失败:`, err);
      }

      // 🎤 检测是否触发主播私联（粉丝团等级达标）
      try {
        const fanClubRecord = await xDb.xFanClubs.get(cleanHandle);
        const levelData = fanClubRecord?.data?.levelSystem?.find(
          (l) => l.level === newLevel
        );

        if (typeof checkStreamerContactTrigger === "function") {
          const userData = {
            fanClubLevel: newLevel,
            fanClubLevelName: levelData?.levelName || "",
            fanClubPoints: membership.points,
            giftHistory: [], // 后续可以从其他地方获取
            danmakuHistory: [], // 后续可以从其他地方获取
          };

          // 异步调用，不阻塞主流程
          checkStreamerContactTrigger(cleanHandle, "fanClub", userData).catch(
            (err) => {
              console.error("❌ [主播私联检测] 失败:", err);
            }
          );
        }
      } catch (err) {
        console.error("❌ [主播私联检测] 异常:", err);
      }
    }

    // 刷新UI（如果粉丝团面板打开）
    if (fanClubState.isOpen) {
      await refreshMembershipUIWithAnimation(cleanHandle, {
        pointsAdded: points,
        checkinSuccess: false,
        checkinDaysChanged: false,
      });
    }

    return membership;
  } catch (error) {
    console.error("❌ [会员系统] 增加积分失败:", error);
    throw error;
  }
}

// 根据积分计算等级
async function calculateLevel(points, streamerHandle) {
  try {
    const xDb = getXDB();
    const cleanHandle = HandleUtils.clean(streamerHandle);
    const fanClubRecord = await xDb.xFanClubs.get(cleanHandle);

    if (
      !fanClubRecord ||
      !fanClubRecord.data ||
      !fanClubRecord.data.levelSystem
    ) {
      console.warn(`⚠️ [等级计算] 粉丝团数据不存在: ${cleanHandle}`);
      return 0;
    }

    const levels = fanClubRecord.data.levelSystem;
    let currentLevel = 0;

    // 从高到低遍历，找到第一个满足条件的等级
    for (let i = levels.length - 1; i >= 0; i--) {
      const levelData = levels[i];
      const requiredPoints =
        levelData.requiredPoints ||
        extractPointsFromRequirement(levelData.requirement);

      if (points >= requiredPoints) {
        currentLevel = levelData.level;
        break;
      }
    }

    return currentLevel;
  } catch (error) {
    console.error(`❌ [等级计算] 计算失败:`, error);
    return 0;
  }
}

// 从达成条件文本中提取积分数字（兼容旧数据）
function extractPointsFromRequirement(requirement) {
  if (!requirement) return 0;
  const match = requirement.match(/(\d+)/);
  const points = match ? parseInt(match[1]) : 0;

  if (points === 0) {
    console.warn(`⚠️ [积分提取] 无法从 "${requirement}" 提取积分`);
  }

  return points;
}

// 获取昨天的日期字符串
function getYesterdayDateString(todayStr) {
  const today = new Date(todayStr);
  const yesterday = new Date(today.getTime() - 24 * 60 * 60 * 1000);
  const year = yesterday.getFullYear();
  const month = String(yesterday.getMonth() + 1).padStart(2, "0");
  const day = String(yesterday.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

// 刷新会员UI状态
async function refreshMembershipUI(streamerHandle) {
  if (!fanClubState.isOpen) return;

  try {
    const xDb = getXDB();

    // 🔑 统一清理句柄格式（streamerHandle可能已经是清理后的）
    const cleanHandle = HandleUtils.clean(streamerHandle);
    console.log(`🔄 [会员UI刷新] 查询handle: "${cleanHandle}"`);

    const membership = await xDb.xFanClubMemberships.get(cleanHandle);
    console.log(`🔄 [会员UI刷新] 会员状态:`, membership ? `已加入` : "未加入");

    const interactionArea = document.getElementById("fanClubInteractionArea");
    if (!interactionArea) return;

    if (!membership || !membership.joined) {
      // 未加入状态
      interactionArea.innerHTML = renderJoinSection();
    } else {
      // 已加入状态
      interactionArea.innerHTML = renderMemberSection(membership);
    }
  } catch (error) {
    console.error("❌ [会员系统] UI刷新失败:", error);
  }
}

// 带动画的UI刷新（签到、积分增加时调用）
async function refreshMembershipUIWithAnimation(
  streamerHandle,
  animConfig = {}
) {
  if (!fanClubState.isOpen) return;

  try {
    const xDb = getXDB();
    const membership = await xDb.xFanClubMemberships.get(streamerHandle);
    const interactionArea = document.getElementById("fanClubInteractionArea");

    if (!interactionArea || !membership || !membership.joined) {
      await refreshMembershipUI(streamerHandle);
      return;
    }

    // 先刷新内容
    interactionArea.innerHTML = renderMemberSection(membership);

    // 等待DOM渲染
    await new Promise((resolve) => setTimeout(resolve, 50));

    // 触发动画
    if (animConfig.checkinSuccess) {
      // 1. LED指示灯闪烁
      const led = document.querySelector(".checkin-panel .label-led");
      if (led) {
        led.classList.add("flash-success");
        setTimeout(() => led.classList.remove("flash-success"), 600);
      }

      // 2. 打卡按钮发光
      const punchBtn = document.querySelector(".punch-btn");
      if (punchBtn) {
        punchBtn.classList.add("success-glow");
        setTimeout(() => punchBtn.classList.remove("success-glow"), 800);
      }

      // 3. 浮动积分文字（签到时显示在按钮上）
      if (punchBtn && animConfig.pointsAdded) {
        const floatingText = document.createElement("div");
        floatingText.className = "floating-points";
        floatingText.textContent = `+${animConfig.pointsAdded}`;
        punchBtn.appendChild(floatingText);
        setTimeout(() => floatingText.remove(), 1200);
      }
    } else if (animConfig.pointsAdded && !animConfig.checkinSuccess) {
      // 4. 送礼物时的浮动积分（显示在LED显示屏上方）
      const ledDisplay = document.querySelector(".led-display");
      if (ledDisplay) {
        const floatingText = document.createElement("div");
        floatingText.className = "floating-points";
        floatingText.textContent = `+${animConfig.pointsAdded}`;
        floatingText.style.top = "-10px"; // 相对于LED显示屏上方
        ledDisplay.style.position = "relative";
        ledDisplay.appendChild(floatingText);
        setTimeout(() => floatingText.remove(), 1200);
      }
    }

    if (animConfig.checkinDaysChanged) {
      // 4. 翻牌计数器动画
      const flipCards = document.querySelectorAll(".flip-card");
      flipCards.forEach((card, index) => {
        setTimeout(() => {
          card.classList.add("flipping");
          setTimeout(() => card.classList.remove("flipping"), 600);
        }, index * 100);
      });
    }

    if (animConfig.pointsAdded) {
      // 5. LED数字滚动和发光
      const ledDigits = document.querySelector(".led-digits");
      if (ledDigits) {
        ledDigits.classList.add("counting", "glow-boost");
        setTimeout(() => {
          ledDigits.classList.remove("counting");
        }, 800);
        setTimeout(() => {
          ledDigits.classList.remove("glow-boost");
        }, 600);
      }

      // 6. VU表指针冲击
      const vuNeedle = document.querySelector(".vu-needle");
      if (vuNeedle) {
        vuNeedle.classList.add("impact");
        setTimeout(() => vuNeedle.classList.remove("impact"), 1000);
      }
    }
  } catch (error) {
    console.error("❌ [会员系统] 动画UI刷新失败:", error);
    await refreshMembershipUI(streamerHandle);
  }
}

