// 获取下一级等级数据
function getNextLevelData(currentLevel) {
  if (!fanClubState.currentData || !fanClubState.currentData.levelSystem)
    return null;
  const nextLevel = fanClubState.currentData.levelSystem.find(
    (l) => l.level === currentLevel + 1
  );
  if (nextLevel && !nextLevel.requiredPoints) {
    nextLevel.requiredPoints = extractPointsFromRequirement(
      nextLevel.requirement
    );
  }
  return nextLevel;
}

