// 暴露粉丝团函数到全局
window.openFanClub = openFanClub;
window.closeFanClub = closeFanClub;
window.addFanClubPoints = addFanClubPoints; // 供外部调用（刷礼物时）

// ============================================
// 主播主动私联功能
// ============================================

// 存储已生成的主播私联消息（避免重复调用API）
window.streamerContactMessageCache = window.streamerContactMessageCache || {};

// 存储用户拒绝记录
window.streamerContactRejections = window.streamerContactRejections || {};

/**
 * 检测是否应触发主播私联
 * @param {string} streamerHandle - 主播句柄
 * @param {string} trigger - 触发类型 "giftRank" | "fanClub"
 * @param {Object} userData - 用户数据
 */
async function checkStreamerContactTrigger(streamerHandle, trigger, userData) {
  try {
    console.log("🎤 [主播私联] 检测触发条件", {
      streamerHandle,
      trigger,
      userData,
    });

    // 检查是否已有待处理的私联（避免重复弹窗）
    const cacheKey = `${streamerHandle}_${trigger}`;
    if (window.streamerContactMessageCache[cacheKey]) {
      console.log("⚠️ [主播私联] 已有待处理的私联消息，跳过");
      return;
    }

    const xDb =
      typeof getXDB === "function"
        ? getXDB()
        : typeof window.getXDB === "function"
        ? window.getXDB()
        : null;

    if (!xDb) {
      console.error("❌ [主播私联] 无法获取数据库实例");
      return;
    }

    // 清理主播句柄（后续多处使用）
    const cleanHandle = HandleUtils.clean(streamerHandle);

    // ⚠️ 检查主播是否已经是联系人或已绑定角色
    // 如果是，则跳过触发（因为已经可以随意私信）

    // 1. 检查是否是已绑定角色
    const settingsId = `xSettings_${currentAccountId || "main"}`;
    const xSettings = await xDb.xSettings.get(settingsId);
    const boundCharacters = xSettings?.boundCharacters || [];

    if (boundCharacters.length > 0) {
      // 获取Tavern数据库中的角色信息
      const db =
        typeof getDB === "function"
          ? getDB()
          : typeof window.getDB === "function"
          ? window.getDB()
          : null;

      if (db) {
        const allChats = await db.chats.toArray();
        const bindedChars = allChats.filter(
          (chat) => !chat.isGroup && boundCharacters.includes(chat.id)
        );

        // 检查主播handle是否匹配已绑定角色的X账户
        for (const char of bindedChars) {
          const xProfile = await xDb.xCharacterProfiles.get(char.id);
          if (xProfile && xProfile.xHandle) {
            const charHandle = HandleUtils.clean(xProfile.xHandle);
            if (charHandle === cleanHandle) {
              console.log(
                "✅ [主播私联] 主播是已绑定角色，跳过私联（已可随意私信）"
              );
              return;
            }
          }
        }
      }
    }

    // 2. 检查是否已在联系人列表（私信列表）
    const messagesListId = `messagesList_${currentAccountId || "main"}`;
    const messagesListData = await xDb.xAccountProfiles.get(messagesListId);
    const messagesList = messagesListData?.data || [];

    const isInContactList = messagesList.some(
      (contact) => HandleUtils.clean(contact.userHandle) === cleanHandle
    );

    if (isInContactList) {
      console.log("✅ [主播私联] 主播已在联系人列表，跳过私联（已可随意私信）");
      return;
    }

    console.log("🆕 [主播私联] 主播是陌生人/随机主播，可以触发私联");

    // 获取主播配置
    let shouldContact = false;
    let thresholdMet = false;
    let persistAfterRejection = false;
    let triggerDetails = {};

    if (trigger === "giftRank") {
      // 礼物榜触发 - 从当前直播间数据获取配置
      if (!currentLiveRoomData || !currentLiveRoomData.details) {
        console.error("❌ [主播私联] 无法获取当前直播间数据");
        return;
      }

      const liveRoomData = currentLiveRoomData.details;
      if (!liveRoomData || !liveRoomData.giftRankContactConfig) {
        console.log("⚠️ [主播私联] 主播未配置礼物榜私联");
        return;
      }

      const config = liveRoomData.giftRankContactConfig;
      shouldContact = config.willContactPrivately;
      persistAfterRejection = config.persistAfterRejection;

      // 检查用户是否在礼物榜门槛内
      const userRank = userData.giftRank || 999;
      thresholdMet = userRank <= config.contactRankThreshold;

      triggerDetails = {
        rank: userRank,
        totalPoints: userData.totalGiftPoints || 0,
        giftHistory: userData.giftHistory || [],
        fanClubData: userData.fanClubData || null,
        danmakuHistory: userData.danmakuHistory || [],
      };

      console.log(
        `🎁 [礼物榜私联] 配置: willContact=${shouldContact}, threshold=${config.contactRankThreshold}, userRank=${userRank}, met=${thresholdMet}`
      );
    } else if (trigger === "fanClub") {
      // 粉丝团触发 - 需要清理句柄（去掉@符号）
      const fanClubData = await xDb.xFanClubs.get(cleanHandle);
      if (
        !fanClubData ||
        !fanClubData.data ||
        !fanClubData.data.fanClubContactConfig
      ) {
        console.log("⚠️ [主播私联] 主播未配置粉丝团私联");
        return;
      }

      const config = fanClubData.data.fanClubContactConfig;
      shouldContact = config.willContactPrivately;
      persistAfterRejection = config.persistAfterRejection;

      // 检查用户粉丝团等级是否达到门槛
      const userLevel = userData.fanClubLevel || 0;
      thresholdMet = userLevel >= config.contactLevelThreshold;

      triggerDetails = {
        level: userLevel,
        levelName: userData.fanClubLevelName || "",
        totalPoints: userData.fanClubPoints || 0,
        giftHistory: userData.giftHistory || [],
        fanClubData: {
          joined: true,
          level: userLevel,
          points: userData.fanClubPoints || 0,
        },
        danmakuHistory: userData.danmakuHistory || [],
      };

      console.log(
        `🌟 [粉丝团私联] 配置: willContact=${shouldContact}, threshold=${config.contactLevelThreshold}, userLevel=${userLevel}, met=${thresholdMet}`
      );
    }

    // 判断是否应该触发
    if (!shouldContact || !thresholdMet) {
      console.log("❌ [主播私联] 未满足触发条件");
      return;
    }

    // 检查历史记录（已接受/已拒绝）
    const historyKey = `streamerContactHistory_${cleanHandle}`;
    const historyRecord = await xDb.xAccountProfiles.get(historyKey);

    if (historyRecord && historyRecord.data && historyRecord.data[trigger]) {
      const history = historyRecord.data[trigger];

      // 如果已经接受过，不再触发
      if (history.accepted) {
        console.log("✅ [主播私联] 用户已接受过此主播的私联，跳过");
        return;
      }

      // 如果已经拒绝过，根据配置决定是否继续
      if (history.rejected && !persistAfterRejection) {
        console.log("⚠️ [主播私联] 用户之前拒绝过，且主播不会持续私联");
        return;
      }
    }

    // 触发条件满足！生成私信内容
    console.log("✅ [主播私联] 触发条件满足，开始生成私信");
    await generateStreamerContactMessage(
      streamerHandle,
      trigger,
      triggerDetails,
      userData
    );
  } catch (error) {
    console.error("❌ [主播私联] 检测失败:", error);
  }
}

/**
 * 生成主播私联消息（调用第9情景）
 */
async function generateStreamerContactMessage(
  streamerHandle,
  trigger,
  triggerDetails,
  userData
) {
  try {
    console.log("📡 [主播私联] 开始生成私信内容...");

    // 获取主播资料
    const streamerInfo = await getStreamerInfoForContact(streamerHandle);
    if (!streamerInfo) {
      console.error("❌ [主播私联] 无法获取主播信息");
      return;
    }

    // 构建messageData
    const messageData = {
      id: `streamer_contact_${Date.now()}`,
      user: {
        name: streamerInfo.name || "主播",
        handle: streamerHandle,
        avatar:
          streamerInfo.avatar ||
          "https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg",
        verified: streamerInfo.verified || false,
      },
    };

    // 补充triggerDetails
    triggerDetails.streamerName = streamerInfo.name;
    triggerDetails.streamerAvatar = streamerInfo.avatar;
    triggerDetails.streamerVerified = streamerInfo.verified;

    // 构建options
    const options = {
      isStreamerContact: true,
      streamerContactData: {
        trigger: trigger, // "giftRank" | "fanClub"
        details: triggerDetails,
      },
    };

    // 调用第9情景生成私信
    const generatedMessages = await generateMessageConversation(
      messageData,
      true,
      options
    );

    if (!generatedMessages || generatedMessages.length === 0) {
      console.log("⚠️ [主播私联] AI未生成消息");
      return;
    }

    // 缓存生成的消息
    const cacheKey = `${streamerHandle}_${trigger}`;
    window.streamerContactMessageCache[cacheKey] = {
      messageData,
      generatedMessages,
      trigger,
      triggerDetails,
      timestamp: Date.now(),
    };

    console.log(
      `✅ [主播私联] 私信内容已生成并缓存 (${generatedMessages.length}条消息)`
    );

    // 显示弹窗通知
    showStreamerContactModal(cacheKey);
  } catch (error) {
    console.error("❌ [主播私联] 生成私信失败:", error);
    showXToast("生成私信失败: " + error.message, "error");
  }
}

/**
 * 获取主播信息用于私联
 */
async function getStreamerInfoForContact(streamerHandle) {
  try {
    // 先尝试从当前直播间数据获取
    if (
      currentLiveRoomData &&
      currentLiveRoomData.streamerHandle === streamerHandle
    ) {
      return {
        name: currentLiveRoomData.streamerName,
        avatar: currentLiveRoomData.streamerAvatar,
        verified: currentLiveRoomData.streamerVerified || false,
      };
    }

    // 从数据库获取（从直播流列表中查找）
    const xDb =
      typeof getXDB === "function"
        ? getXDB()
        : typeof window.getXDB === "function"
        ? window.getXDB()
        : null;
    if (!xDb) {
      console.error("❌ [获取主播信息] 无法获取数据库实例");
      return null;
    }

    // 从直播间列表中查找
    for (const category in liveStreamData) {
      const streams = liveStreamData[category];
      const found = streams.find((s) => s.streamerHandle === streamerHandle);
      if (found) {
        return {
          name: found.streamerName,
          avatar: found.streamerAvatar,
          verified: found.streamerVerified || false,
        };
      }
    }

    return null;
  } catch (error) {
    console.error("❌ [获取主播信息] 失败:", error);
    return null;
  }
}

