/**
 * 处理用户接收主播私联
 */
async function handleStreamerContactAccept(cacheKey) {
  try {
    console.log("✅ [主播私联] 用户选择接收");

    const cachedData = window.streamerContactMessageCache[cacheKey];
    if (!cachedData) {
      showXToast("数据丢失，请重试", "error");
      return;
    }

    const { messageData, generatedMessages, trigger } = cachedData;

    // 关闭弹窗 - 带动画
    const modal = document.getElementById("streamer-contact-modal");
    if (modal) {
      const card = modal.querySelector(".invitation-card");
      const backdrop = modal.querySelector(".backdrop-layer");
      const envelope = modal.querySelector(".envelope-container");

      // 触发接受动画
      if (card) card.classList.add("accepting");
      if (backdrop) backdrop.classList.remove("active");
      if (envelope) envelope.classList.add("leaving");

      // 等待动画完成再删除
      await new Promise((resolve) => setTimeout(resolve, 800));
      modal.remove();
    }

    // 关闭直播间和直播列表
    if (typeof closeLiveRoom === "function") {
      closeLiveRoom();
    }
    if (typeof closeLiveStreamList === "function") {
      closeLiveStreamList();
    }

    // 回到X首页
    if (typeof navigateToXHome === "function") {
      navigateToXHome();
    } else if (typeof navigateTo === "function") {
      navigateTo("home");
    }

    // 延迟一下再打开私信（等待界面切换完成）
    await new Promise((resolve) => setTimeout(resolve, 300));

    // 保存私信对话到数据库
    const xDb =
      typeof getXDB === "function"
        ? getXDB()
        : typeof window.getXDB === "function"
        ? window.getXDB()
        : null;
    if (!xDb) {
      console.error("❌ [主播私联接收] 无法获取数据库实例");
      return;
    }
    const conversationId = `messageConversation_${currentAccountId || "main"}_${
      messageData.id
    }`;
    await xDb.xAccountProfiles.put({
      handle: conversationId,
      name: "messageConversation",
      data: {
        senderProfile: {
          name: messageData.user.name,
          handle: messageData.user.handle,
          avatar: messageData.user.avatar,
          verified: messageData.user.verified,
        },
        messages: generatedMessages,
      },
      messageId: messageData.id,
      accountId: currentAccountId || "main",
      updatedAt: new Date().toISOString(),
    });

    // 添加到联系人列表
    const dataId = `messagesList_${currentAccountId || "main"}`;
    const savedData = await xDb.xAccountProfiles.get(dataId);
    let messagesList = savedData?.data || [];

    // 检查是否已存在
    const existingIndex = messagesList.findIndex(
      (msg) => msg.id === messageData.id
    );
    if (existingIndex === -1) {
      const newMessage = {
        id: messageData.id,
        userName: messageData.user.name,
        userHandle: messageData.user.handle.replace("@", ""),
        userAvatar: messageData.user.avatar,
        lastMessage:
          generatedMessages[generatedMessages.length - 1]?.content || "",
        timestamp: new Date().toISOString(),
        unread: true,
      };
      messagesList.unshift(newMessage);

      await xDb.xAccountProfiles.put({
        handle: dataId,
        name: "messagesList",
        data: messagesList,
        updatedAt: new Date().toISOString(),
      });

      console.log("✅ [主播私联] 已添加到联系人列表");
    }

    // 打开私信详情页
    if (typeof openMessageDetail === "function") {
      await openMessageDetail(messageData);
    }

    // 保存"已接受"历史记录到 IndexedDB（持久化）
    const cleanHandle = HandleUtils.clean(messageData.user.handle);
    const historyKey = `streamerContactHistory_${cleanHandle}`;

    // 读取现有历史记录
    const existingHistory = await xDb.xAccountProfiles.get(historyKey);
    const historyData = existingHistory?.data || {};

    // 更新当前 trigger 的状态
    historyData[trigger] = {
      accepted: true,
      rejected: false,
      timestamp: Date.now(),
    };

    // 保存到数据库
    await xDb.xAccountProfiles.put({
      handle: historyKey,
      name: "streamerContactHistory",
      data: historyData,
      updatedAt: new Date().toISOString(),
    });

    console.log(`✅ [主播私联] 已记录接受历史: ${cleanHandle} - ${trigger}`);

    // 清除缓存
    delete window.streamerContactMessageCache[cacheKey];

    showXToast("已接收主播私信", "success");
  } catch (error) {
    console.error("❌ [主播私联] 接收失败:", error);
    showXToast("接收失败: " + error.message, "error");
  }
}

/**
 * 处理用户拒绝主播私联
 */
async function handleStreamerContactReject(cacheKey) {
  console.log("🚫 [主播私联] 用户选择拒绝");

  const cachedData = window.streamerContactMessageCache[cacheKey];
  if (cachedData) {
    const { trigger, messageData } = cachedData;
    const streamerHandle = messageData.user.handle;

    // 记录拒绝到内存（兼容旧逻辑）
    const rejectionKey = `${streamerHandle}_${trigger}`;
    window.streamerContactRejections[rejectionKey] = Date.now();

    console.log("📝 [主播私联] 已记录拒绝:", rejectionKey);

    // 保存"已拒绝"历史记录到 IndexedDB（持久化）
    const xDb =
      typeof getXDB === "function"
        ? getXDB()
        : typeof window.getXDB === "function"
        ? window.getXDB()
        : null;

    if (xDb) {
      try {
        const cleanHandle = HandleUtils.clean(streamerHandle);
        const historyKey = `streamerContactHistory_${cleanHandle}`;

        // 读取现有历史记录
        const existingHistory = await xDb.xAccountProfiles.get(historyKey);
        const historyData = existingHistory?.data || {};

        // 更新当前 trigger 的状态
        historyData[trigger] = {
          accepted: false,
          rejected: true,
          timestamp: Date.now(),
        };

        // 保存到数据库
        await xDb.xAccountProfiles.put({
          handle: historyKey,
          name: "streamerContactHistory",
          data: historyData,
          updatedAt: new Date().toISOString(),
        });

        console.log(
          `✅ [主播私联] 已记录拒绝历史: ${cleanHandle} - ${trigger}`
        );
      } catch (error) {
        console.error("❌ [主播私联] 保存拒绝历史记录失败:", error);
      }
    }
  }

  // 关闭弹窗 - 带动画
  const modal = document.getElementById("streamer-contact-modal");
  if (modal) {
    const envelope = modal.querySelector(".envelope-container");
    const card = modal.querySelector(".invitation-card");
    const backdrop = modal.querySelector(".backdrop-layer");

    // 触发离开动画
    if (envelope) envelope.classList.add("leaving");
    if (card) card.classList.remove("active");
    if (backdrop) backdrop.classList.remove("active");

    // 等待动画完成再删除
    await new Promise((resolve) => setTimeout(resolve, 600));
    modal.remove();
  }

  showXToast("已拒绝主播私信", "info");
}

// 暴露函数到全局
window.checkStreamerContactTrigger = checkStreamerContactTrigger;
window.handleStreamerContactAccept = handleStreamerContactAccept;
window.handleStreamerContactReject = handleStreamerContactReject;

