/**
 * 设置猫咪情绪
 * @param {string} mood - 情绪类型 (calm, happy, sad, angry, shy, excited, sleepy, surprised)
 * @param {string} targetId - 目标猫咪元素的 ID
 */
function setPixelCatMood(mood, targetId = 'dialogCat') {
  const cat = document.getElementById(targetId);
  if (!cat) return;

  cat.className = 'pixel-cat';
  if (mood !== 'calm') {
    cat.classList.add(`cat-mood-${mood}`);
  }
}

/**
 * 触发狐狸游戏 - 从侧边栏点击
 */
function triggerFoxGame() {
  console.log("🐱 [Cat Game] 触发猫咪游戏");

  // 注入样式和字体
  injectLiveRoomStyles();

  // 关闭侧边栏
  if (typeof closeLiveSidebar === "function") {
    closeLiveSidebar();
  } else if (typeof window.closeLiveSidebar === "function") {
    window.closeLiveSidebar();
  }

  // 显示像素猫咪探头
  const catPeek = document.getElementById("pixelCatPeek");
  if (catPeek) {
    catPeek.classList.add("peeking");
    setPixelCatMood('happy', 'peekCat');
    console.log("🐱 [Cat Game] 猫咪开始探头");

    // 5秒后自动触发对话框
    foxGameAutoPeekTimeout = setTimeout(() => {
      showFoxDialog('greeting');
    }, 5000);
  } else {
    console.error("❌ [Cat Game] 找不到猫咪元素 #pixelCatPeek");
  }
}

/**
 * 显示对话框 - 带打字机动画和情绪系统
 * @param {string} key - 消息配置的键名
 */
function showFoxDialog(key = 'greeting') {
  console.log("💬 [Cat Game] 显示对话框:", key);

  // 清除探头定时器
  if (foxGameAutoPeekTimeout) {
    clearTimeout(foxGameAutoPeekTimeout);
    foxGameAutoPeekTimeout = null;
  }

  // 猫咪飞出动画（快速移除探头状态）
  const catPeek = document.getElementById("pixelCatPeek");
  if (catPeek) {
    setTimeout(() => catPeek.classList.remove("peeking"), 300);
  }

  // 显示对话框容器
  const dialogContainer = document.getElementById("foxDialogContainer");
  if (!dialogContainer) {
    console.error("❌ [Cat Game] 找不到对话框元素 #foxDialogContainer");
    return;
  }

  const dialogText = document.getElementById("foxDialogText");
  const dialogButtons = document.getElementById("foxDialogButtons");

  if (!dialogText || !dialogButtons) {
    console.error("❌ [Cat Game] 找不到对话框子元素");
    return;
  }

  // 获取消息配置
  const msg = PIXEL_CAT_MESSAGES[key];
  if (!msg) {
    console.error("❌ [Cat Game] 找不到消息配置:", key);
    return;
  }

  // 设置猫咪情绪
  setPixelCatMood(msg.mood, 'dialogCat');
  setPixelCatMood(msg.mood, 'peekCat');

  dialogContainer.classList.add("active");
  dialogText.innerHTML = "";
  dialogButtons.style.display = "none";

  // 打字机动画（支持换行符）
  pixelCatTypewriter(msg.text, dialogText, () => {
    if (msg.buttons) {
      setTimeout(() => {
        dialogButtons.style.display = "flex";
        console.log("✅ [Cat Game] 打字机动画完成，显示按钮");
      }, 300);
    } else {
      setTimeout(() => closeFoxGame(), 3000);
    }
  });
}

/**
 * 打字机效果
 * @param {string} str - 要显示的文本
 * @param {HTMLElement} el - 目标元素
 * @param {Function} callback - 完成回调
 */
function pixelCatTypewriter(str, el, callback) {
  let i = 0;
  if (foxGameTypewriterInterval) {
    clearInterval(foxGameTypewriterInterval);
  }

  foxGameTypewriterInterval = setInterval(() => {
    if (i < str.length) {
      // 每次重新构建整个字符串 + 光标（避免多个光标）
      const currentText = str.substring(0, i + 1).replace(/\n/g, '<br>');
      el.innerHTML = currentText + '<span class="typing-cursor"></span>';
      i++;
    } else {
      clearInterval(foxGameTypewriterInterval);
      foxGameTypewriterInterval = null;
      el.innerHTML = str.replace(/\n/g, '<br>');
      if (callback) callback();
    }
  }, 80);
}

