  catGameState.stage = 'showing_cost';

  // 计算随机费用
  const [min, max] = game.costRange;
  const cost = Math.floor(Math.random() * (max - min + 1)) + min;
  catGameState.currentCost = cost;

  console.log(`💰 [Cat Game] ${game.name} 费用: ${cost} 积分`);

