/**
 * 处理猜拳游戏结束 - 隐藏游戏界面，显示对话框，应用奖惩
 */
async function handleRpsGameEnd() {
  console.log('🎮 [RPS Game] 游戏结束，开始处理后续流程');

  // 隐藏猜拳游戏容器
  const rpsContainer = document.getElementById('rpsGameContainer');
  if (rpsContainer) {
    rpsContainer.classList.remove('active');
    setTimeout(() => {
      // 完全移除容器（可选，或者保留以便下次复用）
      // rpsContainer.remove();
    }, 500);
  }

  // 判断用户是赢还是输
  const userWon = rpsGameState.userScore >= 2;

  console.log(`🏆 [RPS Game] 游戏结果: ${userWon ? '用户获胜' : '猫咪获胜'}`);
  console.log(`📊 [RPS Game] 最终比分 - 用户: ${rpsGameState.userScore}, 猫咪: ${rpsGameState.catScore}`);

  // 随机选择一条文本
  const messages = userWon ? RPS_RESULT_MESSAGES.victory : RPS_RESULT_MESSAGES.defeat;
  const randomMessage = messages[Math.floor(Math.random() * messages.length)];

  // 应用奖励或惩罚
  let rewardText = '';
  if (userWon) {
    rewardText = await applyRpsReward();
  } else {
    rewardText = await applyRpsPenalty();
  }

  // 显示对话框
  const dialogContainer = document.getElementById('foxDialogContainer');
  const dialogText = document.getElementById('foxDialogText');
  const dialogButtons = document.getElementById('foxDialogButtons');

  if (!dialogContainer || !dialogText || !dialogButtons) {
    console.error('❌ [RPS Game] 找不到对话框元素');
    return;
  }

  // 设置猫咪情绪
  const catMood = userWon ? 'sad' : 'happy';
  if (window.setPixelCatMood) {
    setPixelCatMood(catMood, 'dialogCat');
    setPixelCatMood(catMood, 'peekCat');
  }

  // 显示对话框
  dialogContainer.classList.add('active');
  dialogText.innerHTML = '';
  dialogButtons.style.display = 'none';

  // 第一段：输赢文本
  pixelCatTypewriter(randomMessage, dialogText, () => {
    setTimeout(() => {
      // 第二段：奖励/惩罚详情
      dialogText.innerHTML = '';
      pixelCatTypewriter(rewardText, dialogText, () => {
        setTimeout(() => {
          // 第三段：再见文本
          dialogText.innerHTML = '';
          const goodbyeText = userWon
            ? "快乐的时光总是超级短暂呢~\n下次也来找我，好不好嘛^^"
            : "今天就到这里啦~\n我会等着你的下次光临^^";

          pixelCatTypewriter(goodbyeText, dialogText, () => {
            setTimeout(() => {
              // 隐藏对话框，结束游戏
              dialogContainer.classList.remove('active');
              console.log('✅ [RPS Game] 游戏及互动结束');

              // 重置游戏状态（为下次游戏准备）
              rpsGameState = {
                currentRound: 1,
                userScore: 0,
                catScore: 0,
                userHistory: [],
                isProcessing: false,
                gameFinished: false,
                consecutiveWins: 0,
              };
            }, 2500);
          });
        }, 2000);
      });
    }, 2500);
  });
}

/**
 * 应用猜拳奖励 - 随机给予积分或金钱
 * @returns {Promise<string>} 奖励详情文本
 */
async function applyRpsReward() {
  // 随机选择奖励类型（50%概率积分，50%概率金钱）
  const rewardType = Math.random() < 0.5 ? 'points' : 'money';

  if (rewardType === 'points') {
    // 积分奖励：500-1000积分
    const pointsReward = Math.floor(Math.random() * 501) + 500;

    const currentPoints = getUserLivePoints();
    const newPoints = currentPoints + pointsReward;
    saveUserLivePoints(newPoints);

    console.log(`🎁 [RPS Game] 积分奖励: +${pointsReward}P (${currentPoints}P → ${newPoints}P)`);

    // 显示手机样式通知
    const userAvatar = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
    showPhoneNotification({
      title: 'X',
      message: `🎉 猜拳获胜！获得 ${pointsReward} 积分`,
      avatar: userAvatar,
      leftIcon: 'x',
    });

    return `奖励已发放！\n你获得了 ${pointsReward} 积分~\n当前积分：${newPoints}P\n\n真是厉害呢！^^`;

  } else {
    // 金钱奖励：100-300元
    const moneyReward = Math.floor(Math.random() * 201) + 100;

    try {
      // 加载钱包数据
      const walletInfo = await getWalletBalance();

      if (!walletInfo.isActivated) {
        console.warn('⚠️ [RPS Game] 钱包未激活，改为发放积分');
        // 钱包未激活，改为发放等值积分（1元=10积分）
        const equivalentPoints = moneyReward * 10;
        const currentPoints = getUserLivePoints();
        const newPoints = currentPoints + equivalentPoints;
        saveUserLivePoints(newPoints);

        // 显示手机样式通知
        const userAvatarInactive = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
        showPhoneNotification({
          title: 'X',
          message: `🎉 猜拳获胜！获得 ${equivalentPoints} 积分（钱包未激活）`,
          avatar: userAvatarInactive,
          leftIcon: 'x',
        });

        return `奖励已发放！\n钱包未激活，改为发放 ${equivalentPoints} 积分~\n当前积分：${newPoints}P\n\n（激活钱包可获得现金奖励哦）^^`;
      }

      // 钱包已激活，发放金钱
      walletInfo.data.balance += moneyReward;

      // 添加交易记录
      const transaction = {
        id: `rps_reward_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        description: `猜拳游戏获胜奖励`,
        amount: moneyReward,
        timestamp: new Date().toISOString(),
        type: 'rps_reward',
        details: {
          userScore: rpsGameState.userScore,
          catScore: rpsGameState.catScore
        }
      };

      if (!walletInfo.data.transactions) {
        walletInfo.data.transactions = [];
      }
      walletInfo.data.transactions.unshift(transaction);

      // 保存钱包数据
      await saveWalletBalance(walletInfo.data);

      console.log(`💰 [RPS Game] 金钱奖励: +$${moneyReward} (余额: $${walletInfo.data.balance.toFixed(2)})`);

      // 显示手机样式通知
      const userAvatarMoney = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
      showPhoneNotification({
        title: 'X',
        message: `🎉 猜拳获胜！获得 $${moneyReward}`,
        avatar: userAvatarMoney,
        leftIcon: 'x',
      });

      return `奖励已发放！\n你获得了 $${moneyReward}~\n钱包余额：$${walletInfo.data.balance.toFixed(2)}\n\n恭喜恭喜！^^`;

    } catch (error) {
      console.error('❌ [RPS Game] 发放金钱奖励失败:', error);
      // 出错时改为发放积分
      const equivalentPoints = moneyReward * 10;
      const currentPoints = getUserLivePoints();
      const newPoints = currentPoints + equivalentPoints;
      saveUserLivePoints(newPoints);

      // 显示手机样式通知
      const userAvatarError = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
      showPhoneNotification({
        title: 'X',
        message: `🎉 猜拳获胜！获得 ${equivalentPoints} 积分`,
        avatar: userAvatarError,
        leftIcon: 'x',
      });

      return `奖励已发放！\n你获得了 ${equivalentPoints} 积分~\n当前积分：${newPoints}P\n\n（钱包系统暂时出错）^^`;
    }
  }
}

/**
 * 应用猜拳惩罚 - 随机扣除积分或金钱
 * @returns {Promise<string>} 惩罚详情文本
 */
async function applyRpsPenalty() {
  // 随机选择惩罚类型（50%概率积分，50%概率金钱）
  const penaltyType = Math.random() < 0.5 ? 'points' : 'money';

  if (penaltyType === 'points') {
    // 积分惩罚：500-1000积分
    const pointsPenalty = Math.floor(Math.random() * 501) + 500;

    const currentPoints = getUserLivePoints();
    const actualPenalty = Math.min(pointsPenalty, currentPoints); // 不能扣成负数
    const newPoints = Math.max(0, currentPoints - actualPenalty);
    saveUserLivePoints(newPoints);

    console.log(`💸 [RPS Game] 积分惩罚: -${actualPenalty}P (${currentPoints}P → ${newPoints}P)`);

    // 显示手机样式通知
    const userAvatarPenalty = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
    showPhoneNotification({
      title: 'X',
      message: `😿 猜拳失败！扣除 ${actualPenalty} 积分`,
      avatar: userAvatarPenalty,
      leftIcon: 'x',
    });

    if (actualPenalty < pointsPenalty) {
      return `惩罚已执行...\n扣除了你所有的 ${actualPenalty} 积分\n当前积分：${newPoints}P\n\n不过别担心，还可以再赚回来的~`;
    } else {
      return `惩罚已执行...\n扣除了 ${actualPenalty} 积分\n当前积分：${newPoints}P\n\n下次加油哦~`;
    }

  } else {
    // 金钱惩罚：100-300元
    const moneyPenalty = Math.floor(Math.random() * 201) + 100;

    try {
      // 加载钱包数据
      const walletInfo = await getWalletBalance();

      if (!walletInfo.isActivated) {
        console.warn('⚠️ [RPS Game] 钱包未激活，改为扣除积分');
        // 钱包未激活，改为扣除等值积分（1元=10积分）
        const equivalentPoints = moneyPenalty * 10;
        const currentPoints = getUserLivePoints();
        const actualPenalty = Math.min(equivalentPoints, currentPoints);
        const newPoints = Math.max(0, currentPoints - actualPenalty);
        saveUserLivePoints(newPoints);

        // 显示手机样式通知
        const userAvatarInactivePenalty = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
        showPhoneNotification({
          title: 'X',
          message: `😿 猜拳失败！扣除 ${actualPenalty} 积分`,
          avatar: userAvatarInactivePenalty,
          leftIcon: 'x',
        });

        return `惩罚已执行...\n扣除了 ${actualPenalty} 积分\n当前积分：${newPoints}P\n\n（钱包未激活，所以扣的是积分）`;
      }

      // 钱包已激活，扣除金钱
      const actualPenalty = Math.min(moneyPenalty, walletInfo.data.balance); // 不能扣成负数
      walletInfo.data.balance = Math.max(0, walletInfo.data.balance - actualPenalty);

      // 添加交易记录
      const transaction = {
        id: `rps_penalty_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        description: `猜拳游戏失败惩罚`,
        amount: -actualPenalty,
        timestamp: new Date().toISOString(),
        type: 'rps_penalty',
        details: {
          userScore: rpsGameState.userScore,
          catScore: rpsGameState.catScore
        }
      };

      if (!walletInfo.data.transactions) {
        walletInfo.data.transactions = [];
      }
      walletInfo.data.transactions.unshift(transaction);

      // 保存钱包数据
      await saveWalletBalance(walletInfo.data);

      console.log(`💸 [RPS Game] 金钱惩罚: -$${actualPenalty} (余额: $${walletInfo.data.balance.toFixed(2)})`);

      // 显示手机样式通知
      const userAvatar = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
      showPhoneNotification({
        title: 'X',
        message: `😿 猜拳失败！扣除 $${actualPenalty}`,
        avatar: userAvatar,
        leftIcon: 'x',
      });

      if (actualPenalty < moneyPenalty) {
        return `惩罚已执行...\n扣除了你所有的 $${actualPenalty}\n钱包余额：$${walletInfo.data.balance.toFixed(2)}\n\n余额不足，只能扣这么多了~`;
      } else {
        return `惩罚已执行...\n扣除了 $${actualPenalty}\n钱包余额：$${walletInfo.data.balance.toFixed(2)}\n\n失败是有代价的嘛~`;
      }

    } catch (error) {
      console.error('❌ [RPS Game] 执行金钱惩罚失败:', error);
      // 出错时改为扣除积分
      const equivalentPoints = moneyPenalty * 10;
      const currentPoints = getUserLivePoints();
      const actualPenalty = Math.min(equivalentPoints, currentPoints);
      const newPoints = Math.max(0, currentPoints - actualPenalty);
      saveUserLivePoints(newPoints);

      // 显示手机样式通知
      const userAvatarFallback = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
      showPhoneNotification({
        title: 'X',
        message: `😿 猜拳失败！扣除 ${actualPenalty} 积分`,
        avatar: userAvatarFallback,
        leftIcon: 'x',
      });

      return `惩罚已执行...\n扣除了 ${actualPenalty} 积分\n当前积分：${newPoints}P\n\n（钱包系统暂时出错）`;
    }
  }
}

/**
 * 启动猜拳游戏 - 创建并显示游戏界面
 */
function startRpsGame() {
  console.log('🎮 [RPS Game] 启动猜拳游戏界面');

  // 隐藏对话框
  const dialogContainer = document.getElementById('foxDialogContainer');
  if (dialogContainer) {
    dialogContainer.classList.remove('active');
  }

  // 获取直播间容器
  const liveRoomContainer = document.getElementById('live-room-container');
  if (!liveRoomContainer) {
    console.error('❌ [RPS Game] 找不到直播间容器');
    return;
  }

  // 检查是否已存在猜拳游戏容器
  let rpsContainer = document.getElementById('rpsGameContainer');

  if (!rpsContainer) {
    // 创建猜拳游戏容器
    rpsContainer = document.createElement('div');
    rpsContainer.id = 'rpsGameContainer';
    rpsContainer.className = 'rpg-dialog-container';
    rpsContainer.innerHTML = `
      <div class="rps-game-box">
        <!-- 背景效果 -->
        <div class="metal-texture"></div>
        <div class="scanlines"></div>

        <!-- 装饰螺丝 -->
        <div class="dialog-screw top-left" style="top: 12px; left: 12px;"></div>
        <div class="dialog-screw top-right" style="top: 12px; right: 12px;"></div>
        <div class="dialog-screw bottom-left" style="bottom: 12px; left: 12px;"></div>
        <div class="dialog-screw bottom-right" style="bottom: 12px; right: 12px;"></div>

        <div class="rps-game-floating" id="rpsGame">
          <!-- 比分栏 - 横向一行 -->
          <div class="rps-scoreboard">
            <div class="rps-round-indicator">
              <div class="round-text">第<span id="roundNumber">1</span>局</div>
            </div>
            <span class="score-separator">|</span>
            <div class="rps-score-item cat-score">
              <div class="score-label">猫猫</div>
              <div class="score-value" id="catScoreValue">0</div>
            </div>
            <span class="score-separator">:</span>
            <div class="rps-score-item user-score">
              <div class="score-value" id="userScoreValue">0</div>
              <div class="score-label">用户</div>
            </div>
          </div>

          <!-- 战斗舞台 - 左右布局 -->
          <div class="rps-battle-stage">
            <!-- 猫咪战斗区 -->
            <div class="rps-cat-arena">
              <div class="cat-label">猫猫 Aron</div>
            <div class="rps-pixel-cat" id="rpsCat">
              <div class="rps-cat-head">
                <!-- 猫耳朵 -->
                <div class="rps-cat-ear left">
                  <div class="rps-cat-ear-inner"></div>
                </div>
                <div class="rps-cat-ear right">
                  <div class="rps-cat-ear-inner"></div>
                </div>
                <!-- 胡须 -->
                <div class="rps-cat-whisker left top"></div>
                <div class="rps-cat-whisker left middle"></div>
                <div class="rps-cat-whisker left bottom"></div>
                <div class="rps-cat-whisker right top"></div>
                <div class="rps-cat-whisker right middle"></div>
                <div class="rps-cat-whisker right bottom"></div>
                <!-- 眼睛 -->
                <div class="rps-cat-eyes">
                  <div class="rps-cat-eye"></div>
                  <div class="rps-cat-eye"></div>
                </div>
                <!-- 鼻子 -->
                <div class="rps-cat-nose"></div>
                <!-- 嘴巴 -->
                <div class="rps-cat-mouth"></div>
                <!-- 脸颊 -->
                <div class="rps-cat-cheek left"></div>
                <div class="rps-cat-cheek right"></div>
              </div>
            </div>

            <!-- 猫咪手势 -->
            <div class="cat-hand-container">
              <div class="cat-hand" id="catHand">
                <div class="hand-gesture rock" id="catGesture"></div>
              </div>
            </div>
          </div>

            <!-- VS分隔线 - 垂直 -->
            <div class="rps-vs-divider">
              <div class="vs-line"></div>
              <div class="vs-text">VS</div>
            </div>

            <!-- 用户战斗区 -->
            <div class="rps-user-arena">
              <div class="user-label">你</div>
              <!-- 用户头像 -->
              <img class="rps-user-avatar" id="rpsUserAvatar" src="" alt="User Avatar">
              <!-- 用户手势 -->
              <div class="user-hand-container">
                <div class="user-hand" id="userHand">
                  <div class="hand-gesture rock" id="userGesture"></div>
                </div>
              </div>
            </div>
          </div>

        <!-- 用户选择按钮 -->
        <div class="rps-choice-buttons" id="rpsChoiceButtons">
          <button class="rps-btn" onclick="selectChoice('rock')">
            <div class="btn-icon">✊</div>
            <div class="btn-label">ROCK</div>
          </button>
          <button class="rps-btn" onclick="selectChoice('paper')">
            <div class="btn-icon">✋</div>
            <div class="btn-label">PAPER</div>
          </button>
          <button class="rps-btn" onclick="selectChoice('scissors')">
            <div class="btn-icon">✌️</div>
            <div class="btn-label">SCISSORS</div>
          </button>
        </div>

        <!-- 结果文字 -->
        <div class="rps-result-text" id="rpsResultText"></div>

          <!-- 重新开始按钮（游戏结束后显示） -->
          <button class="rps-restart-btn" id="rpsRestartBtn" onclick="restartGame()" style="display: none;">
            ▸ PLAY AGAIN
          </button>
        </div>
      </div>
    `;

    // 将容器添加到直播间容器中
    liveRoomContainer.appendChild(rpsContainer);
    console.log('📦 [RPS Game] 猜拳游戏容器已添加到直播间');
  }

  // 重置游戏状态
  rpsGameState = {
    currentRound: 1,
    userScore: 0,
    catScore: 0,
    userHistory: [],
    isProcessing: false,
    gameFinished: false,
    consecutiveWins: 0,
  };

  // 提升z-index确保在最上层
  rpsContainer.style.zIndex = '999999';

  // 显示猜拳游戏容器
  setTimeout(() => {
    rpsContainer.classList.add('active');
    updateScoreboard();
    setRpsCatMood('calm');

    // 设置用户头像
    const userAvatar = document.getElementById('rpsUserAvatar');
    if (userAvatar) {
      const avatarUrl = window.userProfileData?.avatar || 'https://i.postimg.cc/4xmx7V4R/mmexport1759081128356.jpg';
      userAvatar.src = avatarUrl;
      userAvatar.onerror = function() {
        this.className = 'rps-user-avatar-placeholder';
        this.removeAttribute('src');
        this.alt = '👤';
      };
    }

    // 调试信息
    console.log('✅ [RPS Game] 猜拳游戏界面已显示');
    console.log('📊 [RPS Game] 容器状态:', {
      element: rpsContainer,
      hasActiveClass: rpsContainer.classList.contains('active'),
      display: window.getComputedStyle(rpsContainer).display,
      opacity: window.getComputedStyle(rpsContainer).opacity,
      zIndex: window.getComputedStyle(rpsContainer).zIndex,
      position: rpsContainer.getBoundingClientRect()
    });
  }, 100);
}

/**
 * 关闭猜拳游戏界面
 */
function closeRpsGame() {
  const rpsContainer = document.getElementById('rpsGameContainer');
  if (rpsContainer) {
    rpsContainer.classList.remove('active');
    console.log('🎮 [RPS Game] 猜拳游戏界面已关闭');
  }
}

