      verificationType: "none",
      bio: "欢迎来到我的X主页！",
      publicIdentity: "",
      showRealName: false,
      realName: "",
      customTag1: "科技爱好者",
      customTag1Icon: "✨",
      customTag1Color: "#71767b",
      customTag2: "2024年加入",
      customTag2Icon: "📅",
